
CREATE OR REPLACE  
PACKAGE PCRD_ST_CONV_CATALOGUE  
IS
    V_ENV_INFO_TRACE   GLOBAL_VARS.ENV_INFO_TRACE_TYPE;

 


    FUNCTION AUT_POPULATE_CATALOGUE_PRODUCT (P_BANK_CODE VARCHAR2)
        RETURN PLS_INTEGER;

    FUNCTION AUT_POPULATE_CAT_GENPAN (P_BANK_CODE VARCHAR2)
        RETURN PLS_INTEGER;

    FUNCTION AUT_GENERATE_PAN_XML (P_BANK_CODE VARCHAR2)
        RETURN PLS_INTEGER;

    FUNCTION AUT_POPULATE_CAT_INJ_PARAM (P_BANK_CODE VARCHAR2)
        RETURN PLS_INTEGER;

    FUNCTION AUT_UPDATE_GRP_DATA_IDX (P_BANK_CODE VARCHAR2)
        RETURN PLS_INTEGER;
        
    FUNCTION MAIN_AUT_POST (P_BANK_CODE VARCHAR2)
        RETURN PLS_INTEGER;
    
    FUNCTION AUT_MULTI_RANGE_PRODUCTS (P_BANK_CODE VARCHAR2)
        RETURN PLS_INTEGER;    
        
    FUNCTION AUT_CATALOGE_ELIGIBILITY (P_BANK_CODE VARCHAR2)
        RETURN PLS_INTEGER;    
END pcrd_st_conv_catalogue;
/
CREATE OR REPLACE   
PACKAGE BODY PCRD_ST_CONV_CATALOGUE  
IS
    FUNCTION MAIN_AUT_POST (P_BANK_CODE VARCHAR2)
        RETURN PLS_INTEGER
    IS
        RETURN_STATUS   PLS_INTEGER;
    BEGIN
        --DEFINE TRACES RECORD
        V_ENV_INFO_TRACE.USER_NAME       := 'AUTOMATISATION';
        V_ENV_INFO_TRACE.MODULE_CODE     := 'AUT';
        V_ENV_INFO_TRACE.LANG            := 'E';
        V_ENV_INFO_TRACE.FUNCTION_NAME   := 'MAIN_AUT_POST';
        V_ENV_INFO_TRACE.PACKAGE_NAME    := SUBSTR($$PLSQL_UNIT,1,30);

        V_ENV_INFO_TRACE.USER_MESSAGE    := 'START ';
        PCRD_GENERAL_TOOLS.PUT_TRACES (V_ENV_INFO_TRACE, $$PLSQL_LINE);





        RETURN_STATUS                    := pcrd_st_conv_catalogue.AUT_POPULATE_CAT_GENPAN(P_BANK_CODE);

        IF RETURN_STATUS <> DECLARATION_CST.OK
        THEN
            V_ENV_INFO_TRACE.USER_MESSAGE   := 'ERROR WHILE CALLING pcrd_st_conv_catalogue.AUT_POPULATE_CAT_GENPAN';
            PCRD_GENERAL_TOOLS.PUT_TRACES (V_ENV_INFO_TRACE, $$PLSQL_LINE);
            RETURN RETURN_STATUS;
        END IF;



        RETURN_STATUS                    := pcrd_st_conv_catalogue.AUT_POPULATE_CATALOGUE_PRODUCT(P_BANK_CODE);

        IF RETURN_STATUS <> DECLARATION_CST.OK
        THEN
            V_ENV_INFO_TRACE.USER_MESSAGE   := 'ERROR WHILE CALLING pcrd_st_conv_catalogue.AUT_POPULATE_CATALOGUE_PRODUCT';
            PCRD_GENERAL_TOOLS.PUT_TRACES (V_ENV_INFO_TRACE, $$PLSQL_LINE);
            RETURN RETURN_STATUS;
        END IF;


        RETURN_STATUS                    := pcrd_st_conv_catalogue.AUT_GENERATE_PAN_XML(P_BANK_CODE);

        IF RETURN_STATUS <> DECLARATION_CST.OK
        THEN
            V_ENV_INFO_TRACE.USER_MESSAGE   := 'ERROR WHILE CALLING pcrd_st_conv_catalogue.AUT_GENERATE_PAN_XML';
            PCRD_GENERAL_TOOLS.PUT_TRACES (V_ENV_INFO_TRACE, $$PLSQL_LINE);
            RETURN RETURN_STATUS;
        END IF;


        RETURN_STATUS                    := pcrd_st_conv_catalogue.AUT_POPULATE_CAT_INJ_PARAM(P_BANK_CODE);

        IF RETURN_STATUS <> DECLARATION_CST.OK
        THEN
            V_ENV_INFO_TRACE.USER_MESSAGE   := 'ERROR WHILE CALLING pcrd_st_conv_catalogue.AUT_POPULATE_CAT_INJ_PARAM';
            PCRD_GENERAL_TOOLS.PUT_TRACES (V_ENV_INFO_TRACE, $$PLSQL_LINE);
            RETURN RETURN_STATUS;
        END IF;



        RETURN_STATUS                    := pcrd_st_conv_catalogue.AUT_UPDATE_GRP_DATA_IDX(P_BANK_CODE);

        IF RETURN_STATUS <> DECLARATION_CST.OK
        THEN
            V_ENV_INFO_TRACE.USER_MESSAGE   := 'ERROR WHILE CALLING pcrd_st_conv_catalogue.AUT_UPDATE_GRP_DATA_IDX';
            PCRD_GENERAL_TOOLS.PUT_TRACES (V_ENV_INFO_TRACE, $$PLSQL_LINE);
            RETURN RETURN_STATUS;
        END IF;


        RETURN_STATUS                    := pcrd_st_conv_catalogue.AUT_MULTI_RANGE_PRODUCTS(P_BANK_CODE);

        IF RETURN_STATUS <> DECLARATION_CST.OK
        THEN
            V_ENV_INFO_TRACE.USER_MESSAGE   := 'ERROR WHILE CALLING pcrd_st_conv_catalogue.AUT_MULTI_RANGE_PRODUCTS';
            PCRD_GENERAL_TOOLS.PUT_TRACES (V_ENV_INFO_TRACE, $$PLSQL_LINE);
            RETURN RETURN_STATUS;
        END IF;


        RETURN_STATUS                    := pcrd_st_conv_catalogue.AUT_CATALOGE_ELIGIBILITY(P_BANK_CODE);

        IF RETURN_STATUS <> DECLARATION_CST.OK
        THEN
            V_ENV_INFO_TRACE.USER_MESSAGE   := 'ERROR WHILE CALLING pcrd_st_conv_catalogue.AUT_CATALOGE_ELIGIBILITY';
            PCRD_GENERAL_TOOLS.PUT_TRACES (V_ENV_INFO_TRACE, $$PLSQL_LINE);
            RETURN RETURN_STATUS;
        END IF;





        RETURN DECLARATION_CST.OK;
    END;




    FUNCTION AUT_POPULATE_CATALOGUE_PRODUCT (P_BANK_CODE VARCHAR2)
        RETURN PLS_INTEGER
    IS
    BEGIN
        FOR REC IN (SELECT   *
                      FROM   CARD_PRODUCT
                     WHERE   BANK_CODE = P_BANK_CODE)
        LOOP
            BEGIN
                INSERT INTO CATALOGUE_PRODUCT (BANK_CODE,
                                               PRODUCT_CODE,
                                               PROD_VERSION,
                                               PRODUCT_NAME,
                                               PRODUCT_LEVEL,
                                               PRODUCT_TYPE,
                                               DESCRIPTION,
                                               PARENT_PRODUCT_BANK_CODE,
                                               PARENT_PRODUCT_CODE,
                                               PARENT_PRODUCT_VERSION,
                                               VALIDITY_START_DATE,
                                               STATUS,
                                               STATUS_DATE,
                                               DUPLICATION_ALLOWED,
                                               DERIVATION_ALLOWED,
                                               UNIQUE_INDEX,
                                               USER_CREATE,
                                               DATE_CREATE)
                  VALUES   (REC.BANK_CODE,
                            'PAN' || REC.PRODUCT_CODE,
                            '1',
                            'PAN ' || REC.ABRV_WORDING,
                            'M',
                            'P',
                            REC.ABRV_WORDING,
                            '000001',
                            'GENPAN',
                            '1',
                            SYSDATE,
                            'V',
                            SYSDATE,
                            'Y',
                            'N',
                            '1445',
                            'MGR',
                            SYSDATE);
            EXCEPTION
                WHEN OTHERS
                THEN
                    V_ENV_INFO_TRACE.USER_MESSAGE   := 'ERROR INSERT CATALOGUE_PRODUCT product_code='
                                                       || REC.PRODUCT_CODE
                                                       || ' Bank_code='
                                                       || REC.BANK_CODE;
                    PCRD_GENERAL_TOOLS.PUT_TRACES (V_ENV_INFO_TRACE, $$PLSQL_LINE);
                    RETURN DECLARATION_CST.NOK;
            END;
        END LOOP;


        RETURN DECLARATION_CST.OK;
    END AUT_POPULATE_CATALOGUE_PRODUCT;

    FUNCTION AUT_GENERATE_PAN_XML (P_BANK_CODE VARCHAR2)
       RETURN PLS_INTEGER
    IS
        V_BANK_CODE                     VARCHAR2 (6);
        V_PRODUCT_CODE                  VARCHAR2 (6);
        V_CHARACTERISTIC_ID             VARCHAR2 (60);
        V_MCALCUL_INDEX                 VARCHAR2 (3);
        MAX_LINE                        NUMBER;
        V_TEXT                          VARCHAR2 (4000);
        SKIP_COUNTER                    NUMBER;
        MARKUP_CALCUL_REC               MARKUP_CALCUL%ROWTYPE;
        ICC_APPLICATION_PAR_INDEX_REC   ICC_APPLICATION_PAR_INDEX%ROWTYPE;
        BREAK_COUNTER                   NUMBER := 0;
        V_CHECK_EXISTING_INJECTED       NUMBER;
        GEN_NEXT_LINE                   MGR_CAT_GENPAN%ROWTYPE;
        GEN_NEXT_2ND_LINE               MGR_CAT_GENPAN%ROWTYPE;
        V_ENTITY_NAME                   VARCHAR2 (60);
        V_FIELD_NAME                    VARCHAR2 (60);
        TAB_WHERE                       VARCHAR2 (4000);
        V_QUERY                         VARCHAR2 (4000);
        V_TRACE                         VARCHAR2 (4000);
        V_VALUE                         VARCHAR2 (100);
        V_START_BLOCK                   NUMBER := 0;
        V_COUNT_CHECK                   NUMBER;
        V_END_BLOCK                     NUMBER := 0;
        V_START_IN_BLOCK                NUMBER := 0;
        V_END_IN_BLOCK                  NUMBER := 0;
        V_STATUS_LEVEL                  NUMBER;
        V_CURRENT_GRP                   VARCHAR2 (100) := NULL;
        V_CURRENT_TRX_CODE              VARCHAR2 (2);
        V_XML_FILE                      CLOB;
        V_FLAG                          BOOLEAN := TRUE;
        V_REQUIRED_FLAG                 BOOLEAN;
        V_UNIQUE_INDEX                  NUMBER := 1000;
        V_FIRST_FLAG                    CHAR (1) := 'Y';
        V_NUM_1                         NUMBER;
        V_NUM_2                         NUMBER;
        v_exp_date_retry_max            control_verification_flags.exp_date_retry_max%TYPE;
v_parent_group                  VARCHAR2 (60);
gen_next_line_2                 mgr_cat_genpan%ROWTYPE;
        CURSOR GEN_CURSOR
        IS
              SELECT   *
                FROM   MGR_CAT_GENPAN
            ORDER BY   LINE;
    BEGIN
        DELETE FROM   MGR_TRACE;

        DELETE FROM   MGR_CATALOGUE_INJECTED_PARAM;

        FOR ENR IN (SELECT   *
                      FROM   CARD_PRODUCT
                     WHERE   BANK_CODE = P_BANK_CODE  )
        LOOP
            V_BANK_CODE      := ENR.BANK_CODE;
            V_PRODUCT_CODE   := ENR.PRODUCT_CODE;
            V_FLAG           := TRUE;
            V_UNIQUE_INDEX   := 10;

            DELETE FROM   MGR_CAT_OUTPUT;

            FOR REC IN GEN_CURSOR
            LOOP
                IF REC.TEXT LIKE '%uniqueIndex%'
                THEN
                    REC.TEXT         := REPLACE (
                                            REC.TEXT,
                                            'uniqueIndex="'
                                            || SUBSTR (
                                                   REC.TEXT,
                                                   INSTR (REC.TEXT, 'uniqueIndex="') + 13,
                                                   INSTR (
                                                       SUBSTR (
                                                           REC.TEXT,
                                                           INSTR (REC.TEXT, 'uniqueIndex="')
                                                           + 13),
                                                       '"')
                                                   - 1),
                                            'uniqueIndex="' || V_UNIQUE_INDEX);
                    V_UNIQUE_INDEX   := V_UNIQUE_INDEX + 1;
                END IF;

                V_REQUIRED_FLAG   := FALSE;

                BEGIN
                    SELECT   *
                      INTO   GEN_NEXT_LINE
                      FROM   MGR_CAT_GENPAN
                     WHERE   LINE = REC.LINE + 1;
                EXCEPTION
                    WHEN NO_DATA_FOUND
                    THEN
                        NULL;
                END;

                IF V_END_BLOCK = REC.LINE
                THEN
                    V_CURRENT_GRP   := NULL;
                END IF;


                IF V_CURRENT_GRP = 'GRP_CARD_RANGE'
                   AND REC.LINE BETWEEN V_START_BLOCK AND V_END_BLOCK
                THEN
                    IF REC.LINE = V_START_BLOCK + 1
                    THEN
                        FOR TAB_REC
                        IN (SELECT   *
                              FROM   CARD_RANGE
                             WHERE   PRODUCT_CODE = V_PRODUCT_CODE
                                     AND ISSUING_BANK_CODE = V_BANK_CODE)
                        LOOP
                            FOR IN_REC
                            IN (  SELECT   *
                                    FROM   MGR_CAT_GENPAN
                                   WHERE   LINE BETWEEN V_START_IN_BLOCK AND V_END_IN_BLOCK
                                ORDER BY   LINE)
                            LOOP
                                IF IN_REC.TEXT LIKE '%uniqueIndex%'
                                THEN
                                    IN_REC.TEXT      := REPLACE (
                                                            IN_REC.TEXT,
                                                            'uniqueIndex="'
                                                            || SUBSTR (
                                                                   IN_REC.TEXT,
                                                                   INSTR (IN_REC.TEXT,
                                                                          'uniqueIndex="')
                                                                   + 13,
                                                                   INSTR (
                                                                       SUBSTR (
                                                                           IN_REC.TEXT,
                                                                           INSTR (
                                                                               IN_REC.TEXT,
                                                                               'uniqueIndex="')
                                                                           + 13),
                                                                       '"')
                                                                   - 1),
                                                            'uniqueIndex="'
                                                            || V_UNIQUE_INDEX);
                                    V_UNIQUE_INDEX   := V_UNIQUE_INDEX + 1;
                                END IF;

                                SELECT   *
                                  INTO   GEN_NEXT_LINE
                                  FROM   MGR_CAT_GENPAN
                                 WHERE   LINE = IN_REC.LINE + 1;

                                IF IN_REC.TEXT LIKE '%<Characteristic %'
                                THEN
                                    INSERT INTO MGR_CAT_OUTPUT
                                      VALUES   (MGR_CAT_LINE.NEXTVAL, IN_REC.TEXT);

                                    V_CHARACTERISTIC_ID   := SUBSTR (
                                                                 IN_REC.TEXT,
                                                                 INSTR (IN_REC.TEXT,
                                                                        'id="')
                                                                 + 4,
                                                                 INSTR (
                                                                     SUBSTR (
                                                                         IN_REC.TEXT,
                                                                         INSTR (
                                                                             IN_REC.TEXT,
                                                                             'id="')
                                                                         + 4),
                                                                     '"')
                                                                 - 1);

                                    BEGIN
                                        SELECT   DISTINCT FIELD_NAME
                                          INTO   V_FIELD_NAME
                                          FROM   CATALOGUE_MAPPING
                                         WHERE   PRODUCT_TYPE = 'P'
                                                 AND TAG_ID = V_CHARACTERISTIC_ID;
                                    EXCEPTION
                                        WHEN TOO_MANY_ROWS
                                        THEN
                                            IF V_CHARACTERISTIC_ID IN
                                                       ('CAR_CARD_RNG_ISS_BIN',
                                                        'CAR_CARD_RNG_SERVICE_CODE',
                                                        'CAR_NBR_CRD_TYPE',
                                                        'CAR_CARD_RNG_MIN_RANGE',
                                                        'CAR_CARD_RNG_MAX_RANGE')
                                            THEN
                                                SELECT   ENTITY_NAME, FIELD_NAME
                                                  INTO   V_ENTITY_NAME, V_FIELD_NAME
                                                  FROM   CATALOGUE_MAPPING
                                                 WHERE       PRODUCT_TYPE = 'P'
                                                         AND TAG_ID = V_CHARACTERISTIC_ID
                                                         AND ENTITY_NAME = 'Card_range';
                                            ELSIF V_CHARACTERISTIC_ID =
                                                      'CAR_CARD_RNG_CARD_FILE_OPT'
                                            THEN
                                                SELECT   ENTITY_NAME, FIELD_NAME
                                                  INTO   V_ENTITY_NAME, V_FIELD_NAME
                                                  FROM   CATALOGUE_MAPPING
                                                 WHERE   PRODUCT_TYPE = 'P'
                                                         AND TAG_ID = V_CHARACTERISTIC_ID
                                                         AND FIELD_NAME =
                                                                'card_file_option';
                                            ELSE
                                                INSERT INTO MGR_TRACE
                                                  VALUES   ('ERROR too_many_rows TAG_ID='
                                                            || V_CHARACTERISTIC_ID);

                                                COMMIT;
                                                EXIT;
                                            END IF;
                                        WHEN NO_DATA_FOUND
                                        THEN
                                            INSERT INTO MGR_TRACE
                                              VALUES   ('ERROR TAG NOT FOUND TAG_ID='
                                                        || V_CHARACTERISTIC_ID);

                                            V_VALUE   := '';
                                    END;



                                    --if lower(v_entity_name) = 'card_range' then
                                    IF V_FIELD_NAME = 'aav_seq_number'
                                    THEN
                                        V_VALUE   := TAB_REC.AAV_SEQ_NUMBER;
                                    ELSIF V_FIELD_NAME = 'alternate_cvv_key_number'
                                    THEN
                                        V_VALUE   := TAB_REC.ALTERNATE_CVV_KEY_NUMBER;
                                    ELSIF V_FIELD_NAME = 'alternate_pin_key_number'
                                    THEN
                                        V_VALUE   := TAB_REC.ALTERNATE_PIN_KEY_NUMBER;
                                    ELSIF V_FIELD_NAME = 'card_file_option'
                                    THEN
                                        V_VALUE   := TAB_REC.CARD_FILE_OPTION;
                                    ELSIF V_FIELD_NAME = 'card_number_length_max'
                                    THEN
                                        V_VALUE   := TAB_REC.CARD_NUMBER_LENGTH_MAX;
                                    ELSIF V_FIELD_NAME = 'card_number_length_min'
                                    THEN
                                        V_VALUE   := TAB_REC.CARD_NUMBER_LENGTH_MIN;
                                    ELSIF V_FIELD_NAME = 'card_status_code'
                                    THEN
                                        V_VALUE   := TAB_REC.CARD_STATUS_CODE;
                                    ELSIF V_FIELD_NAME = 'card_status_reason'
                                    THEN
                                        V_VALUE   := TAB_REC.CARD_STATUS_REASON;
                                    ELSIF V_FIELD_NAME = 'currency_code'
                                    THEN
                                        V_VALUE   := TAB_REC.CURRENCY_CODE;
                                    ELSIF V_FIELD_NAME = 'dcvv_cvc3_seq_num'
                                    THEN
                                        V_VALUE   := TAB_REC.DCVV_CVC3_SEQ_NUM;
                                    ELSIF V_FIELD_NAME = 'exception_cvv_key_number'
                                    THEN
                                        V_VALUE   := TAB_REC.EXCEPTION_CVV_KEY_NUMBER;
                                    ELSIF V_FIELD_NAME = 'exception_cvv_key_valdate'
                                    THEN
                                        V_VALUE   := TAB_REC.EXCEPTION_CVV_KEY_VALDATE;
                                    ELSIF V_FIELD_NAME = 'get_card_data_level'
                                    THEN
                                        V_VALUE   := TAB_REC.GET_CARD_DATA_LEVEL;
                                    ELSIF V_FIELD_NAME = 'issuer_bin'
                                    THEN
                                        V_VALUE   := TAB_REC.ISSUER_BIN;
                                    ELSIF V_FIELD_NAME = 'issuer_ica'
                                    THEN
                                        V_VALUE   := TAB_REC.ISSUER_ICA;
                                    ELSIF V_FIELD_NAME = 'language_code'
                                    THEN
                                        V_VALUE   := TAB_REC.LANGUAGE_CODE;
                                    ELSIF V_FIELD_NAME = 'max_card_range'
                                    THEN
                                        V_VALUE   := TAB_REC.MAX_CARD_RANGE;
                                    ELSIF V_FIELD_NAME = 'min_card_range'
                                    THEN
                                        V_VALUE   := TAB_REC.MIN_CARD_RANGE;
                                    ELSIF V_FIELD_NAME = 'network_card_type'
                                    THEN
                                        V_VALUE   := TAB_REC.NETWORK_CARD_TYPE;
                                    ELSIF V_FIELD_NAME = 'network_code'
                                    THEN
                                        V_VALUE   := TAB_REC.NETWORK_CODE;
                                    ELSIF V_FIELD_NAME = 'pin_length'
                                    THEN
                                        V_VALUE   := TAB_REC.PIN_LENGTH;
                                    ELSIF V_FIELD_NAME = 'pin_retry_max'
                                    THEN
                                        V_VALUE   := TAB_REC.PIN_RETRY_MAX;
                                    ELSIF V_FIELD_NAME = 'primary_cvv_key_number'
                                    THEN
                                        V_VALUE   := TAB_REC.PRIMARY_CVV_KEY_NUMBER;
                                    ELSIF V_FIELD_NAME = 'primary_pin_key_number'
                                    THEN
                                        V_VALUE   := TAB_REC.PRIMARY_PIN_KEY_NUMBER;
                                    ELSIF V_FIELD_NAME = 'service_code'
                                    THEN
                                        V_VALUE   := TAB_REC.SERVICE_CODE;
                                    ELSIF V_FIELD_NAME = 'start_cvv_alternate_key'
                                    THEN
                                        V_VALUE   := TAB_REC.START_CVV_ALTERNATE_KEY;
                                    ELSIF V_FIELD_NAME = 'start_pin_alternate_key'
                                    THEN
                                        V_VALUE   := TAB_REC.START_PIN_ALTERNATE_KEY;
                                    --end if;
                                    ELSE
                                        NULL;
                                    END IF;
                                ELSIF IN_REC.TEXT LIKE '%<CurrentStructure%'
                                      AND GEN_NEXT_LINE.TEXT NOT LIKE '%<Value%'
                                THEN
                                    INSERT INTO MGR_CAT_OUTPUT
                                      VALUES   (MGR_CAT_LINE.NEXTVAL,
                                                REPLACE (IN_REC.TEXT,
                                                         'CurrentStructure',
                                                         'ParentStructure'));

                                    INSERT INTO MGR_CAT_OUTPUT
                                      VALUES   (MGR_CAT_LINE.NEXTVAL,
                                                '                <CurrentStructure editable="true" mandatory="false" visible="true">');

                                    INSERT INTO MGR_CAT_OUTPUT
                                      VALUES   (MGR_CAT_LINE.NEXTVAL,
                                                '                                <Value>'
                                                || REPLACE (TRIM (V_VALUE), '&', '&amp;')
                                                || '</Value>');

                                    INSERT INTO MGR_CAT_OUTPUT
                                      VALUES   (MGR_CAT_LINE.NEXTVAL,
                                                '                </CurrentStructure>');
                                ELSIF IN_REC.TEXT LIKE '%<CurrentStructure%'
                                      AND GEN_NEXT_LINE.TEXT LIKE '%<Value%'
                                THEN
                                    INSERT INTO MGR_CAT_OUTPUT
                                      VALUES   (MGR_CAT_LINE.NEXTVAL,
                                                REPLACE (IN_REC.TEXT,
                                                         'CurrentStructure',
                                                         'ParentStructure'));

                                    INSERT INTO MGR_CAT_OUTPUT
                                      VALUES   (MGR_CAT_LINE.NEXTVAL, GEN_NEXT_LINE.TEXT);

                                    INSERT INTO MGR_CAT_OUTPUT
                                      VALUES   (MGR_CAT_LINE.NEXTVAL,
                                                '                </ParentStructure>');

                                    INSERT INTO MGR_CAT_OUTPUT
                                      VALUES   (MGR_CAT_LINE.NEXTVAL,
                                                '                <CurrentStructure editable="true" mandatory="false" visible="true">');

                                    INSERT INTO MGR_CAT_OUTPUT
                                      VALUES   (MGR_CAT_LINE.NEXTVAL,
                                                '                                <Value>'
                                                || REPLACE (TRIM (V_VALUE), '&', '&amp;')
                                                || '</Value>');

                                    INSERT INTO MGR_CAT_OUTPUT
                                      VALUES   (MGR_CAT_LINE.NEXTVAL,
                                                '                </CurrentStructure>');
                                ELSIF IN_REC.TEXT LIKE '%<Value%'
                                      OR IN_REC.TEXT LIKE '%</CurrentStructure%'
                                THEN
                                    CONTINUE;
                                ELSE
                                    INSERT INTO MGR_CAT_OUTPUT
                                      VALUES   (MGR_CAT_LINE.NEXTVAL, IN_REC.TEXT);
                                END IF;
                            END LOOP;
                        END LOOP;
                    END IF;

                    CONTINUE;
                END IF;



                IF V_CURRENT_GRP = 'GRP_MARKUP'
                   AND REC.LINE BETWEEN V_START_BLOCK AND V_END_BLOCK
                THEN
                    IF REC.LINE = V_START_BLOCK + 1
                    THEN
                        FOR TAB_REC
                        IN (  SELECT   *
                                FROM   MARKUP_CALCUL
                               WHERE   MARKUP_FEE_INDEX = ENR.MARKUP_CODE
                                       AND BANK_CODE = V_BANK_CODE
                            ORDER BY   MARKUP_ID_SEQ)
                        LOOP
                            V_FLAG   := TRUE;

                            FOR IN_REC
                            IN (  SELECT   *
                                    FROM   MGR_CAT_GENPAN
                                   WHERE   LINE BETWEEN V_START_IN_BLOCK AND V_END_IN_BLOCK
                                ORDER BY   LINE)
                            LOOP
                                IF IN_REC.TEXT LIKE '%uniqueIndex%'
                                THEN
                                    IN_REC.TEXT      := REPLACE (
                                                            IN_REC.TEXT,
                                                            'uniqueIndex="'
                                                            || SUBSTR (
                                                                   IN_REC.TEXT,
                                                                   INSTR (IN_REC.TEXT,
                                                                          'uniqueIndex="')
                                                                   + 13,
                                                                   INSTR (
                                                                       SUBSTR (
                                                                           IN_REC.TEXT,
                                                                           INSTR (
                                                                               IN_REC.TEXT,
                                                                               'uniqueIndex="')
                                                                           + 13),
                                                                       '"')
                                                                   - 1),
                                                            'uniqueIndex="'
                                                            || V_UNIQUE_INDEX);

                                    SELECT   COUNT ( * )
                                      INTO   V_CHECK_EXISTING_INJECTED
                                      FROM   MGR_CATALOGUE_INJECTED_PARAM
                                     WHERE       BANK_CODE = V_BANK_CODE
                                             AND PRODUCT_CODE = 'PAN' || V_PRODUCT_CODE
                                             AND ENTITY_NAME = 'Markup_calcul'
                                             AND PK_FIELD_VALUE_1 = TAB_REC.BANK_CODE
                                             AND PK_FIELD_VALUE_2 =
                                                    TAB_REC.MARKUP_FEE_INDEX
                                             AND PK_FIELD_VALUE_3 = TAB_REC.MARKUP_ID_SEQ;

                                    IF V_CHECK_EXISTING_INJECTED = 0
                                    THEN
                                        INSERT INTO MGR_CATALOGUE_INJECTED_PARAM (BANK_CODE,
                                                                                  PRODUCT_CODE,
                                                                                  PROD_VERSION,
                                                                                  PROD_SEQUENCE,
                                                                                  GROUP_DATA_INDEX,
                                                                                  ENTITY_NAME,
                                                                                  PK_FIELD_NAME_1,
                                                                                  PK_FIELD_VALUE_1,
                                                                                  PK_FIELD_NAME_2,
                                                                                  PK_FIELD_VALUE_2,
                                                                                  PK_FIELD_NAME_3,
                                                                                  PK_FIELD_VALUE_3,
                                                                                  PK_FIELD_NAME_4,
                                                                                  PK_FIELD_VALUE_4,
                                                                                  PK_FIELD_NAME_5,
                                                                                  PK_FIELD_VALUE_5,
                                                                                  PK_FIELD_NAME_6,
                                                                                  PK_FIELD_VALUE_6,
                                                                                  PK_FIELD_NAME_7,
                                                                                  PK_FIELD_VALUE_7,
                                                                                  USER_CREATE,
                                                                                  DATE_CREATE,
                                                                                  USER_MODIF,
                                                                                  DATE_MODIF)
                                          VALUES   (V_BANK_CODE,
                                                    'PAN' || V_PRODUCT_CODE,
                                                    '1',
                                                    V_PRODUCT_CODE,
                                                    V_UNIQUE_INDEX,
                                                    'Markup_calcul',
                                                    'bank_code',
                                                    V_BANK_CODE,
                                                    'markup_fee_index',
                                                    TAB_REC.MARKUP_FEE_INDEX,
                                                    'markup_id_seq',
                                                    TAB_REC.MARKUP_ID_SEQ,
                                                    NULL,
                                                    NULL,
                                                    NULL,
                                                    NULL,
                                                    NULL,
                                                    NULL,
                                                    NULL,
                                                    NULL,
                                                    'mgr',
                                                    NULL,
                                                    NULL,
                                                    NULL);
                                    END IF;

                                    V_UNIQUE_INDEX   := V_UNIQUE_INDEX + 1;
                                END IF;

                                SELECT   *
                                  INTO   GEN_NEXT_LINE
                                  FROM   MGR_CAT_GENPAN
                                 WHERE   LINE = IN_REC.LINE + 1;

