                                    V_CHARACTERISTIC_ID   := SUBSTR (
                                                                 IN_REC.TEXT,
                                                                 INSTR (IN_REC.TEXT,
                                                                        'id="')
                                                                 + 4,
                                                                 INSTR (
                                                                     SUBSTR (
                                                                         IN_REC.TEXT,
                                                                         INSTR (
                                                                             IN_REC.TEXT,
                                                                             'id="')
                                                                         + 4),
                                                                     '"')
                                                                 - 1);

                                    BEGIN
                                        SELECT   DISTINCT FIELD_NAME
                                          INTO   V_FIELD_NAME
                                          FROM   CATALOGUE_MAPPING
                                         WHERE   PRODUCT_TYPE = 'P'
                                                 AND TAG_ID = V_CHARACTERISTIC_ID;
                                    EXCEPTION
                                        WHEN TOO_MANY_ROWS
                                        THEN
                                            BEGIN
                                                SELECT   DISTINCT FIELD_NAME
                                                  INTO   V_FIELD_NAME
                                                  FROM   MGR_CATALOGUE_MAPPING
                                                 WHERE   PRODUCT_TYPE = 'P'
                                                         AND TAG_ID = V_CHARACTERISTIC_ID;
                                            EXCEPTION
                                                WHEN OTHERS
                                                THEN
                                                    INSERT INTO MGR_TRACE
                                                      VALUES   ('ERROR too_many_rows TAG_ID='
                                                                || V_CHARACTERISTIC_ID);

                                                    COMMIT;
                                                    EXIT;
                                            END;
                                        WHEN NO_DATA_FOUND
                                        THEN
                                            INSERT INTO MGR_TRACE
                                              VALUES   ('ERROR TAG NOT FOUND TAG_ID='
                                                        || V_CHARACTERISTIC_ID);

                                            IF V_CHARACTERISTIC_ID =
                                                   'CAR_MARKUP_SELECTED_CCY'
                                               AND V_FLAG = TRUE
                                            THEN
