                                                  INTO   GEN_NEXT_LINE
                                                  FROM   MGR_CAT_GENPAN
                                                 WHERE   LINE = IN_REC.LINE + 1;

                                                INSERT INTO MGR_CAT_OUTPUT
                                                  VALUES   (MGR_CAT_LINE.NEXTVAL,
                                                            REPLACE (IN_REC.TEXT,
                                                                     'CurrentStructure',
                                                                     'ParentStructure'));

                                                INSERT INTO MGR_CAT_OUTPUT
                                                  VALUES   (MGR_CAT_LINE.NEXTVAL,
                                                            '                <ParentStructure mandatory="false" visible="true">');


