                                    ELSIF V_FIELD_NAME = 'on_per1_onus_nbr'
                                    THEN
                                        V_VALUE   := TAB_REC.ON_PER1_ONUS_NBR;
                                    ELSIF V_FIELD_NAME = 'on_per1_nat_amnt'
                                    THEN
                                        V_VALUE   := TAB_REC.ON_PER1_NAT_AMNT;
                                    ELSIF V_FIELD_NAME = 'on_per1_nat_nbr'
                                    THEN
                                        V_VALUE   := TAB_REC.ON_PER1_NAT_NBR;
                                    ELSIF V_FIELD_NAME = 'on_per1_internat_amnt'
                                    THEN
                                        V_VALUE   := TAB_REC.ON_PER1_INTERNAT_AMNT;
                                    ELSIF V_FIELD_NAME = 'on_per1_internat_nbr'
                                    THEN
                                        V_VALUE   := TAB_REC.ON_PER1_INTERNAT_NBR;
                                    ELSIF V_FIELD_NAME = 'on_per1_tot_amnt'
                                    THEN
                                        V_VALUE   := TAB_REC.ON_PER1_TOT_AMNT;
                                    ELSIF V_FIELD_NAME = 'on_per1_tot_nbr'
                                    THEN
                                        V_VALUE   := TAB_REC.ON_PER1_TOT_NBR;
                                    ELSIF V_FIELD_NAME = 'on_per2_onus_amnt'
                                    THEN
                                        V_VALUE   := TAB_REC.ON_PER2_ONUS_AMNT;
                                    ELSIF V_FIELD_NAME = 'on_per2_onus_nbr'
                                    THEN
                                        V_VALUE   := TAB_REC.ON_PER2_ONUS_NBR;
                                    ELSIF V_FIELD_NAME = 'on_per2_nat_amnt'
                                    THEN
                                        V_VALUE   := TAB_REC.ON_PER2_NAT_AMNT;
                                    ELSIF V_FIELD_NAME = 'on_per2_nat_nbr'
                                    THEN
                                        V_VALUE   := TAB_REC.ON_PER2_NAT_NBR;
                                    ELSIF V_FIELD_NAME = 'on_per2_internat_amnt'
                                    THEN
                                        V_VALUE   := TAB_REC.ON_PER2_INTERNAT_AMNT;
                                    ELSIF V_FIELD_NAME = 'on_per2_internat_nbr'
                                    THEN
                                        V_VALUE   := TAB_REC.ON_PER2_INTERNAT_NBR;
                                    ELSIF V_FIELD_NAME = 'on_per2_tot_amnt'
                                    THEN
                                        V_VALUE   := TAB_REC.ON_PER2_TOT_AMNT;
                                    ELSIF V_FIELD_NAME = 'on_per2_tot_nbr'
                                    THEN
                                        V_VALUE   := TAB_REC.ON_PER2_TOT_NBR;
                                    ELSIF V_FIELD_NAME = 'on_per3_onus_amnt'
                                    THEN
                                        V_VALUE   := TAB_REC.ON_PER3_ONUS_AMNT;
                                    ELSIF V_FIELD_NAME = 'on_per3_onus_nbr'
                                    THEN
                                        V_VALUE   := TAB_REC.ON_PER3_ONUS_NBR;
                                    ELSIF V_FIELD_NAME = 'on_per3_nat_amnt'
                                    THEN
                                        V_VALUE   := TAB_REC.ON_PER3_NAT_AMNT;
                                    ELSIF V_FIELD_NAME = 'on_per3_nat_nbr'
                                    THEN
                                        V_VALUE   := TAB_REC.ON_PER3_NAT_NBR;
                                    ELSIF V_FIELD_NAME = 'on_per3_internat_amnt'
                                    THEN
                                        V_VALUE   := TAB_REC.ON_PER3_INTERNAT_AMNT;
                                    ELSIF V_FIELD_NAME = 'on_per3_internat_nbr'
                                    THEN
                                        V_VALUE   := TAB_REC.ON_PER3_INTERNAT_NBR;
                                    ELSIF V_FIELD_NAME = 'on_per3_tot_amnt'
                                    THEN
                                        V_VALUE   := TAB_REC.ON_PER3_TOT_AMNT;
                                    ELSIF V_FIELD_NAME = 'on_per3_tot_nbr'
                                    THEN
                                        V_VALUE   := TAB_REC.ON_PER3_TOT_NBR;
                                    ELSIF V_FIELD_NAME = 'on_per4_onus_amnt'
                                    THEN
                                        V_VALUE   := TAB_REC.ON_PER4_ONUS_AMNT;
                                    ELSIF V_FIELD_NAME = 'on_per4_onus_nbr'
                                    THEN
                                        V_VALUE   := TAB_REC.ON_PER4_ONUS_NBR;
                                    ELSIF V_FIELD_NAME = 'on_per4_nat_amnt'
                                    THEN
                                        V_VALUE   := TAB_REC.ON_PER4_NAT_AMNT;
                                    ELSIF V_FIELD_NAME = 'on_per4_nat_nbr'
                                    THEN
                                        V_VALUE   := TAB_REC.ON_PER4_NAT_NBR;
                                    ELSIF V_FIELD_NAME = 'on_per4_internat_amnt'
                                    THEN
                                        V_VALUE   := TAB_REC.ON_PER4_INTERNAT_AMNT;
                                    ELSIF V_FIELD_NAME = 'on_per4_internat_nbr'
                                    THEN
                                        V_VALUE   := TAB_REC.ON_PER4_INTERNAT_NBR;
                                    END IF;
                                ELSIF IN_REC.TEXT LIKE '%<CurrentStructure%'
                                      AND GEN_NEXT_LINE.TEXT NOT LIKE '%<Value%'
                                THEN
                                    INSERT INTO MGR_CAT_OUTPUT
                                      VALUES   (MGR_CAT_LINE.NEXTVAL,
                                                REPLACE (IN_REC.TEXT,
                                                         'CurrentStructure',
                                                         'ParentStructure'));

                                    INSERT INTO MGR_CAT_OUTPUT
                                      VALUES   (MGR_CAT_LINE.NEXTVAL,
                                                '                <CurrentStructure editable="true" mandatory="false" visible="true">');

                                    INSERT INTO MGR_CAT_OUTPUT
                                      VALUES   (MGR_CAT_LINE.NEXTVAL,
                                                '                                <Value>'
                                                || REPLACE (TRIM (V_VALUE), '&', '&amp;')
                                                || '</Value>');

                                    INSERT INTO MGR_CAT_OUTPUT
                                      VALUES   (MGR_CAT_LINE.NEXTVAL,
                                                '                </CurrentStructure>');
                                ELSIF IN_REC.TEXT LIKE '%<CurrentStructure%'
                                      AND GEN_NEXT_LINE.TEXT LIKE '%<Value%'
                                THEN
                                    INSERT INTO MGR_CAT_OUTPUT
                                      VALUES   (MGR_CAT_LINE.NEXTVAL,
                                                REPLACE (IN_REC.TEXT,
                                                         'CurrentStructure',
                                                         'ParentStructure'));

                                    INSERT INTO MGR_CAT_OUTPUT
                                      VALUES   (MGR_CAT_LINE.NEXTVAL, GEN_NEXT_LINE.TEXT);

                                    INSERT INTO MGR_CAT_OUTPUT
                                      VALUES   (MGR_CAT_LINE.NEXTVAL,
                                                '                </ParentStructure>');

                                    INSERT INTO MGR_CAT_OUTPUT
                                      VALUES   (MGR_CAT_LINE.NEXTVAL,
                                                '                <CurrentStructure editable="true" mandatory="false" visible="true">');

                                    INSERT INTO MGR_CAT_OUTPUT
                                      VALUES   (MGR_CAT_LINE.NEXTVAL,
                                                '                                <Value>'
                                                || REPLACE (TRIM (V_VALUE), '&', '&amp;')
                                                || '</Value>');

