                                ELSE
                                    INSERT INTO MGR_CAT_OUTPUT
                                      VALUES   (MGR_CAT_LINE.NEXTVAL, IN_REC.TEXT);
                                END IF;
                            END LOOP;
                        END LOOP;
                    END IF;

                    CONTINUE;
                END IF;

                IF V_CURRENT_GRP = 'GRP_CONTEXTS'
                   AND REC.LINE BETWEEN V_START_BLOCK AND V_END_BLOCK
                THEN
                    IF REC.LINE = V_START_BLOCK + 1
                    THEN
                        FOR TAB_REC
                        IN (SELECT   *
                              FROM   P7_SPEC_TRANS_LIMITS
                             WHERE   TRIM (LIMIT_INDEX) = ENR.LIMITS_INDEXES
                                     AND BANK_CODE = V_BANK_CODE)
                        LOOP
                            FOR IN_REC
                            IN (  SELECT   *
                                    FROM   MGR_CAT_GENPAN
                                   WHERE   LINE BETWEEN V_START_IN_BLOCK AND V_END_IN_BLOCK
                                ORDER BY   LINE)
                            LOOP
                                IF IN_REC.TEXT LIKE '%uniqueIndex%'
                                THEN
                                    IN_REC.TEXT      := REPLACE (
                                                            IN_REC.TEXT,
                                                            'uniqueIndex="'
                                                            || SUBSTR (
                                                                   IN_REC.TEXT,
                                                                   INSTR (IN_REC.TEXT,
                                                                          'uniqueIndex="')
                                                                   + 13,
                                                                   INSTR (
                                                                       SUBSTR (
                                                                           IN_REC.TEXT,
                                                                           INSTR (
                                                                               IN_REC.TEXT,
                                                                               'uniqueIndex="')
                                                                           + 13),
                                                                       '"')
                                                                   - 1),
                                                            'uniqueIndex="'
                                                            || V_UNIQUE_INDEX);

                                    SELECT   COUNT ( * )
                                      INTO   V_CHECK_EXISTING_INJECTED
                                      FROM   MGR_CATALOGUE_INJECTED_PARAM
                                     WHERE       BANK_CODE = V_BANK_CODE
                                             AND PRODUCT_CODE = 'PAN' || V_PRODUCT_CODE
                                             AND ENTITY_NAME = 'P7_spec_trans_limits'
                                             AND PK_FIELD_VALUE_1 = TAB_REC.SEQ_NUMBER;

                                    IF V_CHECK_EXISTING_INJECTED = 0
                                    THEN
                                        INSERT INTO MGR_CATALOGUE_INJECTED_PARAM (BANK_CODE,
                                                                                  PRODUCT_CODE,
                                                                                  PROD_VERSION,
                                                                                  PROD_SEQUENCE,
                                                                                  GROUP_DATA_INDEX,
                                                                                  ENTITY_NAME,
                                                                                  PK_FIELD_NAME_1,
                                                                                  PK_FIELD_VALUE_1,
                                                                                  PK_FIELD_NAME_2,
                                                                                  PK_FIELD_VALUE_2,
                                                                                  PK_FIELD_NAME_3,
                                                                                  PK_FIELD_VALUE_3,
                                                                                  PK_FIELD_NAME_4,
                                                                                  PK_FIELD_VALUE_4,
                                                                                  PK_FIELD_NAME_5,
                                                                                  PK_FIELD_VALUE_5,
                                                                                  PK_FIELD_NAME_6,
                                                                                  PK_FIELD_VALUE_6,
                                                                                  PK_FIELD_NAME_7,
                                                                                  PK_FIELD_VALUE_7,
                                                                                  USER_CREATE,
                                                                                  DATE_CREATE,
                                                                                  USER_MODIF,
                                                                                  DATE_MODIF)
