                                END IF;

                                SELECT   *
                                  INTO   GEN_NEXT_LINE
                                  FROM   MGR_CAT_GENPAN
                                 WHERE   LINE = IN_REC.LINE + 1;

                                IF IN_REC.TEXT LIKE '%<Characteristic %'
                                THEN
                                    INSERT INTO MGR_CAT_OUTPUT
                                      VALUES   (MGR_CAT_LINE.NEXTVAL, IN_REC.TEXT);

                                    V_CHARACTERISTIC_ID   := SUBSTR (
                                                                 IN_REC.TEXT,
                                                                 INSTR (IN_REC.TEXT,
                                                                        'id="')
                                                                 + 4,
                                                                 INSTR (
                                                                     SUBSTR (
                                                                         IN_REC.TEXT,
                                                                         INSTR (
                                                                             IN_REC.TEXT,
                                                                             'id="')
                                                                         + 4),
                                                                     '"')
                                                                 - 1);

                                    BEGIN
                                        SELECT   DISTINCT FIELD_NAME
                                          INTO   V_FIELD_NAME
                                          FROM   CATALOGUE_MAPPING
                                         WHERE   PRODUCT_TYPE = 'P'
                                                 AND TAG_ID = V_CHARACTERISTIC_ID;
                                    EXCEPTION
                                        WHEN TOO_MANY_ROWS
                                        THEN
                                            INSERT INTO MGR_TRACE
                                              VALUES   ('ERROR too_many_rows TAG_ID='
                                                        || V_CHARACTERISTIC_ID);

                                            COMMIT;
                                            EXIT;
                                        WHEN NO_DATA_FOUND
                                        THEN
                                            INSERT INTO MGR_TRACE
                                              VALUES   ('ERROR TAG NOT FOUND TAG_ID='
                                                        || V_CHARACTERISTIC_ID);

                                            V_VALUE   := '';
                                    END;


                                    IF V_FIELD_NAME = 'wording'
                                    THEN
                                        V_VALUE   := TAB_REC.WORDING;
                                    ELSIF V_FIELD_NAME = 'processing_code'
                                    THEN
                                        V_VALUE   := TAB_REC.PROCESSING_CODE;
                                    ELSIF V_FIELD_NAME = 'function_code'
                                    THEN
                                        V_VALUE   := TAB_REC.FUNCTION_CODE;
                                    ELSIF V_FIELD_NAME = 'country_code'
                                    THEN
                                        V_VALUE   := TAB_REC.COUNTRY_CODE;
                                    ELSIF V_FIELD_NAME = 'card_present'
                                    THEN
                                        V_VALUE   := TAB_REC.CARD_PRESENT;
                                    ELSIF V_FIELD_NAME = 'card_entry_mode'
                                    THEN
                                        V_VALUE   := TAB_REC.CARD_ENTRY_MODE;
                                    ELSIF V_FIELD_NAME = 'mcc'
                                    THEN
                                        V_VALUE   := TAB_REC.MCC;
                                    ELSIF V_FIELD_NAME = 'mcc_group'
                                    THEN
                                        V_VALUE   := TAB_REC.MCC_GROUP;
                                    ELSIF V_FIELD_NAME = 'payment_type_query'
                                    THEN
                                        V_VALUE   := TAB_REC.PAYMENT_TYPE_QUERY;
                                    ELSIF V_FIELD_NAME = 'transaction_currency_code'
                                    THEN
                                        V_VALUE   := TAB_REC.TRANSACTION_CURRENCY_CODE;
                                    ELSIF V_FIELD_NAME = 'limits_id'
                                    THEN
                                        V_VALUE   := TAB_REC.LIMITS_ID;
                                    ELSIF V_FIELD_NAME = 'min_amount_per_transaction'
                                    THEN
                                        V_VALUE   := TAB_REC.MIN_AMOUNT_PER_TRANSACTION;
                                    ELSIF V_FIELD_NAME = 'max_amount_per_transaction'
                                    THEN
                                        V_VALUE   := TAB_REC.MAX_AMOUNT_PER_TRANSACTION;
                                    ELSIF V_FIELD_NAME = 'add_amount_opt'
                                    THEN
                                        V_VALUE   := TAB_REC.ADD_AMOUNT_OPT;
                                    ELSIF V_FIELD_NAME = 'add_limit_id'
                                    THEN
                                        V_VALUE   := TAB_REC.ADD_LIMIT_ID;
                                    ELSIF V_FIELD_NAME = 'add_min_trx_amount'
                                    THEN
                                        V_VALUE   := TAB_REC.ADD_MIN_TRX_AMOUNT;
                                    ELSIF V_FIELD_NAME = 'add_max_trx_amount'
                                    THEN
                                        V_VALUE   := TAB_REC.ADD_MAX_TRX_AMOUNT;
                                    ELSIF V_FIELD_NAME = 'add_min_trx_amnt_per'
                                    THEN
                                        V_VALUE   := TAB_REC.ADD_MIN_TRX_AMNT_PER;
                                    ELSIF V_FIELD_NAME = 'add_max_trx_amnt_per'
                                    THEN
                                        V_VALUE   := TAB_REC.ADD_MAX_TRX_AMNT_PER;
                                    ELSIF V_FIELD_NAME = 'financial_flag'
                                    THEN
                                        V_VALUE   := TAB_REC.FINANCIAL_FLAG;
                                    ELSIF V_FIELD_NAME = 'authorization_type_flag'
                                    THEN
                                        V_VALUE   := TAB_REC.AUTHORIZATION_TYPE_FLAG;
                                    ELSIF V_FIELD_NAME = 'initiated_merchant_flag'
                                    THEN
                                        V_VALUE   := TAB_REC.INITIATED_MERCHANT_FLAG;
                                    END IF;
                                ELSIF IN_REC.TEXT LIKE '%<CurrentStructure%'
                                      AND GEN_NEXT_LINE.TEXT NOT LIKE '%<Value%'
                                THEN
                                    INSERT INTO MGR_CAT_OUTPUT
                                      VALUES   (MGR_CAT_LINE.NEXTVAL,
                                                REPLACE (IN_REC.TEXT,
                                                         'CurrentStructure',
                                                         'ParentStructure'));

                                    INSERT INTO MGR_CAT_OUTPUT
                                      VALUES   (MGR_CAT_LINE.NEXTVAL,
                                                '                <CurrentStructure editable="true" mandatory="false" visible="true">');

                                    INSERT INTO MGR_CAT_OUTPUT
                                      VALUES   (MGR_CAT_LINE.NEXTVAL,
                                                '                                <Value>'
                                                || REPLACE (V_VALUE, '&', '&amp;')
                                                || '</Value>');

                                    INSERT INTO MGR_CAT_OUTPUT
                                      VALUES   (MGR_CAT_LINE.NEXTVAL,
                                                '                </CurrentStructure>');
                                ELSIF IN_REC.TEXT LIKE '%<CurrentStructure%'
                                      AND GEN_NEXT_LINE.TEXT LIKE '%<Value%'
                                THEN
                                    INSERT INTO MGR_CAT_OUTPUT
                                      VALUES   (MGR_CAT_LINE.NEXTVAL,
                                                REPLACE (IN_REC.TEXT,
                                                         'CurrentStructure',
                                                         'ParentStructure'));

                                    INSERT INTO MGR_CAT_OUTPUT
                                      VALUES   (MGR_CAT_LINE.NEXTVAL, GEN_NEXT_LINE.TEXT);

                                    INSERT INTO MGR_CAT_OUTPUT
                                      VALUES   (MGR_CAT_LINE.NEXTVAL,
                                                '                </ParentStructure>');

                                    INSERT INTO MGR_CAT_OUTPUT
                                      VALUES   (MGR_CAT_LINE.NEXTVAL,
                                                '                <CurrentStructure editable="true" mandatory="false" visible="true">');

                                    INSERT INTO MGR_CAT_OUTPUT
                                      VALUES   (MGR_CAT_LINE.NEXTVAL,
                                                '                                <Value>'
                                                || REPLACE (V_VALUE, '&', '&amp;')
                                                || '</Value>');

                                    INSERT INTO MGR_CAT_OUTPUT
                                      VALUES   (MGR_CAT_LINE.NEXTVAL,
                                                '                </CurrentStructure>');
                                ELSIF IN_REC.TEXT LIKE '%<Value%'
                                      OR IN_REC.TEXT LIKE '%</CurrentStructure%'
                                THEN
                                    CONTINUE;
                                ELSE
                                    INSERT INTO MGR_CAT_OUTPUT
                                      VALUES   (MGR_CAT_LINE.NEXTVAL, IN_REC.TEXT);
                                END IF;
                            END LOOP;
                        END LOOP;
                    END IF;

                    CONTINUE;
                END IF;



                IF V_CURRENT_GRP = 'GRP_SERVICE'
                   AND REC.LINE BETWEEN V_START_BLOCK AND V_END_BLOCK
                THEN
                    IF REC.LINE = V_START_BLOCK + 1
                    THEN
                        FOR TAB_REC
                        IN (SELECT   *
                              FROM   P7_SERVICES_SETUP
                             WHERE   SERVICE_SETUP_INDEX IN
                                             (SELECT   SERVICES_SETUP_INDEX
                                                FROM   CARD_PRODUCT
                                               WHERE   PRODUCT_CODE = V_PRODUCT_CODE
                                                       AND BANK_CODE = V_BANK_CODE)
                                     AND BANK_CODE = V_BANK_CODE)
                        LOOP
                            FOR IN_REC
                            IN (  SELECT   *
                                    FROM   MGR_CAT_GENPAN
                                   WHERE   LINE BETWEEN V_START_IN_BLOCK AND V_END_IN_BLOCK
                                ORDER BY   LINE)
                            LOOP
                                IF IN_REC.TEXT LIKE '%uniqueIndex%'
                                THEN
                                    IN_REC.TEXT      := REPLACE (
                                                            IN_REC.TEXT,
                                                            'uniqueIndex="'
                                                            || SUBSTR (
                                                                   IN_REC.TEXT,
                                                                   INSTR (IN_REC.TEXT,
                                                                          'uniqueIndex="')
                                                                   + 13,
                                                                   INSTR (
                                                                       SUBSTR (
                                                                           IN_REC.TEXT,
                                                                           INSTR (
                                                                               IN_REC.TEXT,
                                                                               'uniqueIndex="')
                                                                           + 13),
                                                                       '"')
                                                                   - 1),
                                                            'uniqueIndex="'
                                                            || V_UNIQUE_INDEX);

                                    SELECT   COUNT ( * )
                                      INTO   V_CHECK_EXISTING_INJECTED
                                      FROM   MGR_CATALOGUE_INJECTED_PARAM
                                     WHERE       BANK_CODE = V_BANK_CODE
                                             AND PRODUCT_CODE = 'PAN' || V_PRODUCT_CODE
                                             AND ENTITY_NAME = 'P7_services_setup'
                                             AND PK_FIELD_VALUE_1 = to_number(TAB_REC.SEQUENCE_ID);

                                    IF V_CHECK_EXISTING_INJECTED = 0
                                    THEN
                                        INSERT INTO MGR_CATALOGUE_INJECTED_PARAM (BANK_CODE,
                                                                                  PRODUCT_CODE,
                                                                                  PROD_VERSION,
                                                                                  PROD_SEQUENCE,
                                                                                  GROUP_DATA_INDEX,
                                                                                  ENTITY_NAME,
                                                                                  PK_FIELD_NAME_1,
                                                                                  PK_FIELD_VALUE_1,
                                                                                  PK_FIELD_NAME_2,
                                                                                  PK_FIELD_VALUE_2,
                                                                                  PK_FIELD_NAME_3,
                                                                                  PK_FIELD_VALUE_3,
                                                                                  PK_FIELD_NAME_4,
                                                                                  PK_FIELD_VALUE_4,
                                                                                  PK_FIELD_NAME_5,
                                                                                  PK_FIELD_VALUE_5,
                                                                                  PK_FIELD_NAME_6,
                                                                                  PK_FIELD_VALUE_6,
                                                                                  PK_FIELD_NAME_7,
                                                                                  PK_FIELD_VALUE_7,
                                                                                  USER_CREATE,
                                                                                  DATE_CREATE,
                                                                                  USER_MODIF,
                                                                                  DATE_MODIF)
                                          VALUES   (V_BANK_CODE,
                                                    'PAN' || V_PRODUCT_CODE,
                                                    '1',
                                                    V_PRODUCT_CODE,
                                                    V_UNIQUE_INDEX,
                                                    'P7_services_setup',
                                                    'sequence_id',
                                                    TAB_REC.SEQUENCE_ID,
                                                    NULL,
                                                    NULL,
                                                    NULL,
                                                    NULL,
                                                    NULL,
                                                    NULL,
                                                    NULL,
                                                    NULL,
                                                    NULL,
                                                    NULL,
                                                    NULL,
                                                    NULL,
                                                    'mgr',
                                                    NULL,
                                                    NULL,
                                                    NULL);
                                    END IF;

                                    V_UNIQUE_INDEX   := V_UNIQUE_INDEX + 1;
                                END IF;

                                SELECT   *
                                  INTO   GEN_NEXT_LINE
                                  FROM   MGR_CAT_GENPAN
                                 WHERE   LINE = IN_REC.LINE + 1;

                                IF IN_REC.TEXT LIKE '%<Characteristic %'
                                THEN
                                    INSERT INTO MGR_CAT_OUTPUT
                                      VALUES   (MGR_CAT_LINE.NEXTVAL, IN_REC.TEXT);

                                    V_CHARACTERISTIC_ID   := SUBSTR (
                                                                 IN_REC.TEXT,
                                                                 INSTR (IN_REC.TEXT,
                                                                        'id="')
                                                                 + 4,
                                                                 INSTR (
                                                                     SUBSTR (
                                                                         IN_REC.TEXT,
                                                                         INSTR (
                                                                             IN_REC.TEXT,
                                                                             'id="')
                                                                         + 4),
                                                                     '"')
                                                                 - 1);

                                    BEGIN
                                        SELECT   DISTINCT FIELD_NAME
                                          INTO   V_FIELD_NAME
                                          FROM   CATALOGUE_MAPPING
                                         WHERE   PRODUCT_TYPE = 'P'
                                                 AND TAG_ID = V_CHARACTERISTIC_ID;
                                    EXCEPTION
                                        WHEN TOO_MANY_ROWS
                                        THEN
                                            INSERT INTO MGR_TRACE
                                              VALUES   ('ERROR too_many_rows TAG_ID='
                                                        || V_CHARACTERISTIC_ID);

                                            COMMIT;
                                            EXIT;
                                    END;


                                    IF V_FIELD_NAME = 'mti'
                                    THEN
                                        V_VALUE   := TAB_REC.MTI;
                                    ELSIF V_FIELD_NAME = 'abrv_wording'
                                    THEN
                                        V_VALUE   := TAB_REC.ABRV_WORDING;
                                    ELSIF V_FIELD_NAME = 'processing_code'
                                    THEN
                                        V_VALUE   := TAB_REC.PROCESSING_CODE;
                                    ELSIF V_FIELD_NAME = 'function_code'
                                    THEN
                                        V_VALUE   := TAB_REC.FUNCTION_CODE;
                                    ELSIF V_FIELD_NAME = 'tcc'
                                    THEN
                                        V_VALUE   := TAB_REC.TCC;
                                    ELSIF V_FIELD_NAME = 'source_account'
                                    THEN
                                        V_VALUE   := TAB_REC.SOURCE_ACCOUNT;
                                    ELSIF V_FIELD_NAME = 'destination_account'
                                    THEN
                                        V_VALUE   := TAB_REC.DESTINATION_ACCOUNT;
                                    ELSIF V_FIELD_NAME = 'wording'
                                    THEN
                                        V_VALUE   := TAB_REC.WORDING;
                                    ELSIF V_FIELD_NAME = 'discrimination_flag'
                                    THEN
                                        V_VALUE   := TAB_REC.DISCRIMINATION_FLAG;
                                    END IF;
                                ELSIF IN_REC.TEXT LIKE '%<CurrentStructure%'
                                      AND GEN_NEXT_LINE.TEXT NOT LIKE '%<Value%'
                                THEN
                                    INSERT INTO MGR_CAT_OUTPUT
                                      VALUES   (MGR_CAT_LINE.NEXTVAL,
                                                REPLACE (IN_REC.TEXT,
                                                         'CurrentStructure',
                                                         'ParentStructure'));

                                    INSERT INTO MGR_CAT_OUTPUT
                                      VALUES   (MGR_CAT_LINE.NEXTVAL,
                                                '                <CurrentStructure editable="true" mandatory="false" visible="true">');

                                    INSERT INTO MGR_CAT_OUTPUT
                                      VALUES   (MGR_CAT_LINE.NEXTVAL,
                                                '                                <Value>'
                                                || REPLACE (V_VALUE, '&', '&amp;')
                                                || '</Value>');

                                    INSERT INTO MGR_CAT_OUTPUT
                                      VALUES   (MGR_CAT_LINE.NEXTVAL,
                                                '                </CurrentStructure>');
                                ELSIF IN_REC.TEXT LIKE '%<CurrentStructure%'
                                      AND GEN_NEXT_LINE.TEXT LIKE '%<Value%'
                                THEN
                                    INSERT INTO MGR_CAT_OUTPUT
                                      VALUES   (MGR_CAT_LINE.NEXTVAL,
                                                REPLACE (IN_REC.TEXT,
                                                         'CurrentStructure',
                                                         'ParentStructure'));

                                    INSERT INTO MGR_CAT_OUTPUT
                                      VALUES   (MGR_CAT_LINE.NEXTVAL, GEN_NEXT_LINE.TEXT);

                                    INSERT INTO MGR_CAT_OUTPUT
                                      VALUES   (MGR_CAT_LINE.NEXTVAL,
                                                '                </ParentStructure>');

                                    INSERT INTO MGR_CAT_OUTPUT
                                      VALUES   (MGR_CAT_LINE.NEXTVAL,
                                                '                <CurrentStructure editable="true" mandatory="false" visible="true">');

                                    INSERT INTO MGR_CAT_OUTPUT
                                      VALUES   (MGR_CAT_LINE.NEXTVAL,
                                                '                                <Value>'
                                                || REPLACE (V_VALUE, '&', '&amp;')
                                                || '</Value>');

                                    INSERT INTO MGR_CAT_OUTPUT
                                      VALUES   (MGR_CAT_LINE.NEXTVAL,
                                                '                </CurrentStructure>');
                                ELSIF IN_REC.TEXT LIKE '%<Value%'
                                      OR IN_REC.TEXT LIKE '%</CurrentStructure%'
                                THEN
                                    CONTINUE;
                                ELSE
                                    INSERT INTO MGR_CAT_OUTPUT
                                      VALUES   (MGR_CAT_LINE.NEXTVAL, IN_REC.TEXT);
                                END IF;
                            END LOOP;
                        END LOOP;
                    END IF;

                    CONTINUE;
                END IF;


                IF V_CURRENT_GRP = 'GRP_FEES_ON_TRANS_ARRAY'
                   AND REC.LINE BETWEEN V_START_BLOCK AND V_END_BLOCK
                THEN
                    IF REC.LINE = V_START_BLOCK + 1
                    THEN
                        V_FIRST_FLAG   := 'Y';

                        SELECT   COUNT ( * )
                          INTO   V_COUNT_CHECK
                          FROM   ISS_TRANSACTION_FEES_PARAM
                         WHERE   CARD_PRODUCT_CODE = V_PRODUCT_CODE
                                 AND ISSUER_BANK_CODE = V_BANK_CODE;

                        IF V_COUNT_CHECK = '0'
                        THEN
                            FOR IN_REC
                            IN (  SELECT   *
                                    FROM   MGR_CAT_GENPAN
                                   WHERE   LINE BETWEEN V_START_IN_BLOCK AND V_END_IN_BLOCK
                                ORDER BY   LINE)
                            LOOP
                                SELECT   *
                                  INTO   GEN_NEXT_LINE
                                  FROM   MGR_CAT_GENPAN
                                 WHERE   LINE = IN_REC.LINE + 1;

                                IF IN_REC.TEXT LIKE '%<Characteristic %'
                                THEN
                                    INSERT INTO MGR_CAT_OUTPUT
                                      VALUES   (MGR_CAT_LINE.NEXTVAL, IN_REC.TEXT);

                                    V_VALUE   := '';
                                ELSIF IN_REC.TEXT LIKE '%<CurrentStructure%'
                                      AND GEN_NEXT_LINE.TEXT NOT LIKE '%<Value%'
                                THEN
                                    INSERT INTO MGR_CAT_OUTPUT
                                      VALUES   (MGR_CAT_LINE.NEXTVAL,
                                                REPLACE (IN_REC.TEXT,
                                                         'CurrentStructure',
                                                         'ParentStructure'));

                                    INSERT INTO MGR_CAT_OUTPUT
                                      VALUES   (MGR_CAT_LINE.NEXTVAL,
                                                '                <CurrentStructure editable="true" mandatory="false" visible="true">');

                                    INSERT INTO MGR_CAT_OUTPUT
                                      VALUES   (MGR_CAT_LINE.NEXTVAL,
                                                '                                <Value>'
                                                || REPLACE (V_VALUE, '&', '&amp;')
                                                || '</Value>');

                                    INSERT INTO MGR_CAT_OUTPUT
                                      VALUES   (MGR_CAT_LINE.NEXTVAL,
                                                '                </CurrentStructure>');
                                ELSIF IN_REC.TEXT LIKE '%<CurrentStructure%'
                                      AND GEN_NEXT_LINE.TEXT LIKE '%<Value%'
                                THEN
                                    INSERT INTO MGR_CAT_OUTPUT
                                      VALUES   (MGR_CAT_LINE.NEXTVAL,
                                                REPLACE (IN_REC.TEXT,
                                                         'CurrentStructure',
                                                         'ParentStructure'));

                                    INSERT INTO MGR_CAT_OUTPUT
                                      VALUES   (MGR_CAT_LINE.NEXTVAL, GEN_NEXT_LINE.TEXT);

                                    INSERT INTO MGR_CAT_OUTPUT
                                      VALUES   (MGR_CAT_LINE.NEXTVAL,
                                                '                </ParentStructure>');

                                    INSERT INTO MGR_CAT_OUTPUT
                                      VALUES   (MGR_CAT_LINE.NEXTVAL,
                                                '                <CurrentStructure editable="true" mandatory="false" visible="true">');

                                    INSERT INTO MGR_CAT_OUTPUT
                                      VALUES   (MGR_CAT_LINE.NEXTVAL,
                                                '                                <Value>'
                                                || REPLACE (V_VALUE, '&', '&amp;')
                                                || '</Value>');

                                    INSERT INTO MGR_CAT_OUTPUT
                                      VALUES   (MGR_CAT_LINE.NEXTVAL,
                                                '                </CurrentStructure>');
                                ELSIF IN_REC.TEXT LIKE '%<Value%'
                                      OR IN_REC.TEXT LIKE '%</CurrentStructure%'
                                THEN
                                    CONTINUE;
                                ELSE
                                    INSERT INTO MGR_CAT_OUTPUT
                                      VALUES   (MGR_CAT_LINE.NEXTVAL, IN_REC.TEXT);
                                END IF;
                            END LOOP;
                        ELSE
                            FOR TAB_REC
                            IN (SELECT   *
                                  FROM   ISS_TRANSACTION_FEES_PARAM
                                 WHERE   CARD_PRODUCT_CODE = V_PRODUCT_CODE
                                         AND ISSUER_BANK_CODE = V_BANK_CODE)
                            LOOP
                                IF V_FIRST_FLAG = 'Y'
                                THEN
                                    FOR IN_REC
                                    IN (  SELECT   *
                                            FROM   MGR_CAT_GENPAN
                                           WHERE   LINE BETWEEN V_START_IN_BLOCK
                                                            AND  V_END_IN_BLOCK
                                        ORDER BY   LINE)
                                    LOOP
                                        IF IN_REC.TEXT LIKE '%uniqueIndex%'
                                        THEN
                                            IN_REC.TEXT      := REPLACE (
                                                                    IN_REC.TEXT,
                                                                    'uniqueIndex="'
                                                                    || SUBSTR (
                                                                           IN_REC.TEXT,
                                                                           INSTR (
                                                                               IN_REC.TEXT,
                                                                               'uniqueIndex="')
                                                                           + 13,
                                                                           INSTR (
                                                                               SUBSTR (
                                                                                   IN_REC.TEXT,
                                                                                   INSTR (
                                                                                       IN_REC.TEXT,
                                                                                       'uniqueIndex="')
                                                                                   + 13),
                                                                               '"')
                                                                           - 1),
                                                                    'uniqueIndex="'
                                                                    || V_UNIQUE_INDEX);

                                            V_UNIQUE_INDEX   := V_UNIQUE_INDEX + 1;
                                        END IF;

                                        SELECT   *
                                          INTO   GEN_NEXT_LINE
                                          FROM   MGR_CAT_GENPAN
                                         WHERE   LINE = IN_REC.LINE + 1;

                                        IF IN_REC.TEXT LIKE '%<Characteristic %'
                                        THEN
                                            INSERT INTO MGR_CAT_OUTPUT
                                              VALUES   (MGR_CAT_LINE.NEXTVAL, IN_REC.TEXT)
;

                                            V_VALUE   := '';
                                        ELSIF IN_REC.TEXT LIKE '%<CurrentStructure%'
                                              AND GEN_NEXT_LINE.TEXT NOT LIKE '%<Value%'
                                        THEN
                                            INSERT INTO MGR_CAT_OUTPUT
                                              VALUES   (MGR_CAT_LINE.NEXTVAL,
                                                        REPLACE (IN_REC.TEXT,
                                                                 'CurrentStructure',
                                                                 'ParentStructure'));

                                            INSERT INTO MGR_CAT_OUTPUT
                                              VALUES   (MGR_CAT_LINE.NEXTVAL,
                                                        '                <CurrentStructure editable="true" mandatory="false" visible="true">');

                                            INSERT INTO MGR_CAT_OUTPUT
                                              VALUES   (MGR_CAT_LINE.NEXTVAL,
                                                        '                                <Value>'
                                                        || REPLACE (V_VALUE,
                                                                    '&',
                                                                    '&amp;')
                                                        || '</Value>');

                                            INSERT INTO MGR_CAT_OUTPUT
                                              VALUES   (MGR_CAT_LINE.NEXTVAL,
                                                        '                </CurrentStructure>');
                                        ELSIF IN_REC.TEXT LIKE '%<CurrentStructure%'
                                              AND GEN_NEXT_LINE.TEXT LIKE '%<Value%'
                                        THEN
                                            INSERT INTO MGR_CAT_OUTPUT
                                              VALUES   (MGR_CAT_LINE.NEXTVAL,
                                                        REPLACE (IN_REC.TEXT,
                                                                 'CurrentStructure',
                                                                 'ParentStructure'));

                                            INSERT INTO MGR_CAT_OUTPUT
                                              VALUES   (MGR_CAT_LINE.NEXTVAL,
                                                        GEN_NEXT_LINE.TEXT);

                                            INSERT INTO MGR_CAT_OUTPUT
                                              VALUES   (MGR_CAT_LINE.NEXTVAL,
                                                        '                </ParentStructure>');

                                            INSERT INTO MGR_CAT_OUTPUT
                                              VALUES   (MGR_CAT_LINE.NEXTVAL,
                                                        '                <CurrentStructure editable="true" mandatory="false" visible="true">');

                                            INSERT INTO MGR_CAT_OUTPUT
                                              VALUES   (MGR_CAT_LINE.NEXTVAL,
                                                        '                                <Value>'
                                                        || REPLACE (V_VALUE,
                                                                    '&',
                                                                    '&amp;')
                                                        || '</Value>');

                                            INSERT INTO MGR_CAT_OUTPUT
                                              VALUES   (MGR_CAT_LINE.NEXTVAL,
                                                        '                </CurrentStructure>');
                                        ELSIF IN_REC.TEXT LIKE '%<Value%'
                                              OR IN_REC.TEXT LIKE '%</CurrentStructure%'
                                        THEN
                                            CONTINUE;
                                        ELSE
                                            INSERT INTO MGR_CAT_OUTPUT
                                              VALUES   (MGR_CAT_LINE.NEXTVAL, IN_REC.TEXT)
;
                                        END IF;
                                    END LOOP;

                                    V_FIRST_FLAG   := 'N';
                                END IF;



                                FOR IN_REC
                                IN (  SELECT   *
                                        FROM   MGR_CAT_GENPAN
                                       WHERE   LINE BETWEEN V_START_IN_BLOCK
                                                        AND  V_END_IN_BLOCK
                                    ORDER BY   LINE)
                                LOOP
                                    IF IN_REC.TEXT LIKE '%uniqueIndex%'
                                    THEN
                                        IN_REC.TEXT      := REPLACE (
                                                                IN_REC.TEXT,
                                                                'uniqueIndex="'
                                                                || SUBSTR (
                                                                       IN_REC.TEXT,
                                                                       INSTR (
                                                                           IN_REC.TEXT,
                                                                           'uniqueIndex="')
                                                                       + 13,
                                                                       INSTR (
                                                                           SUBSTR (
                                                                               IN_REC.TEXT,
                                                                               INSTR (
                                                                                   IN_REC.TEXT,
                                                                                   'uniqueIndex="')
                                                                               + 13),
                                                                           '"')
                                                                       - 1),
                                                                'uniqueIndex="'
                                                                || V_UNIQUE_INDEX);

                                        SELECT   COUNT ( * )
                                          INTO   V_CHECK_EXISTING_INJECTED
                                          FROM   MGR_CATALOGUE_INJECTED_PARAM
                                         WHERE   BANK_CODE = V_BANK_CODE
                                                 AND PRODUCT_CODE =
                                                        'PAN' || V_PRODUCT_CODE
                                                 AND ENTITY_NAME =
                                                        'Iss_transaction_fees_param'
                                                 AND PK_FIELD_VALUE_1 =
                                                        TAB_REC.SEQUENCE_ID;


                                        IF V_CHECK_EXISTING_INJECTED = 0
                                        THEN
                                            INSERT INTO MGR_CATALOGUE_INJECTED_PARAM (BANK_CODE,
                                                                                      PRODUCT_CODE,
                                                                                      PROD_VERSION,
                                                                                      PROD_SEQUENCE,
                                                                                      GROUP_DATA_INDEX,
                                                                                      ENTITY_NAME,
                                                                                      PK_FIELD_NAME_1,
                                                                                      PK_FIELD_VALUE_1,
                                                                                      PK_FIELD_NAME_2,
                                                                                      PK_FIELD_VALUE_2,
                                                                                      PK_FIELD_NAME_3,
                                                                                      PK_FIELD_VALUE_3,
                                                                                      PK_FIELD_NAME_4,
                                                                                      PK_FIELD_VALUE_4,
                                                                                      PK_FIELD_NAME_5,
                                                                                      PK_FIELD_VALUE_5,
                                                                                      PK_FIELD_NAME_6,
                                                                                      PK_FIELD_VALUE_6,
                                                                                      PK_FIELD_NAME_7,
                                                                                      PK_FIELD_VALUE_7,
                                                                                      USER_CREATE,
                                                                                      DATE_CREATE,
                                                                                      USER_MODIF,
                                                                                      DATE_MODIF)
                                              VALUES   (V_BANK_CODE,
                                                        'PAN' || V_PRODUCT_CODE,
                                                        '1',
                                                        V_PRODUCT_CODE,
                                                        V_UNIQUE_INDEX,
                                                        'Iss_transaction_fees_param',
                                                        'sequence_id',
                                                        TAB_REC.SEQUENCE_ID,
                                                        NULL,
                                                        NULL,
                                                        NULL,
                                                        NULL,
                                                        NULL,
                                                        NULL,
                                                        NULL,
                                                        NULL,
                                                        NULL,
                                                        NULL,
                                                        NULL,
                                                        NULL,
                                                        'mgr',
                                                        NULL,
                                                        NULL,
                                                        NULL);
                                        END IF;

                                        V_UNIQUE_INDEX   := V_UNIQUE_INDEX + 1;
                                    END IF;

                                    SELECT   *
                                      INTO   GEN_NEXT_LINE
                                      FROM   MGR_CAT_GENPAN
                                     WHERE   LINE = IN_REC.LINE + 1;

                                    IF IN_REC.TEXT LIKE '%<Characteristic %'
                                    THEN
                                        INSERT INTO MGR_CAT_OUTPUT
                                          VALUES   (MGR_CAT_LINE.NEXTVAL, IN_REC.TEXT);

                                        V_CHARACTERISTIC_ID   := SUBSTR (
                                                                     IN_REC.TEXT,
                                                                     INSTR (IN_REC.TEXT,
                                                                            'id="')
                                                                     + 4,
                                                                     INSTR (
                                                                         SUBSTR (
                                                                             IN_REC.TEXT,
                                                                             INSTR (
                                                                                 IN_REC.TEXT,
                                                                                 'id="')
                                                                             + 4),
                                                                         '"')
                                                                     - 1);

                                        BEGIN
                                            SELECT   DISTINCT FIELD_NAME
                                              INTO   V_FIELD_NAME
                                              FROM   CATALOGUE_MAPPING
                                             WHERE   PRODUCT_TYPE = 'P'
                                                     AND TAG_ID = V_CHARACTERISTIC_ID;
                                        EXCEPTION
                                            WHEN TOO_MANY_ROWS
                                            THEN
                                                INSERT INTO MGR_TRACE
                                                  VALUES   ('ERROR too_many_rows TAG_ID='
                                                            || V_CHARACTERISTIC_ID);

                                                COMMIT;
                                                EXIT;
                                        END;


                                        IF V_FIELD_NAME = 'sequence_id'
                                        THEN
                                            V_VALUE   := TAB_REC.SEQUENCE_ID;
                                        ELSIF V_FIELD_NAME = 'grace_amount'
                                        THEN
                                            V_VALUE   := TAB_REC.GRACE_AMOUNT;
                                        ELSIF V_FIELD_NAME = 'origin_code'
                                        THEN
                                            V_VALUE   := TAB_REC.ORIGIN_CODE;
                                        ELSIF V_FIELD_NAME = 'currency_code_transaction'
                                        THEN
                                            V_VALUE   := TAB_REC.CURRENCY_CODE_TRANSACTION
;
                                        ELSIF V_FIELD_NAME = 'reversal_flag'
                                        THEN
                                            V_VALUE   := TAB_REC.REVERSAL_FLAG;
                                        ELSIF V_FIELD_NAME = 'mcc_group'
                                        THEN
                                            V_VALUE   := TAB_REC.MCC_GROUP;
                                        ELSIF V_FIELD_NAME = 'mcc'
                                        THEN
                                            V_VALUE   := TAB_REC.MCC;
                                        ELSIF V_FIELD_NAME = 'tcc'
                                        THEN
                                            V_VALUE   := TAB_REC.TCC;
                                        ELSIF V_FIELD_NAME = 'min_amount'
                                        THEN
                                            V_VALUE   := TAB_REC.MIN_AMOUNT;
                                        ELSIF V_FIELD_NAME = 'max_amount'
                                        THEN
                                            V_VALUE   := TAB_REC.MAX_AMOUNT;
                                        ELSIF V_FIELD_NAME = 'fixed_amount'
                                        THEN
                                            V_VALUE   := TAB_REC.FIXED_AMOUNT;
                                        ELSIF V_FIELD_NAME = 'threshold_amount'
                                        THEN
                                            V_VALUE   := TAB_REC.THRESHOLD_AMOUNT;
                                        ELSIF V_FIELD_NAME = 'rounded_method_identifier'
                                        THEN
                                            V_VALUE   := TAB_REC.ROUNDED_METHOD_IDENTIFIER
;
                                        ELSIF V_FIELD_NAME = 'rule_identifier'
                                        THEN
                                            V_VALUE   := TAB_REC.RULE_IDENTIFIER;
                                        ELSIF V_FIELD_NAME = 'processing_rules'
                                        THEN
                                            V_VALUE   := TAB_REC.PROCESSING_RULES;
                                        ELSIF V_FIELD_NAME = 'rate'
                                        THEN
                                            V_VALUE   := TAB_REC.RATE;
                                        ELSIF V_FIELD_NAME = 'description'
                                        THEN
                                            V_VALUE   := TAB_REC.DESCRIPTION;
                                        ELSIF V_FIELD_NAME = 'transaction_fees_code'
                                        THEN
                                            V_VALUE   := TAB_REC.TRANSACTION_FEES_CODE;
                                        ELSIF V_FIELD_NAME = 'transaction_code'
                                        THEN
                                            V_VALUE   := TAB_REC.TRANSACTION_CODE;
                                        ELSIF V_FIELD_NAME = 'tax_calculation'
                                        THEN
                                            V_VALUE   := TAB_REC.TAX_CALCULATION;
                                        END IF;
                                    ELSIF IN_REC.TEXT LIKE '%<CurrentStructure%'
                                          AND GEN_NEXT_LINE.TEXT NOT LIKE '%<Value%'
                                    THEN
                                        INSERT INTO MGR_CAT_OUTPUT
                                          VALUES   (MGR_CAT_LINE.NEXTVAL,
                                                    REPLACE (IN_REC.TEXT,
                                                             'CurrentStructure',
                                                             'ParentStructure'));

                                        INSERT INTO MGR_CAT_OUTPUT
                                          VALUES   (MGR_CAT_LINE.NEXTVAL,
                                                    '                <CurrentStructure editable="true" mandatory="false" visible="true">');

                                        INSERT INTO MGR_CAT_OUTPUT
                                          VALUES   (MGR_CAT_LINE.NEXTVAL,
                                                    '                                <Value>'
                                                    || REPLACE (V_VALUE, '&', '&amp;')
                                                    || '</Value>');

                                        INSERT INTO MGR_CAT_OUTPUT
                                          VALUES   (MGR_CAT_LINE.NEXTVAL,
                                                    '                </CurrentStructure>')
;
                                    ELSIF IN_REC.TEXT LIKE '%<CurrentStructure%'
                                          AND GEN_NEXT_LINE.TEXT LIKE '%<Value%'
                                    THEN
                                        INSERT INTO MGR_CAT_OUTPUT
                                          VALUES   (MGR_CAT_LINE.NEXTVAL,
                                                    REPLACE (IN_REC.TEXT,
                                                             'CurrentStructure',
                                                             'ParentStructure'));

                                        INSERT INTO MGR_CAT_OUTPUT
                                          VALUES   (MGR_CAT_LINE.NEXTVAL,
                                                    GEN_NEXT_LINE.TEXT);

                                        INSERT INTO MGR_CAT_OUTPUT
                                          VALUES   (MGR_CAT_LINE.NEXTVAL,
                                                    '                </ParentStructure>');

                                        INSERT INTO MGR_CAT_OUTPUT
                                          VALUES   (MGR_CAT_LINE.NEXTVAL,
                                                    '                <CurrentStructure editable="true" mandatory="false" visible="true">');

                                        INSERT INTO MGR_CAT_OUTPUT
                                          VALUES   (MGR_CAT_LINE.NEXTVAL,
                                                    '                                <Value>'
                                                    || REPLACE (V_VALUE, '&', '&amp;')
                                                    || '</Value>');

                                        INSERT INTO MGR_CAT_OUTPUT
                                          VALUES   (MGR_CAT_LINE.NEXTVAL,
                                                    '                </CurrentStructure>')
;
                                    ELSIF IN_REC.TEXT LIKE '%<Value%'
                                          OR IN_REC.TEXT LIKE '%</CurrentStructure%'
                                    THEN
                                        CONTINUE;
                                    ELSE
                                        INSERT INTO MGR_CAT_OUTPUT
                                          VALUES   (MGR_CAT_LINE.NEXTVAL, IN_REC.TEXT);
                                    END IF;
                                END LOOP;
                            END LOOP;
                        END IF;
                    END IF;

                    CONTINUE;
                END IF;


                IF V_CURRENT_GRP = 'GRP_EMV_ARC_CARD_BLOCKED'
                   AND REC.LINE BETWEEN V_START_BLOCK AND V_END_BLOCK
                THEN
                    IF REC.LINE = V_START_BLOCK + 1
                    THEN
                        V_FIRST_FLAG   := 'Y';

                        SELECT   COUNT ( * )
                          INTO   V_COUNT_CHECK
                          FROM   ARPC_RESPONSE_CODE_MAPPING
                         WHERE   ICC_APPLICATION_INDEX IN
                                         (SELECT   ICC_APPLICATION_INDEX
                                            FROM   CARD_PRODUCT
                                           WHERE   PRODUCT_CODE = V_PRODUCT_CODE
                                                   AND BANK_CODE = V_BANK_CODE)
                                 AND BANK_CODE = V_BANK_CODE
                                 AND PRODUCT_CODE = V_PRODUCT_CODE;

                        IF V_COUNT_CHECK = '0'
                        THEN
                            FOR IN_REC
                            IN (  SELECT   *
                                    FROM   MGR_CAT_GENPAN
                                   WHERE   LINE BETWEEN V_START_IN_BLOCK AND V_END_IN_BLOCK
                                ORDER BY   LINE)
                            LOOP
                                SELECT   *
                                  INTO   GEN_NEXT_LINE
                                  FROM   MGR_CAT_GENPAN
                                 WHERE   LINE = IN_REC.LINE + 1;

                                IF IN_REC.TEXT LIKE '%<Characteristic %'
                                THEN
                                    INSERT INTO MGR_CAT_OUTPUT
                                      VALUES   (MGR_CAT_LINE.NEXTVAL, IN_REC.TEXT);

                                    V_VALUE   := '';
                                ELSIF IN_REC.TEXT LIKE '%<CurrentStructure%'
                                      AND GEN_NEXT_LINE.TEXT NOT LIKE '%<Value%'
                                THEN
                                    INSERT INTO MGR_CAT_OUTPUT
                                      VALUES   (MGR_CAT_LINE.NEXTVAL,
                                                REPLACE (IN_REC.TEXT,
                                                         'CurrentStructure',
                                                         'ParentStructure'));

                                    INSERT INTO MGR_CAT_OUTPUT
                                      VALUES   (MGR_CAT_LINE.NEXTVAL,
                                                '                <CurrentStructure editable="true" mandatory="false" visible="true">');

                                    INSERT INTO MGR_CAT_OUTPUT
                                      VALUES   (MGR_CAT_LINE.NEXTVAL,
                                                '                                <Value>'
                                                || REPLACE (V_VALUE, '&', '&amp;')
                                                || '</Value>');

                                    INSERT INTO MGR_CAT_OUTPUT
                                      VALUES   (MGR_CAT_LINE.NEXTVAL,
                                                '                </CurrentStructure>');
                                ELSIF IN_REC.TEXT LIKE '%<CurrentStructure%'
                                      AND GEN_NEXT_LINE.TEXT LIKE '%<Value%'
                                THEN
                                    INSERT INTO MGR_CAT_OUTPUT
                                      VALUES   (MGR_CAT_LINE.NEXTVAL,
                                                REPLACE (IN_REC.TEXT,
                                                         'CurrentStructure',
                                                         'ParentStructure'));

                                    INSERT INTO MGR_CAT_OUTPUT
                                      VALUES   (MGR_CAT_LINE.NEXTVAL, GEN_NEXT_LINE.TEXT);

                                    INSERT INTO MGR_CAT_OUTPUT
                                      VALUES   (MGR_CAT_LINE.NEXTVAL,
                                                '                </ParentStructure>');

                                    INSERT INTO MGR_CAT_OUTPUT
                                      VALUES   (MGR_CAT_LINE.NEXTVAL,
                                                '                <CurrentStructure editable="true" mandatory="false" visible="true">');

