                                                            elsif v_field_name='cashback_transaction_code' then
                                                            v_value:=tab_rec.cashback_transaction_code;
                                                            elsif v_field_name='currency_code' then
                                                            v_value:=tab_rec.currency_code;
                                                            elsif v_field_name='customer_segment_index' then
                                                            v_value:=tab_rec.customer_segment_index;
                                                            elsif v_field_name='fee_id' then
                                                            v_value:=tab_rec.fee_id;
                                                            elsif v_field_name='fee_priority' then
                                                            v_value:=tab_rec.fee_priority;
                                                            elsif v_field_name='fee_type' then
                                                            v_value:=tab_rec.fee_type;
                                                            elsif v_field_name='fees_amount_threshold' then
                                                            v_value:=tab_rec.fees_amount_threshold;
                                                            elsif v_field_name='fees_indicator' then
                                                            v_value:=tab_rec.fees_indicator;
                                                            elsif v_field_name='inc_check_avail' then
                                                            v_value:=tab_rec.inc_check_avail;
                                                            elsif v_field_name='mcc' then
                                                            v_value:=tab_rec.mcc;
                                                            elsif v_field_name='mcc_group' then
                                                            v_value:=tab_rec.mcc_group;
                                                            elsif v_field_name='network_region' then
                                                            v_value:=tab_rec.network_region;
                                                            elsif v_field_name='origin_code' then
                                                            v_value:=tab_rec.origin_code;
                                                            elsif v_field_name='processing_code' then
                                                            v_value:=tab_rec.processing_code;
                                                            elsif v_field_name='receipt_flag' then
                                                            v_value:=tab_rec.receipt_flag;
                                                            elsif v_field_name='rounded_method_identifier' then
                                                            v_value:=tab_rec.rounded_method_identifier;
                                                            elsif v_field_name='rule_identifier' then
                                                            v_value:=tab_rec.rule_identifier;
                                                            elsif v_field_name='tiered_fees_amount' then
                                                            v_value:=tab_rec.tiered_fees_amount;
                                                            elsif v_field_name='tiered_fees_rate' then
                                                            v_value:=tab_rec.tiered_fees_rate;
                                                            elsif v_field_name='transaction_code' then
                                                            v_value:=tab_rec.transaction_code;
                                                            elsif v_field_name='transaction_currency' then
                                                            v_value:=tab_rec.transaction_currency;
                                                            elsif v_field_name='vip_level' then
                                                            v_value:=tab_rec.vip_level;
                                                            elsif v_field_name='wording' then
                                                            v_value:=tab_rec.wording;

                                    end if;


                                elsif in_rec.text like '%<CurrentStructure%' and gen_next_line.text not like '%<Value%' then
                                        insert into mgr_cat_output values (mgr_cat_line.nextval,replace(in_rec.text,'CurrentStructure','ParentStructure'));
                                        insert into mgr_cat_output values (mgr_cat_line.nextval,'                <CurrentStructure editable="true" mandatory="false" visible="true">');
                                        insert into mgr_cat_output values (mgr_cat_line.nextval,'                                <Value>'||replace(v_value,'&','&amp;')||'</Value>');
                                        insert into mgr_cat_output values (mgr_cat_line.nextval,'                </CurrentStructure>');

                                    elsif in_rec.text like '%<CurrentStructure%' and gen_next_line.text  like '%<Value%' then
                                        insert into mgr_cat_output values (mgr_cat_line.nextval,replace(in_rec.text,'CurrentStructure','ParentStructure'));
                                        insert into mgr_cat_output values (mgr_cat_line.nextval,gen_next_line.text);
                                        insert into mgr_cat_output values (mgr_cat_line.nextval,'                </ParentStructure>');
                                        insert into mgr_cat_output values (mgr_cat_line.nextval,'                <CurrentStructure editable="true" mandatory="false" visible="true">');
                                        insert into mgr_cat_output values (mgr_cat_line.nextval,'                                <Value>'||replace(v_value,'&','&amp;')||'</Value>');
                                        insert into mgr_cat_output values (mgr_cat_line.nextval,'                </CurrentStructure>');
                                    elsif in_rec.text like   '%<Value%' or in_rec.text  like '%</CurrentStructure%' then
                                        continue;
                                    else
                                    insert into mgr_cat_output values (mgr_cat_line.nextval,in_rec.text);

                                end if;
                            end loop;
                        end loop;

                    end if;
                    continue;
                end if;


                */

          IF     v_current_grp = 'GRP_CTRL_DECISION_MATRIX'
               AND rec.line BETWEEN v_start_block AND v_end_block
            THEN
                IF rec.line = v_start_block + 1
                THEN                                                      ---2
                    v_first_flag := 'Y';

                    IF v_parent_group IS NULL
                    THEN
                        v_parent_group := 'GRP_CTRL_DECISION_MATRIX';
                    END IF;

                    SELECT *
                      INTO gen_next_line_2
                      FROM mgr_cat_genpan
                     WHERE line = rec.line - 2;



                    --if rec.text like '%<GroupData%id=%' then

                    IF gen_next_line_2.text LIKE '%<GroupData%id=%'
                    THEN                                                   --5
                        v_parent_group :=
                            SUBSTR (
                                gen_next_line_2.text,
                                INSTR (gen_next_line_2.text, 'id="') + 4,
                                  INSTR (
                                      SUBSTR (
                                          gen_next_line_2.text,
                                            INSTR (gen_next_line_2.text,
                                                   'id="')
                                          + 4),
                                      '"')
                                - 1);
                        DBMS_OUTPUT.put_line (
                            rec.line || 'PG-ctrl=' || v_parent_group);
                    END IF;                                                --5

                    IF v_parent_group = 'GRP_CTRL_DECISION_ON'
                    THEN                                                  ---4
                        SELECT COUNT (*)
                          INTO v_count_check
                          FROM p7_ctrl_decision_matrix
                         WHERE     on_off_flag = 'ON'
                               AND control_verification_index IN (SELECT control_verification_index
                                                                    FROM card_product
                                                                   WHERE     bank_code =
                                                                                 v_bank_code
                                                                         AND product_code =
                                                                                 v_product_code)
                               AND bank_code = v_bank_code;

                        IF v_count_check = '0'
                        THEN                                              ---3
                            FOR in_rec
                                IN (SELECT *
                                      FROM mgr_cat_genpan
                                     WHERE line BETWEEN v_start_in_block
                                                    AND v_end_in_block
                                    ORDER BY line)
                            LOOP
                                SELECT *
                                  INTO gen_next_line
                                  FROM mgr_cat_genpan
                                 WHERE line = in_rec.line + 1;

                                IF in_rec.text LIKE '%<Characteristic %'
                                THEN
                                    INSERT INTO mgr_cat_output
                                        VALUES (
                                                   mgr_cat_line.NEXTVAL,
                                                   in_rec.text);

                                    v_value := '';
                                ELSIF     in_rec.text LIKE
                                              '%<CurrentStructure%'
                                      AND gen_next_line.text NOT LIKE
                                              '%<Value%'
                                THEN
                                    INSERT INTO mgr_cat_output
                                        VALUES (
                                                   mgr_cat_line.NEXTVAL,
                                                   REPLACE (
                                                       in_rec.text,
                                                       'CurrentStructure',
                                                       'ParentStructure'));

                                    INSERT INTO mgr_cat_output
                                        VALUES (
                                                   mgr_cat_line.NEXTVAL,
                                                   '                <CurrentStructure editable="true" mandatory="false" visible="true">');

                                    INSERT INTO mgr_cat_output
                                        VALUES (
                                                   mgr_cat_line.NEXTVAL,
                                                      '                                <Value>'
                                                   || REPLACE (v_value,
                                                               '&',
                                                               '&amp;')
                                                   || '</Value>');

                                    INSERT INTO mgr_cat_output
                                        VALUES (
                                                   mgr_cat_line.NEXTVAL,
                                                   '                </CurrentStructure>');
                                ELSIF     in_rec.text LIKE
                                              '%<CurrentStructure%'
                                      AND gen_next_line.text LIKE '%<Value%'
                                THEN
                                    INSERT INTO mgr_cat_output
                                        VALUES (
                                                   mgr_cat_line.NEXTVAL,
                                                   REPLACE (
                                                       in_rec.text,
                                                       'CurrentStructure',
                                                       'ParentStructure'));

                                    INSERT INTO mgr_cat_output
                                        VALUES (
                                                   mgr_cat_line.NEXTVAL,
                                                   gen_next_line.text);

                                    INSERT INTO mgr_cat_output
                                        VALUES (
                                                   mgr_cat_line.NEXTVAL,
                                                   '                </ParentStructure>');

                                    INSERT INTO mgr_cat_output
                                        VALUES (
                                                   mgr_cat_line.NEXTVAL,
                                                   '                <CurrentStructure editable="true" mandatory="false" visible="true">');

                                    INSERT INTO mgr_cat_output
                                        VALUES (
                                                   mgr_cat_line.NEXTVAL,
                                                      '                                <Value>'
                                                   || REPLACE (v_value,
                                                               '&',
                                                               '&amp;')
                                                   || '</Value>');

                                    INSERT INTO mgr_cat_output
                                        VALUES (
                                                   mgr_cat_line.NEXTVAL,
                                                   '                </CurrentStructure>');
                                ELSIF    in_rec.text LIKE '%<Value%'
                                      OR in_rec.text LIKE
                                             '%</CurrentStructure%'
                                THEN
                                    CONTINUE;
                                ELSE
                                    INSERT INTO mgr_cat_output
                                        VALUES (
                                                   mgr_cat_line.NEXTVAL,
                                                   in_rec.text);
                                END IF;
                            END LOOP;
                        ELSE
                            FOR tab_rec
                                IN (SELECT *
                                      FROM p7_ctrl_decision_matrix
                                     WHERE     on_off_flag = 'ON'
                                           AND control_verification_index IN (SELECT control_verification_index
                                                                                FROM card_product
                                                                               WHERE     bank_code =
                                                                                             v_bank_code
                                                                                     AND product_code =
                                                                                             v_product_code)
                                           AND bank_code = v_bank_code)
                            LOOP
                                IF v_first_flag = 'Y'
                                THEN
                                    FOR in_rec
                                        IN (SELECT *
                                              FROM mgr_cat_genpan
                                             WHERE line BETWEEN v_start_in_block
                                                            AND v_end_in_block
                                            ORDER BY line)
                                    LOOP
                                        IF in_rec.text LIKE '%uniqueIndex%'
                                        THEN
                                            in_rec.text :=
                                                REPLACE (
                                                    in_rec.text,
                                                       'uniqueIndex="'
                                                    || SUBSTR (
                                                           in_rec.text,
                                                             INSTR (
                                                                 in_rec.text,
                                                                 'uniqueIndex="')
                                                           + 13,
                                                             INSTR (
                                                                 SUBSTR (
                                                                     in_rec.text,
                                                                       INSTR (
                                                                           in_rec.text,
                                                                           'uniqueIndex="')
                                                                     + 13),
                                                                 '"')
                                                           - 1),
                                                       'uniqueIndex="'
                                                    || v_unique_index);

                                            v_unique_index :=
                                                v_unique_index + 1;
                                        END IF;

                                        SELECT *
                                          INTO gen_next_line
                                          FROM mgr_cat_genpan
                                         WHERE line = in_rec.line + 1;

                                        IF in_rec.text LIKE
                                               '%<Characteristic %'
                                        THEN
                                            INSERT INTO mgr_cat_output
                                                VALUES (
                                                           mgr_cat_line.NEXTVAL,
                                                           in_rec.text);

                                            v_value := '';
                                        ELSIF     in_rec.text LIKE
                                                      '%<CurrentStructure%'
                                              AND gen_next_line.text NOT LIKE
                                                      '%<Value%'
                                        THEN
                                            INSERT INTO mgr_cat_output
                                                VALUES (
                                                           mgr_cat_line.NEXTVAL,
                                                           REPLACE (
                                                               in_rec.text,
                                                               'CurrentStructure',
                                                               'ParentStructure'));

                                            INSERT INTO mgr_cat_output
                                                VALUES (
                                                           mgr_cat_line.NEXTVAL,
                                                           '                <CurrentStructure editable="true" mandatory="false" visible="true">');

                                            INSERT INTO mgr_cat_output
                                                VALUES (
                                                           mgr_cat_line.NEXTVAL,
                                                              '                                <Value>'
                                                           || REPLACE (
                                                                  v_value,
                                                                  '&',
                                                                  '&amp;')
                                                           || '</Value>');

                                            INSERT INTO mgr_cat_output
                                                VALUES (
                                                           mgr_cat_line.NEXTVAL,
                                                           '                </CurrentStructure>');
                                        ELSIF     in_rec.text LIKE
                                                      '%<CurrentStructure%'
                                              AND gen_next_line.text LIKE
                                                      '%<Value%'
                                        THEN
                                            INSERT INTO mgr_cat_output
                                                VALUES (
                                                           mgr_cat_line.NEXTVAL,
                                                           REPLACE (
                                                               in_rec.text,
                                                               'CurrentStructure',
                                                               'ParentStructure'));

                                            INSERT INTO mgr_cat_output
                                                VALUES (
                                                           mgr_cat_line.NEXTVAL,
                                                           gen_next_line.text);

                                            INSERT INTO mgr_cat_output
                                                VALUES (
                                                           mgr_cat_line.NEXTVAL,
                                                           '                </ParentStructure>');

                                            INSERT INTO mgr_cat_output
                                                VALUES (
                                                           mgr_cat_line.NEXTVAL,
                                                           '                <CurrentStructure editable="true" mandatory="false" visible="true">');

                                            INSERT INTO mgr_cat_output
                                                VALUES (
                                                           mgr_cat_line.NEXTVAL,
                                                              '                                <Value>'
                                                           || REPLACE (
                                                                  v_value,
                                                                  '&',
                                                                  '&amp;')
                                                           || '</Value>');

                                            INSERT INTO mgr_cat_output
                                                VALUES (
                                                           mgr_cat_line.NEXTVAL,
                                                           '                </CurrentStructure>');
                                        ELSIF    in_rec.text LIKE '%<Value%'
                                              OR in_rec.text LIKE
                                                     '%</CurrentStructure%'
                                        THEN
                                            CONTINUE;
                                        ELSE
                                            INSERT INTO mgr_cat_output
                                                VALUES (
                                                           mgr_cat_line.NEXTVAL,
                                                           in_rec.text);
                                        END IF;
                                    END LOOP;

                                    v_first_flag := 'N';
                                END IF;



                                FOR in_rec
                                    IN (SELECT *
                                          FROM mgr_cat_genpan
                                         WHERE line BETWEEN v_start_in_block
                                                        AND v_end_in_block
                                        ORDER BY line)
                                LOOP
                                    IF in_rec.text LIKE '%uniqueIndex%'
                                    THEN
                                        in_rec.text :=
                                            REPLACE (
                                                in_rec.text,
                                                   'uniqueIndex="'
                                                || SUBSTR (
                                                       in_rec.text,
                                                         INSTR (
                                                             in_rec.text,
                                                             'uniqueIndex="')
                                                       + 13,
                                                         INSTR (
                                                             SUBSTR (
                                                                 in_rec.text,
                                                                   INSTR (
                                                                       in_rec.text,
                                                                       'uniqueIndex="')
                                                                 + 13),
                                                             '"')
                                                       - 1),
                                                   'uniqueIndex="'
                                                || v_unique_index);

                                        SELECT COUNT (*)
                                          INTO v_check_existing_injected
                                          FROM mgr_catalogue_injected_param
                                         WHERE     bank_code = v_bank_code
                                               AND product_code =
                                                          'PAN'
                                                       || v_product_code
                                               AND entity_name =
                                                       'P7_ctrl_decision_matrix'
                                               AND pk_field_value_1 =
                                                       tab_rec.bank_code
                                               AND pk_field_value_2 =
                                                       tab_rec.control_verification_index
                                               AND pk_field_value_3 =
                                                       tab_rec.on_off_flag
                                               AND pk_field_value_4 =
                                                       tab_rec.ctrl_id
                                               AND pk_field_value_5 =
                                                       tab_rec.ctrl_results;

                                        IF v_check_existing_injected = 0
                                        THEN
                                            INSERT
                                              INTO mgr_catalogue_injected_param (
                                                       bank_code,
                                                       product_code,
                                                       prod_version,
                                                       prod_sequence,
                                                       group_data_index,
                                                       entity_name,
                                                       pk_field_name_1,
                                                       pk_field_value_1,
                                                       pk_field_name_2,
                                                       pk_field_value_2,
                                                       pk_field_name_3,
                                                       pk_field_value_3,
                                                       pk_field_name_4,
                                                       pk_field_value_4,
                                                       pk_field_name_5,
                                                       pk_field_value_5,
                                                       pk_field_name_6,
                                                       pk_field_value_6,
                                                       pk_field_name_7,
                                                       pk_field_value_7,
                                                       user_create,
                                                       date_create,
                                                       user_modif,
                                                       date_modif)
                                                VALUES (
                                                           v_bank_code,
                                                              'PAN'
                                                           || v_product_code,
                                                           '1',
                                                           v_product_code,
                                                           v_unique_index,
                                                           'P7_ctrl_decision_matrix',
                                                           'bank_code',
                                                           tab_rec.bank_code,
                                                           'control_verification_index',
                                                           tab_rec.control_verification_index,
                                                           'on_off_flag',
                                                           tab_rec.on_off_flag,
                                                           'ctrl_id',
                                                           tab_rec.ctrl_id,
                                                           'ctrl_results',
                                                           tab_rec.ctrl_results,
                                                           NULL,
                                                           NULL,
                                                           NULL,
                                                           NULL,
                                                           'mgr',
                                                           NULL,
                                                           NULL,
                                                           NULL);
                                        END IF;

                                        v_unique_index := v_unique_index + 1;
                                    END IF;

                                    SELECT *
                                      INTO gen_next_line
                                      FROM mgr_cat_genpan
                                     WHERE line = in_rec.line + 1;

                                    IF in_rec.text LIKE '%<Characteristic %'
                                    THEN
                                        INSERT INTO mgr_cat_output
                                            VALUES (
                                                       mgr_cat_line.NEXTVAL,
                                                       in_rec.text);

                                        v_characteristic_id :=
                                            SUBSTR (
                                                in_rec.text,
                                                  INSTR (in_rec.text, 'id="')
                                                + 4,
                                                  INSTR (
                                                      SUBSTR (
                                                          in_rec.text,
                                                            INSTR (
                                                                in_rec.text,
                                                                'id="')
                                                          + 4),
                                                      '"')
                                                - 1);

                                        BEGIN
                                            SELECT DISTINCT field_name
                                              INTO v_field_name
                                              FROM catalogue_mapping
                                             WHERE     product_type = 'P'
                                                   AND tag_id =
                                                           v_characteristic_id;
                                        EXCEPTION
                                            WHEN TOO_MANY_ROWS
                                            THEN
                                                INSERT INTO mgr_trace
                                                    VALUES (
                                                                  'ERROR too_many_rows TAG_ID='
                                                               || v_characteristic_id);

                                                COMMIT;
                                                EXIT;
                                        END;


                                        IF v_field_name = 'on_off_flag'
                                        THEN
                                            v_value := tab_rec.on_off_flag;
                                        ELSIF v_field_name = 'action_code'
                                        THEN
                                            v_value := tab_rec.action_code;

                                        ELSIF v_field_name = 'int_ext_flag'
                                        THEN
                                            v_value := tab_rec.int_ext_flag;

                                        ELSIF v_field_name = 'ctrl_results'
                                        THEN
                                            v_value := tab_rec.ctrl_results;
                                        ELSIF v_field_name = 'user_message'
                                        THEN
                                            v_value := tab_rec.user_message;
                                        END IF;
                                    ELSIF     in_rec.text LIKE
                                                  '%<CurrentStructure%'
                                          AND gen_next_line.text NOT LIKE
                                                  '%<Value%'
                                    THEN
                                        INSERT INTO mgr_cat_output
                                            VALUES (
                                                       mgr_cat_line.NEXTVAL,
                                                       REPLACE (
                                                           in_rec.text,
                                                           'CurrentStructure',
                                                           'ParentStructure'));

                                        INSERT INTO mgr_cat_output
                                            VALUES (
                                                       mgr_cat_line.NEXTVAL,
                                                       '                <CurrentStructure editable="true" mandatory="false" visible="true">');

                                        INSERT INTO mgr_cat_output
                                            VALUES (
                                                       mgr_cat_line.NEXTVAL,
                                                          '                                <Value>'
                                                       || REPLACE (v_value,
                                                                   '&',
                                                                   '&amp;')
                                                       || '</Value>');

                                        INSERT INTO mgr_cat_output
                                            VALUES (
                                                       mgr_cat_line.NEXTVAL,
                                                       '                </CurrentStructure>');
                                    ELSIF     in_rec.text LIKE
                                                  '%<CurrentStructure%'
                                          AND gen_next_line.text LIKE
                                                  '%<Value%'
                                    THEN
                                        INSERT INTO mgr_cat_output
                                            VALUES (
                                                       mgr_cat_line.NEXTVAL,
                                                       REPLACE (
                                                           in_rec.text,
                                                           'CurrentStructure',
                                                           'ParentStructure'));

                                        INSERT INTO mgr_cat_output
                                            VALUES (
                                                       mgr_cat_line.NEXTVAL,
                                                       gen_next_line.text);

                                        INSERT INTO mgr_cat_output
                                            VALUES (
                                                       mgr_cat_line.NEXTVAL,
                                                       '                </ParentStructure>');

                                        INSERT INTO mgr_cat_output
                                            VALUES (
                                                       mgr_cat_line.NEXTVAL,
                                                       '                <CurrentStructure editable="true" mandatory="false" visible="true">');

                                        INSERT INTO mgr_cat_output
                                            VALUES (
                                                       mgr_cat_line.NEXTVAL,
                                                          '                                <Value>'
                                                       || REPLACE (v_value,
                                                                   '&',
                                                                   '&amp;')
                                                       || '</Value>');

                                        INSERT INTO mgr_cat_output
                                            VALUES (
                                                       mgr_cat_line.NEXTVAL,
                                                       '                </CurrentStructure>');
                                    ELSIF    in_rec.text LIKE '%<Value%'
                                          OR in_rec.text LIKE
                                                 '%</CurrentStructure%'
                                    THEN
                                        CONTINUE;
                                    ELSE
                                        INSERT INTO mgr_cat_output
                                            VALUES (
                                                       mgr_cat_line.NEXTVAL,
                                                       in_rec.text);
                                    END IF;
                                END LOOP;
                            END LOOP;
                        END IF;                                         -----3
                    ELSIF v_parent_group = 'GRP_CTRL_DECISION_OFF'
                    THEN
                        SELECT COUNT (*)
                          INTO v_count_check
                          FROM p7_ctrl_decision_matrix
                         WHERE     on_off_flag = 'OFF'
                               AND control_verification_index IN (SELECT control_verification_index
                                                                    FROM card_product
                                                                   WHERE     bank_code =
                                                                                 v_bank_code
                                                                         AND product_code =
                                                                                 v_product_code)
                               AND bank_code = v_bank_code;

                        IF v_count_check = '0'
                        THEN                                              ---3
                            FOR in_rec
                                IN (SELECT *
                                      FROM mgr_cat_genpan
                                     WHERE line BETWEEN v_start_in_block
                                                    AND v_end_in_block
                                    ORDER BY line)
                            LOOP
                                SELECT *
                                  INTO gen_next_line
                                  FROM mgr_cat_genpan
                                 WHERE line = in_rec.line + 1;

                                IF in_rec.text LIKE '%<Characteristic %'
                                THEN
                                    INSERT INTO mgr_cat_output
                                        VALUES (
                                                   mgr_cat_line.NEXTVAL,
                                                   in_rec.text);

                                    v_value := '';
                                ELSIF     in_rec.text LIKE
                                              '%<CurrentStructure%'
                                      AND gen_next_line.text NOT LIKE
                                              '%<Value%'
                                THEN
                                    INSERT INTO mgr_cat_output
                                        VALUES (
                                                   mgr_cat_line.NEXTVAL,
                                                   REPLACE (
                                                       in_rec.text,
                                                       'CurrentStructure',
                                                       'ParentStructure'));

                                    INSERT INTO mgr_cat_output
                                        VALUES (
                                                   mgr_cat_line.NEXTVAL,
                                                   '                <CurrentStructure editable="true" mandatory="false" visible="true">');

                                    INSERT INTO mgr_cat_output
                                        VALUES (
                                                   mgr_cat_line.NEXTVAL,
                                                      '                                <Value>'
                                                   || REPLACE (v_value,
                                                               '&',
                                                               '&amp;')
                                                   || '</Value>');

                                    INSERT INTO mgr_cat_output
                                        VALUES (
                                                   mgr_cat_line.NEXTVAL,
                                                   '                </CurrentStructure>');
                                ELSIF     in_rec.text LIKE
                                              '%<CurrentStructure%'
                                      AND gen_next_line.text LIKE '%<Value%'
                                THEN
                                    INSERT INTO mgr_cat_output
                                        VALUES (
                                                   mgr_cat_line.NEXTVAL,
                                                   REPLACE (
                                                       in_rec.text,
                                                       'CurrentStructure',
                                                       'ParentStructure'));

                                    INSERT INTO mgr_cat_output
                                        VALUES (
                                                   mgr_cat_line.NEXTVAL,
                                                   gen_next_line.text);

                                    INSERT INTO mgr_cat_output
                                        VALUES (
                                                   mgr_cat_line.NEXTVAL,
                                                   '                </ParentStructure>');

                                    INSERT INTO mgr_cat_output
                                        VALUES (
                                                   mgr_cat_line.NEXTVAL,
                                                   '                <CurrentStructure editable="true" mandatory="false" visible="true">');

                                    INSERT INTO mgr_cat_output
                                        VALUES (
