                                                                       in_rec.text,
                                                                       'uniqueIndex="')
                                                                 + 13),
                                                             '"')
                                                       - 1),
                                                   'uniqueIndex="'
                                                || v_unique_index);

                                        SELECT COUNT (*)
                                          INTO v_check_existing_injected
                                          FROM mgr_catalogue_injected_param
                                         WHERE     bank_code = v_bank_code
                                               AND product_code =
                                                          'PAN'
                                                       || v_product_code
