                                                       in_rec.text);
                                    END IF;
                                END LOOP;
                            END LOOP;
                        END IF;                                         -----3
                    END IF;                                               ---4
                --end if; --5
                END IF;                                                  ----2

                CONTINUE;
            END IF;




                IF V_CURRENT_GRP = 'GRP_SCA_MATRIX'
                   AND REC.LINE BETWEEN V_START_BLOCK AND V_END_BLOCK
                THEN
                    IF REC.LINE = V_START_BLOCK + 1
                    THEN
