                          FROM   SCA_RP_DECISION_MATRIX
                         WHERE   CONTROL_VERIFICATION_INDEX =
                                     (SELECT   CONTROL_VERIFICATION_INDEX
                                        FROM   CARD_PRODUCT
                                       WHERE   PRODUCT_CODE = V_PRODUCT_CODE
                                               AND BANK_CODE = V_BANK_CODE)
                                 AND BANK_CODE = V_BANK_CODE;

                        IF V_COUNT_CHECK = '0'
                        THEN
                            FOR IN_REC
                            IN (  SELECT   *
                                    FROM   MGR_CAT_GENPAN
                                   WHERE   LINE BETWEEN V_START_IN_BLOCK AND V_END_IN_BLOCK
                                ORDER BY   LINE)
                            LOOP
                                SELECT   *
                                  INTO   GEN_NEXT_LINE
                                  FROM   MGR_CAT_GENPAN
                                 WHERE   LINE = IN_REC.LINE + 1;

                                IF IN_REC.TEXT LIKE '%<Characteristic %'
                                THEN
                                    INSERT INTO MGR_CAT_OUTPUT
