                                    INSERT INTO MGR_CAT_OUTPUT
                                      VALUES   (MGR_CAT_LINE.NEXTVAL,
                                                '                                <Value>'
                                                || REPLACE (V_VALUE, '&', '&amp;')
                                                || '</Value>');

                                    INSERT INTO MGR_CAT_OUTPUT
                                      VALUES   (MGR_CAT_LINE.NEXTVAL,
                                                '                </CurrentStructure>');
                                ELSIF IN_REC.TEXT LIKE '%<CurrentStructure%'
                                      AND GEN_NEXT_LINE.TEXT LIKE '%<Value%'
                                THEN
                                    INSERT INTO MGR_CAT_OUTPUT
                                      VALUES   (MGR_CAT_LINE.NEXTVAL,
                                                REPLACE (IN_REC.TEXT,
                                                         'CurrentStructure',
                                                         'ParentStructure'));

