                                                            'PAN' || V_PRODUCT_CODE
                                                     AND ENTITY_NAME =
                                                            'Sca_rp_decision_matrix'
                                                     AND PK_FIELD_VALUE_1 =
                                                            TAB_REC.SEQUENCE_ID;

                                            IF V_CHECK_EXISTING_INJECTED = 0
                                            THEN
                                                INSERT INTO MGR_CATALOGUE_INJECTED_PARAM (BANK_CODE,
                                                                                          PRODUCT_CODE,
                                                                                          PROD_VERSION,
                                                                                          PROD_SEQUENCE,
                                                                                          GROUP_DATA_INDEX,
                                                                                          ENTITY_NAME,
                                                                                          PK_FIELD_NAME_1,
                                                                                          PK_FIELD_VALUE_1,
                                                                                          PK_FIELD_NAME_2,
                                                                                          PK_FIELD_VALUE_2,
                                                                                          PK_FIELD_NAME_3,
                                                                                          PK_FIELD_VALUE_3,
                                                                                          PK_FIELD_NAME_4,
                                                                                          PK_FIELD_VALUE_4,
                                                                                          PK_FIELD_NAME_5,
                                                                                          PK_FIELD_VALUE_5,
                                                                                          PK_FIELD_NAME_6,
                                                                                          PK_FIELD_VALUE_6,
                                                                                          PK_FIELD_NAME_7,
                                                                                          PK_FIELD_VALUE_7,
                                                                                          USER_CREATE,
                                                                                          DATE_CREATE,
                                                                                          USER_MODIF,
                                                                                          DATE_MODIF)
                                                  VALUES   (V_BANK_CODE,
