                                                            '1',
                                                            V_PRODUCT_CODE,
                                                            V_UNIQUE_INDEX,
                                                            'Sca_rp_decision_matrix',
                                                            'sequence_id',
                                                            TAB_REC.SEQUENCE_ID,
                                                            NULL,
                                                            NULL,
                                                            NULL,
                                                            NULL,
                                                            NULL,
                                                            NULL,
                                                            NULL,
                                                            NULL,
                                                            NULL,
                                                            NULL,
                                                            NULL,
                                                            NULL,
                                                            'mgr',
                                                            NULL,
                                                            NULL,
                                                            NULL);
                                            END IF;

                                            V_UNIQUE_INDEX   := V_UNIQUE_INDEX + 1;
                                        END IF;

                                        SELECT   *
                                          INTO   GEN_NEXT_LINE
                                          FROM   MGR_CAT_GENPAN
                                         WHERE   LINE = IN_REC.LINE + 1;

                                        IF IN_REC.TEXT LIKE '%<Characteristic %'
                                        THEN
                                            INSERT INTO MGR_CAT_OUTPUT
