                                        ELSE
                                            INSERT INTO MGR_CAT_OUTPUT
                                              VALUES   (MGR_CAT_LINE.NEXTVAL, IN_REC.TEXT)
;
                                        END IF;
                                    END LOOP;

                                    V_FIRST_FLAG   := 'N';
                                END IF;


                                FOR IN_REC
                                IN (  SELECT   *
                                        FROM   MGR_CAT_GENPAN
                                       WHERE   LINE BETWEEN V_START_IN_BLOCK
                                                        AND  V_END_IN_BLOCK
                                    ORDER BY   LINE)
                                LOOP
                                    IF IN_REC.TEXT LIKE '%uniqueIndex%'
                                    THEN
                                        IN_REC.TEXT      := REPLACE (
                                                                IN_REC.TEXT,
                                                                'uniqueIndex="'
                                                                || SUBSTR (
                                                                       IN_REC.TEXT,
                                                                       INSTR (
                                                                           IN_REC.TEXT,
                                                                           'uniqueIndex="')
                                                                       + 13,
                                                                       INSTR (
                                                                           SUBSTR (
                                                                               IN_REC.TEXT,
                                                                               INSTR (
                                                                                   IN_REC.TEXT,
                                                                                   'uniqueIndex="')
                                                                               + 13),
                                                                           '"')
                                                                       - 1),
                                                                'uniqueIndex="'
                                                                || V_UNIQUE_INDEX);

                                        SELECT   COUNT ( * )
                                          INTO   V_CHECK_EXISTING_INJECTED
                                          FROM   MGR_CATALOGUE_INJECTED_PARAM
                                         WHERE   BANK_CODE = V_BANK_CODE
