                                                                                      PK_FIELD_VALUE_3,
                                                                                      PK_FIELD_NAME_4,
                                                                                      PK_FIELD_VALUE_4,
                                                                                      PK_FIELD_NAME_5,
                                                                                      PK_FIELD_VALUE_5,
                                                                                      PK_FIELD_NAME_6,
                                                                                      PK_FIELD_VALUE_6,
                                                                                      PK_FIELD_NAME_7,
                                                                                      PK_FIELD_VALUE_7,
                                                                                      USER_CREATE,
                                                                                      DATE_CREATE,
                                                                                      USER_MODIF,
                                                                                      DATE_MODIF)
                                              VALUES   (V_BANK_CODE,
                                                        'PAN' || V_PRODUCT_CODE,
                                                        '1',
                                                        V_PRODUCT_CODE,
                                                        V_UNIQUE_INDEX,
                                                        'Sca_rp_decision_matrix',
                                                        'sequence_id',
                                                        TAB_REC.SEQUENCE_ID,
                                                        NULL,
                                                        NULL,
                                                        NULL,
                                                        NULL,
                                                        NULL,
                                                        NULL,
                                                        NULL,
                                                        NULL,
                                                        NULL,
                                                        NULL,
                                                        NULL,
                                                        NULL,
                                                        'mgr',
                                                        NULL,
                                                        NULL,
                                                        NULL);
                                        END IF;

                                        V_UNIQUE_INDEX   := V_UNIQUE_INDEX + 1;
                                    END IF;

                                    SELECT   *
                                      INTO   GEN_NEXT_LINE
                                      FROM   MGR_CAT_GENPAN
                                     WHERE   LINE = IN_REC.LINE + 1;

                                    IF IN_REC.TEXT LIKE '%<Characteristic %'
                                    THEN
                                        INSERT INTO MGR_CAT_OUTPUT
                                          VALUES   (MGR_CAT_LINE.NEXTVAL, IN_REC.TEXT);

                                        V_CHARACTERISTIC_ID   := SUBSTR (
                                                                     IN_REC.TEXT,
                                                                     INSTR (IN_REC.TEXT,
                                                                            'id="')
                                                                     + 4,
                                                                     INSTR (
                                                                         SUBSTR (
                                                                             IN_REC.TEXT,
                                                                             INSTR (
                                                                                 IN_REC.TEXT,
                                                                                 'id="')
                                                                             + 4),
                                                                         '"')
                                                                     - 1);

                                        BEGIN
                                            SELECT   DISTINCT FIELD_NAME
                                              INTO   V_FIELD_NAME
                                              FROM   CATALOGUE_MAPPING
                                             WHERE   PRODUCT_TYPE = 'P'
                                                     AND TAG_ID = V_CHARACTERISTIC_ID;
                                        EXCEPTION
                                            WHEN TOO_MANY_ROWS
                                            THEN
                                                INSERT INTO MGR_TRACE
                                                  VALUES   (   'ERROR '
                                                            || $$PLSQL_LINE
                                                            || '  too_many_rows TAG_ID='
                                                            || V_CHARACTERISTIC_ID);

                                                COMMIT;
                                                EXIT;
                                        END;



                                        IF V_FIELD_NAME = 'action_code_offline'
                                        THEN
                                            V_VALUE   := TAB_REC.ACTION_CODE_OFFLINE;
                                        ELSIF V_FIELD_NAME = 'action_code_online'
                                        THEN
                                            V_VALUE   := TAB_REC.ACTION_CODE_ONLINE;
                                        ELSIF V_FIELD_NAME = 'exemp_any_flag'
                                        THEN
                                            V_VALUE   := TAB_REC.EXEMP_ANY_FLAG;
                                        ELSIF V_FIELD_NAME = 'exemp_lvp_flag'
                                        THEN
                                            V_VALUE   := TAB_REC.EXEMP_LVP_FLAG;
                                        ELSIF V_FIELD_NAME = 'exemp_mwl_flag'
                                        THEN
                                            V_VALUE   := TAB_REC.EXEMP_MWL_FLAG;
                                        ELSIF V_FIELD_NAME = 'exemp_scp_flag'
                                        THEN
                                            V_VALUE   := TAB_REC.EXEMP_SCP_FLAG;
                                        ELSIF V_FIELD_NAME = 'exemp_tra_flag'
                                        THEN
                                            V_VALUE   := TAB_REC.EXEMP_TRA_FLAG;
                                        ELSIF V_FIELD_NAME = 'flag_3ds'
                                        THEN
                                            V_VALUE   := TAB_REC.FLAG_3DS;
                                        ELSIF V_FIELD_NAME = 'user_message'
                                        THEN
                                            V_VALUE   := TAB_REC.USER_MESSAGE;
                                        ELSIF V_FIELD_NAME = 'version_3ds'
                                        THEN
                                            V_VALUE   := TAB_REC.VERSION_3DS;
                                        END IF;
                                    ELSIF IN_REC.TEXT LIKE '%<CurrentStructure%'
                                          AND GEN_NEXT_LINE.TEXT NOT LIKE '%<Value%'
                                    THEN
                                        INSERT INTO MGR_CAT_OUTPUT
                                          VALUES   (MGR_CAT_LINE.NEXTVAL,
                                                    REPLACE (IN_REC.TEXT,
                                                             'CurrentStructure',
                                                             'ParentStructure'));

                                        INSERT INTO MGR_CAT_OUTPUT
                                          VALUES   (MGR_CAT_LINE.NEXTVAL,
                                                    '                <CurrentStructure editable="true" mandatory="false" visible="true">');

                                        INSERT INTO MGR_CAT_OUTPUT
                                          VALUES   (MGR_CAT_LINE.NEXTVAL,
                                                    '                                <Value>'
                                                    || REPLACE (V_VALUE, '&', '&amp;')
                                                    || '</Value>');

                                        INSERT INTO MGR_CAT_OUTPUT
                                          VALUES   (MGR_CAT_LINE.NEXTVAL,
                                                    '                </CurrentStructure>')
;
                                    ELSIF IN_REC.TEXT LIKE '%<CurrentStructure%'
                                          AND GEN_NEXT_LINE.TEXT LIKE '%<Value%'
                                    THEN
                                        INSERT INTO MGR_CAT_OUTPUT
                                          VALUES   (MGR_CAT_LINE.NEXTVAL,
                                                    REPLACE (IN_REC.TEXT,
                                                             'CurrentStructure',
                                                             'ParentStructure'));

                                        INSERT INTO MGR_CAT_OUTPUT
                                          VALUES   (MGR_CAT_LINE.NEXTVAL,
                                                    GEN_NEXT_LINE.TEXT);

                                        INSERT INTO MGR_CAT_OUTPUT
                                          VALUES   (MGR_CAT_LINE.NEXTVAL,
                                                    '                </ParentStructure>');

                                        INSERT INTO MGR_CAT_OUTPUT
                                          VALUES   (MGR_CAT_LINE.NEXTVAL,
                                                    '                <CurrentStructure editable="true" mandatory="false" visible="true">');

                                        INSERT INTO MGR_CAT_OUTPUT
                                          VALUES   (MGR_CAT_LINE.NEXTVAL,
                                                    '                                <Value>'
                                                    || REPLACE (V_VALUE, '&', '&amp;')
                                                    || '</Value>');

                                        INSERT INTO MGR_CAT_OUTPUT
                                          VALUES   (MGR_CAT_LINE.NEXTVAL,
                                                    '                </CurrentStructure>')
;
                                    ELSIF IN_REC.TEXT LIKE '%<Value%'
                                          OR IN_REC.TEXT LIKE '%</CurrentStructure%'
                                    THEN
                                        CONTINUE;
                                    ELSE
                                        INSERT INTO MGR_CAT_OUTPUT
                                          VALUES   (MGR_CAT_LINE.NEXTVAL, IN_REC.TEXT);
                                    END IF;
                                END LOOP;
                            END LOOP;
                        END IF;
                    END IF;

                    CONTINUE;
                END IF;



                IF V_CURRENT_GRP = 'GRP_AUTHO_FEES_LIST'
                   AND REC.LINE BETWEEN V_START_BLOCK AND V_END_BLOCK
                THEN
                    IF REC.LINE = V_START_BLOCK + 1
                    THEN
                        V_FIRST_FLAG   := 'Y';

                        SELECT   COUNT ( * )
                          INTO   V_COUNT_CHECK
                          FROM   AUTHO_FEES_PARAM
                         WHERE   TRIM (FEE_INDEX) = V_PRODUCT_CODE
                                 AND BANK_CODE = V_BANK_CODE;

                        IF V_COUNT_CHECK = '0'
                        THEN
                            FOR IN_REC
                            IN (  SELECT   *
                                    FROM   MGR_CAT_GENPAN
                                   WHERE   LINE BETWEEN V_START_IN_BLOCK AND V_END_IN_BLOCK
                                ORDER BY   LINE)
                            LOOP
                                SELECT   *
                                  INTO   GEN_NEXT_LINE
                                  FROM   MGR_CAT_GENPAN
                                 WHERE   LINE = IN_REC.LINE + 1;

                                IF IN_REC.TEXT LIKE '%<Characteristic %'
                                THEN
                                    INSERT INTO MGR_CAT_OUTPUT
                                      VALUES   (MGR_CAT_LINE.NEXTVAL, IN_REC.TEXT);

                                    V_VALUE   := '';
                                ELSIF IN_REC.TEXT LIKE '%<CurrentStructure%'
                                      AND GEN_NEXT_LINE.TEXT NOT LIKE '%<Value%'
                                THEN
                                    INSERT INTO MGR_CAT_OUTPUT
                                      VALUES   (MGR_CAT_LINE.NEXTVAL,
                                                REPLACE (IN_REC.TEXT,
                                                         'CurrentStructure',
                                                         'ParentStructure'));

                                    INSERT INTO MGR_CAT_OUTPUT
                                      VALUES   (MGR_CAT_LINE.NEXTVAL,
                                                '                <CurrentStructure editable="true" mandatory="false" visible="true">');

                                    INSERT INTO MGR_CAT_OUTPUT
                                      VALUES   (MGR_CAT_LINE.NEXTVAL,
                                                '                                <Value>'
                                                || REPLACE (V_VALUE, '&', '&amp;')
                                                || '</Value>');

                                    INSERT INTO MGR_CAT_OUTPUT
                                      VALUES   (MGR_CAT_LINE.NEXTVAL,
                                                '                </CurrentStructure>');
                                ELSIF IN_REC.TEXT LIKE '%<CurrentStructure%'
                                      AND GEN_NEXT_LINE.TEXT LIKE '%<Value%'
                                THEN
                                    INSERT INTO MGR_CAT_OUTPUT
                                      VALUES   (MGR_CAT_LINE.NEXTVAL,
                                                REPLACE (IN_REC.TEXT,
                                                         'CurrentStructure',
                                                         'ParentStructure'));

                                    INSERT INTO MGR_CAT_OUTPUT
                                      VALUES   (MGR_CAT_LINE.NEXTVAL, GEN_NEXT_LINE.TEXT);

                                    INSERT INTO MGR_CAT_OUTPUT
                                      VALUES   (MGR_CAT_LINE.NEXTVAL,
                                                '                </ParentStructure>');

                                    INSERT INTO MGR_CAT_OUTPUT
                                      VALUES   (MGR_CAT_LINE.NEXTVAL,
                                                '                <CurrentStructure editable="true" mandatory="false" visible="true">');

                                    INSERT INTO MGR_CAT_OUTPUT
                                      VALUES   (MGR_CAT_LINE.NEXTVAL,
                                                '                                <Value>'
                                                || REPLACE (V_VALUE, '&', '&amp;')
                                                || '</Value>');

                                    INSERT INTO MGR_CAT_OUTPUT
                                      VALUES   (MGR_CAT_LINE.NEXTVAL,
                                                '                </CurrentStructure>');
                                ELSIF IN_REC.TEXT LIKE '%<Value%'
                                      OR IN_REC.TEXT LIKE '%</CurrentStructure%'
                                THEN
                                    CONTINUE;
                                ELSE
                                    INSERT INTO MGR_CAT_OUTPUT
                                      VALUES   (MGR_CAT_LINE.NEXTVAL, IN_REC.TEXT);
                                END IF;
                            END LOOP;
                        ELSE
                            FOR TAB_REC
                            IN (SELECT   *
                                  FROM   AUTHO_FEES_PARAM
                                 WHERE   TRIM (FEE_INDEX) = V_PRODUCT_CODE
                                         AND BANK_CODE = V_BANK_CODE)
                            LOOP
                                IF V_FIRST_FLAG = 'Y'
                                THEN
                                    FOR IN_REC
                                    IN (  SELECT   *
                                            FROM   MGR_CAT_GENPAN
                                           WHERE   LINE BETWEEN V_START_IN_BLOCK
                                                            AND  V_END_IN_BLOCK
                                        ORDER BY   LINE)
                                    LOOP
                                        IF IN_REC.TEXT LIKE '%uniqueIndex%'
                                        THEN
                                            IN_REC.TEXT      := REPLACE (
                                                                    IN_REC.TEXT,
                                                                    'uniqueIndex="'
                                                                    || SUBSTR (
                                                                           IN_REC.TEXT,
                                                                           INSTR (
                                                                               IN_REC.TEXT,
                                                                               'uniqueIndex="')
                                                                           + 13,
                                                                           INSTR (
                                                                               SUBSTR (
                                                                                   IN_REC.TEXT,
                                                                                   INSTR (
                                                                                       IN_REC.TEXT,
                                                                                       'uniqueIndex="')
                                                                                   + 13),
                                                                               '"')
                                                                           - 1),
                                                                    'uniqueIndex="'
                                                                    || V_UNIQUE_INDEX);

                                            SELECT   COUNT ( * )
                                              INTO   V_CHECK_EXISTING_INJECTED
                                              FROM   MGR_CATALOGUE_INJECTED_PARAM
                                             WHERE   BANK_CODE = V_BANK_CODE
                                                     AND PRODUCT_CODE =
                                                            'PAN' || V_PRODUCT_CODE
                                                     AND ENTITY_NAME = 'Autho_fees_param'
                                                     AND PK_FIELD_VALUE_1 =
                                                            TAB_REC.SEQ_NUMBER;

                                            IF V_CHECK_EXISTING_INJECTED = 0
                                            THEN
                                                INSERT INTO MGR_CATALOGUE_INJECTED_PARAM (BANK_CODE,
                                                                                          PRODUCT_CODE,
                                                                                          PROD_VERSION,
                                                                                          PROD_SEQUENCE,
                                                                                          GROUP_DATA_INDEX,
                                                                                          ENTITY_NAME,
                                                                                          PK_FIELD_NAME_1,
                                                                                          PK_FIELD_VALUE_1,
                                                                                          PK_FIELD_NAME_2,
                                                                                          PK_FIELD_VALUE_2,
                                                                                          PK_FIELD_NAME_3,
                                                                                          PK_FIELD_VALUE_3,
                                                                                          PK_FIELD_NAME_4,
                                                                                          PK_FIELD_VALUE_4,
                                                                                          PK_FIELD_NAME_5,
                                                                                          PK_FIELD_VALUE_5,
                                                                                          PK_FIELD_NAME_6,
                                                                                          PK_FIELD_VALUE_6,
                                                                                          PK_FIELD_NAME_7,
                                                                                          PK_FIELD_VALUE_7,
                                                                                          USER_CREATE,
                                                                                          DATE_CREATE,
                                                                                          USER_MODIF,
                                                                                          DATE_MODIF)
                                                  VALUES   (V_BANK_CODE,
                                                            'PAN' || V_PRODUCT_CODE,
                                                            '1',
                                                            V_PRODUCT_CODE,
                                                            V_UNIQUE_INDEX,
                                                            'Autho_fees_param',
                                                            'seq_number',
                                                            TAB_REC.SEQ_NUMBER,
                                                            NULL,
                                                            NULL,
                                                            NULL,
                                                            NULL,
                                                            NULL,
                                                            NULL,
                                                            NULL,
                                                            NULL,
                                                            NULL,
                                                            NULL,
                                                            NULL,
                                                            NULL,
                                                            'mgr',
                                                            NULL,
                                                            NULL,
                                                            NULL);
                                            END IF;

                                            V_UNIQUE_INDEX   := V_UNIQUE_INDEX + 1;
                                        END IF;

                                        SELECT   *
                                          INTO   GEN_NEXT_LINE
                                          FROM   MGR_CAT_GENPAN
                                         WHERE   LINE = IN_REC.LINE + 1;

                                        IF IN_REC.TEXT LIKE '%<Characteristic %'
                                        THEN
                                            INSERT INTO MGR_CAT_OUTPUT
                                              VALUES   (MGR_CAT_LINE.NEXTVAL, IN_REC.TEXT)
;
                                            V_VALUE   := '';
                                        ELSIF IN_REC.TEXT LIKE '%<CurrentStructure%'
                                              AND GEN_NEXT_LINE.TEXT NOT LIKE '%<Value%'
                                        THEN
                                            INSERT INTO MGR_CAT_OUTPUT
                                              VALUES   (MGR_CAT_LINE.NEXTVAL,
                                                        REPLACE (IN_REC.TEXT,
                                                                 'CurrentStructure',
                                                                 'ParentStructure'));

                                            INSERT INTO MGR_CAT_OUTPUT
                                              VALUES   (MGR_CAT_LINE.NEXTVAL,
                                                        '                <CurrentStructure editable="true" mandatory="false" visible="true">');

                                            INSERT INTO MGR_CAT_OUTPUT
                                              VALUES   (MGR_CAT_LINE.NEXTVAL,
                                                        '                                <Value>'
                                                        || REPLACE (V_VALUE,
                                                                    '&',
                                                                    '&amp;')
                                                        || '</Value>');

                                            INSERT INTO MGR_CAT_OUTPUT
                                              VALUES   (MGR_CAT_LINE.NEXTVAL,
                                                        '                </CurrentStructure>');
                                        ELSIF IN_REC.TEXT LIKE '%<CurrentStructure%'
                                              AND GEN_NEXT_LINE.TEXT LIKE '%<Value%'
                                        THEN
                                            INSERT INTO MGR_CAT_OUTPUT
                                              VALUES   (MGR_CAT_LINE.NEXTVAL,
                                                        REPLACE (IN_REC.TEXT,
                                                                 'CurrentStructure',
                                                                 'ParentStructure'));

                                            INSERT INTO MGR_CAT_OUTPUT
                                              VALUES   (MGR_CAT_LINE.NEXTVAL,
                                                        GEN_NEXT_LINE.TEXT);

                                            INSERT INTO MGR_CAT_OUTPUT
                                              VALUES   (MGR_CAT_LINE.NEXTVAL,
                                                        '                </ParentStructure>');

                                            INSERT INTO MGR_CAT_OUTPUT
                                              VALUES   (MGR_CAT_LINE.NEXTVAL,
                                                        '                <CurrentStructure editable="true" mandatory="false" visible="true">');

                                            INSERT INTO MGR_CAT_OUTPUT
                                              VALUES   (MGR_CAT_LINE.NEXTVAL,
                                                        '                                <Value>'
                                                        || REPLACE (V_VALUE,
                                                                    '&',
                                                                    '&amp;')
                                                        || '</Value>');

                                            INSERT INTO MGR_CAT_OUTPUT
                                              VALUES   (MGR_CAT_LINE.NEXTVAL,
                                                        '                </CurrentStructure>');
                                        ELSIF IN_REC.TEXT LIKE '%<Value%'
                                              OR IN_REC.TEXT LIKE '%</CurrentStructure%'
                                        THEN
                                            CONTINUE;
                                        ELSE
                                            INSERT INTO MGR_CAT_OUTPUT
                                              VALUES   (MGR_CAT_LINE.NEXTVAL, IN_REC.TEXT)
;
                                        END IF;
                                    END LOOP;

                                    V_FIRST_FLAG   := 'N';
                                END IF;


                                FOR IN_REC
                                IN (  SELECT   *
                                        FROM   MGR_CAT_GENPAN
                                       WHERE   LINE BETWEEN V_START_IN_BLOCK
                                                        AND  V_END_IN_BLOCK
                                    ORDER BY   LINE)
                                LOOP
                                    IF IN_REC.TEXT LIKE '%uniqueIndex%'
                                    THEN
                                        IN_REC.TEXT      := REPLACE (
                                                                IN_REC.TEXT,
                                                                'uniqueIndex="'
                                                                || SUBSTR (
                                                                       IN_REC.TEXT,
                                                                       INSTR (
                                                                           IN_REC.TEXT,
                                                                           'uniqueIndex="')
                                                                       + 13,
                                                                       INSTR (
                                                                           SUBSTR (
                                                                               IN_REC.TEXT,
                                                                               INSTR (
                                                                                   IN_REC.TEXT,
                                                                                   'uniqueIndex="')
                                                                               + 13),
                                                                           '"')
                                                                       - 1),
                                                                'uniqueIndex="'
                                                                || V_UNIQUE_INDEX);
                                        V_UNIQUE_INDEX   := V_UNIQUE_INDEX + 1;
                                    END IF;

                                    SELECT   *
                                      INTO   GEN_NEXT_LINE
                                      FROM   MGR_CAT_GENPAN
                                     WHERE   LINE = IN_REC.LINE + 1;

                                    IF IN_REC.TEXT LIKE '%<Characteristic %'
                                    THEN
                                        INSERT INTO MGR_CAT_OUTPUT
                                          VALUES   (MGR_CAT_LINE.NEXTVAL, IN_REC.TEXT);

                                        V_CHARACTERISTIC_ID   := SUBSTR (
                                                                     IN_REC.TEXT,
                                                                     INSTR (IN_REC.TEXT,
                                                                            'id="')
                                                                     + 4,
                                                                     INSTR (
                                                                         SUBSTR (
                                                                             IN_REC.TEXT,
                                                                             INSTR (
                                                                                 IN_REC.TEXT,
                                                                                 'id="')
                                                                             + 4),
                                                                         '"')
                                                                     - 1);

                                        BEGIN
                                            SELECT   DISTINCT FIELD_NAME
                                              INTO   V_FIELD_NAME
                                              FROM   CATALOGUE_MAPPING
                                             WHERE   PRODUCT_TYPE = 'P'
                                                     AND TAG_ID = V_CHARACTERISTIC_ID;
                                        EXCEPTION
                                            WHEN TOO_MANY_ROWS
                                            THEN
                                                INSERT INTO MGR_TRACE
                                                  VALUES   (   'ERROR '
                                                            || $$PLSQL_LINE
                                                            || '  too_many_rows TAG_ID='
                                                            || V_CHARACTERISTIC_ID);

                                                COMMIT;
                                                EXIT;
                                        END;


                                        IF V_FIELD_NAME = 'abrv_wording'
                                        THEN
                                            V_VALUE   := TAB_REC.ABRV_WORDING;
                                        ELSIF V_FIELD_NAME = 'acquirer_country'
                                        THEN
                                            V_VALUE   := TAB_REC.ACQUIRER_COUNTRY;
                                        ELSIF V_FIELD_NAME = 'acquiring_bank_code'
                                        THEN
                                            V_VALUE   := TAB_REC.ACQUIRING_BANK_CODE;
                                        ELSIF V_FIELD_NAME = 'acquiring_network_code'
                                        THEN
                                            V_VALUE   := TAB_REC.ACQUIRING_NETWORK_CODE;
                                        ELSIF V_FIELD_NAME = 'action_code_query'
                                        THEN
                                            V_VALUE   := TAB_REC.ACTION_CODE_QUERY;
                                        ELSIF V_FIELD_NAME = 'action_flag'
                                        THEN
                                            V_VALUE   := TAB_REC.ACTION_FLAG;
                                        ELSIF V_FIELD_NAME = 'app_fees_fix'
                                        THEN
                                            V_VALUE   := TAB_REC.APP_FEES_FIX;
                                        ELSIF V_FIELD_NAME = 'app_fees_grace'
                                        THEN
                                            V_VALUE   := TAB_REC.APP_FEES_GRACE;
                                        ELSIF V_FIELD_NAME = 'app_fees_max'
                                        THEN
                                            V_VALUE   := TAB_REC.APP_FEES_MAX;
                                        ELSIF V_FIELD_NAME = 'app_fees_min'
                                        THEN
                                            V_VALUE   := TAB_REC.APP_FEES_MIN;
                                        ELSIF V_FIELD_NAME = 'app_fees_rate'
                                        THEN
                                            V_VALUE   := TAB_REC.APP_FEES_RATE;
                                        ELSIF V_FIELD_NAME = 'cash_fees_fix'
                                        THEN
                                            V_VALUE   := TAB_REC.CASH_FEES_FIX;
                                        ELSIF V_FIELD_NAME = 'cash_fees_grace'
                                        THEN
                                            V_VALUE   := TAB_REC.CASH_FEES_GRACE;
                                        ELSIF V_FIELD_NAME = 'cash_fees_max'
                                        THEN
                                            V_VALUE   := TAB_REC.CASH_FEES_MAX;
                                        ELSIF V_FIELD_NAME = 'cash_fees_min'
                                        THEN
                                            V_VALUE   := TAB_REC.CASH_FEES_MIN;
                                        ELSIF V_FIELD_NAME = 'cash_fees_rate'
                                        THEN
                                            V_VALUE   := TAB_REC.CASH_FEES_RATE;
                                        ELSIF V_FIELD_NAME =
                                                  'cash_rounded_method_identifier'
                                        THEN
                                            V_VALUE   := TAB_REC.CASH_ROUNDED_METHOD_IDENTIFIER;
                                        ELSIF V_FIELD_NAME = 'cashback_indicator'
                                        THEN
