                                        ELSIF V_FIELD_NAME = 'cashback_transaction_code'
                                        THEN
                                            V_VALUE   := TAB_REC.CASHBACK_TRANSACTION_CODE
;
                                        ELSIF V_FIELD_NAME = 'currency_code'
                                        THEN
                                            V_VALUE   := TAB_REC.CURRENCY_CODE;
                                        ELSIF V_FIELD_NAME = 'customer_segment_index'
                                        THEN
                                            V_VALUE   := TAB_REC.CUSTOMER_SEGMENT_INDEX;
                                        ELSIF V_FIELD_NAME = 'fee_id'
                                        THEN
                                            V_VALUE   := TAB_REC.FEE_ID;
                                        ELSIF V_FIELD_NAME = 'fee_priority'
                                        THEN
                                            V_VALUE   := TAB_REC.FEE_PRIORITY;
                                        ELSIF V_FIELD_NAME = 'fee_type'
                                        THEN
                                            V_VALUE   := TAB_REC.FEE_TYPE;
                                        ELSIF V_FIELD_NAME = 'fees_amount_threshold'
                                        THEN
                                            V_VALUE   := TAB_REC.FEES_AMOUNT_THRESHOLD;
                                        ELSIF V_FIELD_NAME = 'fees_indicator'
                                        THEN
                                            V_VALUE   := TAB_REC.FEES_INDICATOR;
                                        ELSIF V_FIELD_NAME = 'inc_check_avail'
                                        THEN
                                            V_VALUE   := TAB_REC.INC_CHECK_AVAIL;
                                        ELSIF V_FIELD_NAME = 'mcc'
                                        THEN
                                            V_VALUE   := TAB_REC.MCC;
                                        ELSIF V_FIELD_NAME = 'mcc_group'
                                        THEN
                                            V_VALUE   := TAB_REC.MCC_GROUP;
                                        ELSIF V_FIELD_NAME = 'network_region'
                                        THEN
                                            V_VALUE   := TAB_REC.NETWORK_REGION;
                                        ELSIF V_FIELD_NAME = 'origin_code'
                                        THEN
                                            V_VALUE   := TAB_REC.ORIGIN_CODE;
                                        ELSIF V_FIELD_NAME = 'processing_code'
                                        THEN
                                            V_VALUE   := TAB_REC.PROCESSING_CODE;
                                        ELSIF V_FIELD_NAME = 'receipt_flag'
                                        THEN
                                            V_VALUE   := TAB_REC.RECEIPT_FLAG;
                                        ELSIF V_FIELD_NAME = 'rounded_method_identifier'
                                        THEN
                                            V_VALUE   := TAB_REC.ROUNDED_METHOD_IDENTIFIER
;
                                        ELSIF V_FIELD_NAME = 'rule_identifier'
                                        THEN
                                            V_VALUE   := TAB_REC.RULE_IDENTIFIER;
                                        ELSIF V_FIELD_NAME = 'tiered_fees_amount'
                                        THEN
                                            V_VALUE   := TAB_REC.TIERED_FEES_AMOUNT;
                                        ELSIF V_FIELD_NAME = 'tiered_fees_rate'
                                        THEN
                                            V_VALUE   := TAB_REC.TIERED_FEES_RATE;
                                        ELSIF V_FIELD_NAME = 'transaction_code'
                                        THEN
                                            V_VALUE   := TAB_REC.TRANSACTION_CODE;
                                        ELSIF V_FIELD_NAME = 'transaction_currency'
                                        THEN
                                            V_VALUE   := TAB_REC.TRANSACTION_CURRENCY;
                                        ELSIF V_FIELD_NAME = 'vip_level'
                                        THEN
                                            V_VALUE   := TAB_REC.VIP_LEVEL;
                                        ELSIF V_FIELD_NAME = 'wording'
                                        THEN
                                            V_VALUE   := TAB_REC.WORDING;
                                        END IF;
                                    ELSIF IN_REC.TEXT LIKE '%<CurrentStructure%'
                                          AND GEN_NEXT_LINE.TEXT NOT LIKE '%<Value%'
                                    THEN
                                        INSERT INTO MGR_CAT_OUTPUT
                                          VALUES   (MGR_CAT_LINE.NEXTVAL,
                                                    REPLACE (IN_REC.TEXT,
                                                             'CurrentStructure',
                                                             'ParentStructure'));

                                        INSERT INTO MGR_CAT_OUTPUT
                                          VALUES   (MGR_CAT_LINE.NEXTVAL,
                                                    '                <CurrentStructure editable="true" mandatory="false" visible="true">');

                                        INSERT INTO MGR_CAT_OUTPUT
                                          VALUES   (MGR_CAT_LINE.NEXTVAL,
                                                    '                                <Value>'
                                                    || REPLACE (V_VALUE, '&', '&amp;')
                                                    || '</Value>');

                                        INSERT INTO MGR_CAT_OUTPUT
                                          VALUES   (MGR_CAT_LINE.NEXTVAL,
                                                    '                </CurrentStructure>')
;
                                    ELSIF IN_REC.TEXT LIKE '%<CurrentStructure%'
                                          AND GEN_NEXT_LINE.TEXT LIKE '%<Value%'
                                    THEN
                                        INSERT INTO MGR_CAT_OUTPUT
                                          VALUES   (MGR_CAT_LINE.NEXTVAL,
                                                    REPLACE (IN_REC.TEXT,
                                                             'CurrentStructure',
                                                             'ParentStructure'));

                                        INSERT INTO MGR_CAT_OUTPUT
                                          VALUES   (MGR_CAT_LINE.NEXTVAL,
                                                    GEN_NEXT_LINE.TEXT);

                                        INSERT INTO MGR_CAT_OUTPUT
                                          VALUES   (MGR_CAT_LINE.NEXTVAL,
                                                    '                </ParentStructure>');

                                        INSERT INTO MGR_CAT_OUTPUT
                                          VALUES   (MGR_CAT_LINE.NEXTVAL,
                                                    '                <CurrentStructure editable="true" mandatory="false" visible="true">');

                                        INSERT INTO MGR_CAT_OUTPUT
                                          VALUES   (MGR_CAT_LINE.NEXTVAL,
                                                    '                                <Value>'
                                                    || REPLACE (V_VALUE, '&', '&amp;')
                                                    || '</Value>');

                                        INSERT INTO MGR_CAT_OUTPUT
                                          VALUES   (MGR_CAT_LINE.NEXTVAL,
                                                    '                </CurrentStructure>')
;
                                    ELSIF IN_REC.TEXT LIKE '%<Value%'
                                          OR IN_REC.TEXT LIKE '%</CurrentStructure%'
                                    THEN
                                        CONTINUE;
                                    ELSE
                                        INSERT INTO MGR_CAT_OUTPUT
                                          VALUES   (MGR_CAT_LINE.NEXTVAL, IN_REC.TEXT);
                                    END IF;
                                END LOOP;
                            END LOOP;
                        END IF;
                    END IF;

                    CONTINUE;
                END IF;



                IF V_CURRENT_GRP = 'GRP_ISS_POSTING_RULES'
                   AND REC.LINE BETWEEN V_START_BLOCK AND V_END_BLOCK
                THEN
                    IF REC.LINE = V_START_BLOCK + 1
                    THEN
                        V_FIRST_FLAG   := 'Y';

                        SELECT   COUNT ( * )
                          INTO   V_COUNT_CHECK
                          FROM   ISS_POSTING_RULES
                         WHERE   CARD_PRODUCT_CODE = V_PRODUCT_CODE
                                 AND BANK_CODE = V_BANK_CODE;

                        IF 1 = 2
                        THEN
                            FOR IN_REC
                            IN (  SELECT   *
                                    FROM   MGR_CAT_GENPAN
                                   WHERE   LINE BETWEEN V_START_IN_BLOCK AND V_END_IN_BLOCK
                                ORDER BY   LINE)
                            LOOP
                                SELECT   *
                                  INTO   GEN_NEXT_LINE
                                  FROM   MGR_CAT_GENPAN
                                 WHERE   LINE = IN_REC.LINE + 1;

                                IF IN_REC.TEXT LIKE '%<Characteristic %'
                                THEN
                                    INSERT INTO MGR_CAT_OUTPUT
                                      VALUES   (MGR_CAT_LINE.NEXTVAL, IN_REC.TEXT);

                                    V_VALUE   := '';
                                ELSIF IN_REC.TEXT LIKE '%<CurrentStructure%'
                                      AND GEN_NEXT_LINE.TEXT NOT LIKE '%<Value%'
                                THEN
                                    INSERT INTO MGR_CAT_OUTPUT
                                      VALUES   (MGR_CAT_LINE.NEXTVAL,
                                                REPLACE (IN_REC.TEXT,
                                                         'CurrentStructure',
                                                         'ParentStructure'));

                                    INSERT INTO MGR_CAT_OUTPUT
                                      VALUES   (MGR_CAT_LINE.NEXTVAL,
                                                '                <CurrentStructure editable="true" mandatory="false" visible="true">');

                                    INSERT INTO MGR_CAT_OUTPUT
                                      VALUES   (MGR_CAT_LINE.NEXTVAL,
                                                '                                <Value>'
                                                || REPLACE (V_VALUE, '&', '&amp;')
                                                || '</Value>');

                                    INSERT INTO MGR_CAT_OUTPUT
                                      VALUES   (MGR_CAT_LINE.NEXTVAL,
                                                '                </CurrentStructure>');
                                ELSIF IN_REC.TEXT LIKE '%<CurrentStructure%'
                                      AND GEN_NEXT_LINE.TEXT LIKE '%<Value%'
                                THEN
                                    INSERT INTO MGR_CAT_OUTPUT
                                      VALUES   (MGR_CAT_LINE.NEXTVAL,
                                                REPLACE (IN_REC.TEXT,
                                                         'CurrentStructure',
                                                         'ParentStructure'));

                                    INSERT INTO MGR_CAT_OUTPUT
                                      VALUES   (MGR_CAT_LINE.NEXTVAL, GEN_NEXT_LINE.TEXT);

                                    INSERT INTO MGR_CAT_OUTPUT
                                      VALUES   (MGR_CAT_LINE.NEXTVAL,
                                                '                </ParentStructure>');

                                    INSERT INTO MGR_CAT_OUTPUT
                                      VALUES   (MGR_CAT_LINE.NEXTVAL,
                                                '                <CurrentStructure editable="true" mandatory="false" visible="true">');

                                    INSERT INTO MGR_CAT_OUTPUT
                                      VALUES   (MGR_CAT_LINE.NEXTVAL,
                                                '                                <Value>'
                                                || REPLACE (V_VALUE, '&', '&amp;')
                                                || '</Value>');

                                    INSERT INTO MGR_CAT_OUTPUT
                                      VALUES   (MGR_CAT_LINE.NEXTVAL,
                                                '                </CurrentStructure>');
                                ELSIF IN_REC.TEXT LIKE '%<Value%'
                                      OR IN_REC.TEXT LIKE '%</CurrentStructure%'
                                THEN
                                    CONTINUE;
                                ELSE
                                    INSERT INTO MGR_CAT_OUTPUT
                                      VALUES   (MGR_CAT_LINE.NEXTVAL, IN_REC.TEXT);
                                END IF;
                            END LOOP;
                        ELSE
                            FOR TAB_REC
                            IN (SELECT   *
                                  FROM   ISS_POSTING_RULES
                                 WHERE   CARD_PRODUCT_CODE = V_PRODUCT_CODE
                                         AND BANK_CODE = V_BANK_CODE)
                            LOOP
                                IF 1 = 2
                                THEN
                                    FOR IN_REC
                                    IN (  SELECT   *
                                            FROM   MGR_CAT_GENPAN
                                           WHERE   LINE BETWEEN V_START_IN_BLOCK
                                                            AND  V_END_IN_BLOCK
                                        ORDER BY   LINE)
                                    LOOP
                                        IF IN_REC.TEXT LIKE '%uniqueIndex%'
                                        THEN
                                            IN_REC.TEXT      := REPLACE (
                                                                    IN_REC.TEXT,
                                                                    'uniqueIndex="'
                                                                    || SUBSTR (
                                                                           IN_REC.TEXT,
                                                                           INSTR (
                                                                               IN_REC.TEXT,
                                                                               'uniqueIndex="')
                                                                           + 13,
                                                                           INSTR (
                                                                               SUBSTR (
                                                                                   IN_REC.TEXT,
                                                                                   INSTR (
                                                                                       IN_REC.TEXT,
                                                                                       'uniqueIndex="')
                                                                                   + 13),
                                                                               '"')
                                                                           - 1),
                                                                    'uniqueIndex="'
                                                                    || V_UNIQUE_INDEX);

                                            SELECT   COUNT ( * )
                                              INTO   V_CHECK_EXISTING_INJECTED
                                              FROM   MGR_CATALOGUE_INJECTED_PARAM
                                             WHERE   BANK_CODE = V_BANK_CODE
                                                     AND PRODUCT_CODE =
                                                            'PAN' || V_PRODUCT_CODE
                                                     AND ENTITY_NAME =
                                                            'Iss_posting_rules'
                                                     AND PK_FIELD_VALUE_1 =
                                                            TAB_REC.SEQUENCE_ID;

                                            IF V_CHECK_EXISTING_INJECTED = 0
                                            THEN
                                                INSERT INTO MGR_CATALOGUE_INJECTED_PARAM (BANK_CODE,
                                                                                          PRODUCT_CODE,
                                                                                          PROD_VERSION,
                                                                                          PROD_SEQUENCE,
                                                                                          GROUP_DATA_INDEX,
                                                                                          ENTITY_NAME,
                                                                                          PK_FIELD_NAME_1,
                                                                                          PK_FIELD_VALUE_1,
                                                                                          PK_FIELD_NAME_2,
                                                                                          PK_FIELD_VALUE_2,
                                                                                          PK_FIELD_NAME_3,
                                                                                          PK_FIELD_VALUE_3,
                                                                                          PK_FIELD_NAME_4,
                                                                                          PK_FIELD_VALUE_4,
                                                                                          PK_FIELD_NAME_5,
                                                                                          PK_FIELD_VALUE_5,
                                                                                          PK_FIELD_NAME_6,
                                                                                          PK_FIELD_VALUE_6,
                                                                                          PK_FIELD_NAME_7,
                                                                                          PK_FIELD_VALUE_7,
                                                                                          USER_CREATE,
                                                                                          DATE_CREATE,
                                                                                          USER_MODIF,
                                                                                          DATE_MODIF)
                                                  VALUES   (V_BANK_CODE,
                                                            'PAN' || V_PRODUCT_CODE,
                                                            '1',
                                                            V_PRODUCT_CODE,
                                                            V_UNIQUE_INDEX,
                                                            'Iss_posting_rules',
                                                            'sequence_id',
                                                            TAB_REC.SEQUENCE_ID,
                                                            NULL,
                                                            NULL,
                                                            NULL,
                                                            NULL,
                                                            NULL,
                                                            NULL,
                                                            NULL,
                                                            NULL,
                                                            NULL,
                                                            NULL,
                                                            NULL,
                                                            NULL,
                                                            'mgr',
                                                            NULL,
                                                            NULL,
                                                            NULL);
                                            END IF;

                                            V_UNIQUE_INDEX   := V_UNIQUE_INDEX + 1;
                                        END IF;

                                        SELECT   *
                                          INTO   GEN_NEXT_LINE
                                          FROM   MGR_CAT_GENPAN
                                         WHERE   LINE = IN_REC.LINE + 1;

                                        IF IN_REC.TEXT LIKE '%<Characteristic %'
                                        THEN
                                            INSERT INTO MGR_CAT_OUTPUT
                                              VALUES   (MGR_CAT_LINE.NEXTVAL, IN_REC.TEXT)
;
                                            V_VALUE   := '';
                                        ELSIF IN_REC.TEXT LIKE '%<CurrentStructure%'
                                              AND GEN_NEXT_LINE.TEXT NOT LIKE '%<Value%'
                                        THEN
                                            INSERT INTO MGR_CAT_OUTPUT
                                              VALUES   (MGR_CAT_LINE.NEXTVAL,
                                                        REPLACE (IN_REC.TEXT,
                                                                 'CurrentStructure',
                                                                 'ParentStructure'));

                                            INSERT INTO MGR_CAT_OUTPUT
                                              VALUES   (MGR_CAT_LINE.NEXTVAL,
                                                        '                <CurrentStructure editable="true" mandatory="false" visible="true">');

                                            INSERT INTO MGR_CAT_OUTPUT
                                              VALUES   (MGR_CAT_LINE.NEXTVAL,
                                                        '                                <Value>'
                                                        || REPLACE (V_VALUE,
                                                                    '&',
                                                                    '&amp;')
                                                        || '</Value>');

                                            INSERT INTO MGR_CAT_OUTPUT
                                              VALUES   (MGR_CAT_LINE.NEXTVAL,
                                                        '                </CurrentStructure>');
                                        ELSIF IN_REC.TEXT LIKE '%<CurrentStructure%'
                                              AND GEN_NEXT_LINE.TEXT LIKE '%<Value%'
                                        THEN
                                            INSERT INTO MGR_CAT_OUTPUT
                                              VALUES   (MGR_CAT_LINE.NEXTVAL,
                                                        REPLACE (IN_REC.TEXT,
                                                                 'CurrentStructure',
                                                                 'ParentStructure'));

                                            INSERT INTO MGR_CAT_OUTPUT
                                              VALUES   (MGR_CAT_LINE.NEXTVAL,
                                                        GEN_NEXT_LINE.TEXT);

                                            INSERT INTO MGR_CAT_OUTPUT
                                              VALUES   (MGR_CAT_LINE.NEXTVAL,
                                                        '                </ParentStructure>');

                                            INSERT INTO MGR_CAT_OUTPUT
                                              VALUES   (MGR_CAT_LINE.NEXTVAL,
                                                        '                <CurrentStructure editable="true" mandatory="false" visible="true">');

                                            INSERT INTO MGR_CAT_OUTPUT
                                              VALUES   (MGR_CAT_LINE.NEXTVAL,
                                                        '                                <Value>'
                                                        || REPLACE (V_VALUE,
                                                                    '&',
                                                                    '&amp;')
                                                        || '</Value>');

                                            INSERT INTO MGR_CAT_OUTPUT
                                              VALUES   (MGR_CAT_LINE.NEXTVAL,
                                                        '                </CurrentStructure>');
                                        ELSIF IN_REC.TEXT LIKE '%<Value%'
                                              OR IN_REC.TEXT LIKE '%</CurrentStructure%'
                                        THEN
                                            CONTINUE;
                                        ELSE
                                            INSERT INTO MGR_CAT_OUTPUT
                                              VALUES   (MGR_CAT_LINE.NEXTVAL, IN_REC.TEXT)
;
                                        END IF;
                                    END LOOP;

                                    V_FIRST_FLAG   := 'N';
                                END IF;


                                FOR IN_REC
                                IN (  SELECT   *
                                        FROM   MGR_CAT_GENPAN
                                       WHERE   LINE BETWEEN V_START_IN_BLOCK
                                                        AND  V_END_IN_BLOCK
                                    ORDER BY   LINE)
                                LOOP
                                    IF IN_REC.TEXT LIKE '%uniqueIndex%'
                                    THEN
                                        IN_REC.TEXT      := REPLACE (
                                                                IN_REC.TEXT,
                                                                'uniqueIndex="'
                                                                || SUBSTR (
                                                                       IN_REC.TEXT,
                                                                       INSTR (
                                                                           IN_REC.TEXT,
                                                                           'uniqueIndex="')
                                                                       + 13,
                                                                       INSTR (
                                                                           SUBSTR (
                                                                               IN_REC.TEXT,
                                                                               INSTR (
                                                                                   IN_REC.TEXT,
                                                                                   'uniqueIndex="')
                                                                               + 13),
                                                                           '"')
                                                                       - 1),
                                                                'uniqueIndex="'
                                                                || V_UNIQUE_INDEX);

                                        SELECT   COUNT ( * )
                                          INTO   V_CHECK_EXISTING_INJECTED
                                          FROM   MGR_CATALOGUE_INJECTED_PARAM
                                         WHERE   BANK_CODE = V_BANK_CODE
                                                 AND PRODUCT_CODE =
                                                        'PAN' || V_PRODUCT_CODE
                                                 AND ENTITY_NAME = 'Iss_posting_rules'
                                                 AND PK_FIELD_VALUE_1 =
                                                        TAB_REC.SEQUENCE_ID;

                                        IF V_CHECK_EXISTING_INJECTED = 0
                                        THEN
                                            INSERT INTO MGR_CATALOGUE_INJECTED_PARAM (BANK_CODE,
                                                                                      PRODUCT_CODE,
                                                                                      PROD_VERSION,
                                                                                      PROD_SEQUENCE,
                                                                                      GROUP_DATA_INDEX,
                                                                                      ENTITY_NAME,
                                                                                      PK_FIELD_NAME_1,
                                                                                      PK_FIELD_VALUE_1,
                                                                                      PK_FIELD_NAME_2,
                                                                                      PK_FIELD_VALUE_2,
                                                                                      PK_FIELD_NAME_3,
                                                                                      PK_FIELD_VALUE_3,
                                                                                      PK_FIELD_NAME_4,
                                                                                      PK_FIELD_VALUE_4,
                                                                                      PK_FIELD_NAME_5,
                                                                                      PK_FIELD_VALUE_5,
                                                                                      PK_FIELD_NAME_6,
                                                                                      PK_FIELD_VALUE_6,
                                                                                      PK_FIELD_NAME_7,
                                                                                      PK_FIELD_VALUE_7,
                                                                                      USER_CREATE,
                                                                                      DATE_CREATE,
                                                                                      USER_MODIF,
                                                                                      DATE_MODIF)
                                              VALUES   (V_BANK_CODE,
                                                        'PAN' || V_PRODUCT_CODE,
                                                        '1',
                                                        V_PRODUCT_CODE,
                                                        V_UNIQUE_INDEX,
                                                        'Iss_posting_rules',
                                                        'sequence_id',
                                                        TAB_REC.SEQUENCE_ID,
                                                        NULL,
                                                        NULL,
                                                        NULL,
                                                        NULL,
                                                        NULL,
                                                        NULL,
                                                        NULL,
                                                        NULL,
                                                        NULL,
                                                        NULL,
                                                        NULL,
                                                        NULL,
                                                        'mgr',
                                                        NULL,
                                                        NULL,
                                                        NULL);
                                        END IF;

                                        V_UNIQUE_INDEX   := V_UNIQUE_INDEX + 1;
                                    END IF;

                                    SELECT   *
                                      INTO   GEN_NEXT_LINE
                                      FROM   MGR_CAT_GENPAN
                                     WHERE   LINE = IN_REC.LINE + 1;

                                    IF IN_REC.TEXT LIKE '%<Characteristic %'
                                    THEN
                                        INSERT INTO MGR_CAT_OUTPUT
                                          VALUES   (MGR_CAT_LINE.NEXTVAL, IN_REC.TEXT);

                                        V_CHARACTERISTIC_ID   := SUBSTR (
                                                                     IN_REC.TEXT,
                                                                     INSTR (IN_REC.TEXT,
                                                                            'id="')
                                                                     + 4,
                                                                     INSTR (
                                                                         SUBSTR (
                                                                             IN_REC.TEXT,
                                                                             INSTR (
                                                                                 IN_REC.TEXT,
                                                                                 'id="')
                                                                             + 4),
                                                                         '"')
                                                                     - 1);

                                        BEGIN
                                            SELECT   DISTINCT FIELD_NAME
                                              INTO   V_FIELD_NAME
                                              FROM   CATALOGUE_MAPPING
                                             WHERE   PRODUCT_TYPE = 'P'
                                                     AND TAG_ID = V_CHARACTERISTIC_ID;
                                        EXCEPTION
                                            WHEN TOO_MANY_ROWS
                                            THEN
                                                BEGIN
                                                    SELECT   DISTINCT FIELD_NAME
                                                      INTO   V_FIELD_NAME
                                                      FROM   CATALOGUE_MAPPING
                                                     WHERE   PRODUCT_TYPE = 'P'
                                                             AND TAG_ID =
                                                                    V_CHARACTERISTIC_ID;
                                                EXCEPTION
                                                    WHEN TOO_MANY_ROWS
                                                    THEN
                                                        BEGIN
                                                            SELECT   DISTINCT FIELD_NAME
                                                              INTO   V_FIELD_NAME
                                                              FROM   MGR_CATALOGUE_MAPPING
                                                             WHERE   PRODUCT_TYPE = 'P'
                                                                     AND TAG_ID =
                                                                            V_CHARACTERISTIC_ID
;
                                                        EXCEPTION
                                                            WHEN NO_DATA_FOUND
                                                            THEN
                                                                INSERT INTO MGR_TRACE
                                                                  VALUES   ('ERROR '
                                                                            || $$PLSQL_LINE
                                                                            || '  too_many_rows TAG_ID='
                                                                            || V_CHARACTERISTIC_ID);
                                                                COMMIT;
                                                                EXIT;
                                                        END;
                                                END;
                                        END;

                                        IF V_FIELD_NAME = 'corporate_id'
                                        THEN
                                            V_VALUE   := TAB_REC.CORPORATE_ID;
                                        ELSIF V_FIELD_NAME = 'mcc'
                                        THEN
                                            V_VALUE   := TAB_REC.MCC;
                                        ELSIF V_FIELD_NAME = 'mcc_group'
                                        THEN
                                            V_VALUE   := TAB_REC.MCC_GROUP;
                                        ELSIF V_FIELD_NAME = 'owner_code'
                                        THEN
                                            V_VALUE   := TAB_REC.OWNER_CODE;
                                        ELSIF V_FIELD_NAME = 'transaction_code'
                                        THEN
                                            V_VALUE   := TAB_REC.TRANSACTION_CODE;
                                        ELSIF V_FIELD_NAME = 'transaction_category'
                                        THEN
                                            V_VALUE   := TAB_REC.TRANSACTION_CATEGORY;
                                        ELSIF V_FIELD_NAME = 'transaction_currency'
                                        THEN
                                            V_VALUE   := TAB_REC.TRANSACTION_CURRENCY;
                                        ELSIF V_FIELD_NAME = 'acquirer_country_code'
                                        THEN
                                            V_VALUE   := TAB_REC.ACQUIRER_COUNTRY_CODE;
                                        ELSIF V_FIELD_NAME = 'currency_flag'
                                        THEN
                                            V_VALUE   := TAB_REC.CURRENCY_FLAG;
                                        ELSIF V_FIELD_NAME = 'country_flag'
                                        THEN
                                            V_VALUE   := TAB_REC.COUNTRY_FLAG;
                                        ELSIF V_FIELD_NAME = 'posting_destination'
                                        THEN
                                            V_VALUE   := TAB_REC.POSTING_DESTINATION;
                                        ELSIF V_FIELD_NAME = 'corporate_level'
                                        THEN
                                            V_VALUE   := TAB_REC.CORPORATE_LEVEL;
                                        ELSIF V_FIELD_NAME = 'posting_account_type'
                                        THEN
                                            V_VALUE   := TAB_REC.POSTING_ACCOUNT_TYPE;
                                        ELSIF V_FIELD_NAME = 'posting_account_sequence'
                                        THEN
                                            V_VALUE   := TAB_REC.POSTING_ACCOUNT_SEQUENCE;
                                        ELSIF V_FIELD_NAME = 'customer_segment_code'
                                        THEN
                                            V_VALUE   := TAB_REC.CUSTOMER_SEGMENT_CODE;
                                        ELSIF V_FIELD_NAME = 'vip_code'
                                        THEN
                                            V_VALUE   := TAB_REC.VIP_CODE;
                                        END IF;
                                    ELSIF IN_REC.TEXT LIKE '%<CurrentStructure%'
                                          AND GEN_NEXT_LINE.TEXT NOT LIKE '%<Value%'
                                    THEN
                                        INSERT INTO MGR_CAT_OUTPUT
                                          VALUES   (MGR_CAT_LINE.NEXTVAL,
                                                    REPLACE (IN_REC.TEXT,
                                                             'CurrentStructure',
                                                             'ParentStructure'));

                                        INSERT INTO MGR_CAT_OUTPUT
                                          VALUES   (MGR_CAT_LINE.NEXTVAL,
                                                    '                <CurrentStructure editable="true" mandatory="false" visible="true">');

                                        INSERT INTO MGR_CAT_OUTPUT
                                          VALUES   (MGR_CAT_LINE.NEXTVAL,
                                                    '                                <Value>'
                                                    || REPLACE (V_VALUE, '&', '&amp;')
                                                    || '</Value>');

                                        INSERT INTO MGR_CAT_OUTPUT
                                          VALUES   (MGR_CAT_LINE.NEXTVAL,
                                                    '                </CurrentStructure>')
;
                                    ELSIF IN_REC.TEXT LIKE '%<CurrentStructure%'
                                          AND GEN_NEXT_LINE.TEXT LIKE '%<Value%'
                                    THEN
                                        INSERT INTO MGR_CAT_OUTPUT
                                          VALUES   (MGR_CAT_LINE.NEXTVAL,
                                                    REPLACE (IN_REC.TEXT,
                                                             'CurrentStructure',
                                                             'ParentStructure'));

                                        INSERT INTO MGR_CAT_OUTPUT
                                          VALUES   (MGR_CAT_LINE.NEXTVAL,
                                                    GEN_NEXT_LINE.TEXT);

                                        INSERT INTO MGR_CAT_OUTPUT
                                          VALUES   (MGR_CAT_LINE.NEXTVAL,
                                                    '                </ParentStructure>');

                                        INSERT INTO MGR_CAT_OUTPUT
                                          VALUES   (MGR_CAT_LINE.NEXTVAL,
                                                    '                <CurrentStructure editable="true" mandatory="false" visible="true">');

                                        INSERT INTO MGR_CAT_OUTPUT
                                          VALUES   (MGR_CAT_LINE.NEXTVAL,
                                                    '                                <Value>'
                                                    || REPLACE (V_VALUE, '&', '&amp;')
                                                    || '</Value>');

                                        INSERT INTO MGR_CAT_OUTPUT
                                          VALUES   (MGR_CAT_LINE.NEXTVAL,
                                                    '                </CurrentStructure>')
;
                                    ELSIF IN_REC.TEXT LIKE '%<Value%'
                                          OR IN_REC.TEXT LIKE '%</CurrentStructure%'
                                    THEN
                                        CONTINUE;
                                    ELSE
                                        INSERT INTO MGR_CAT_OUTPUT
                                          VALUES   (MGR_CAT_LINE.NEXTVAL, IN_REC.TEXT);
                                    END IF;
                                END LOOP;
                            END LOOP;
                        END IF;
                    END IF;

                    CONTINUE;
                END IF;



                IF REC.TEXT LIKE '%<Characteristic %' AND V_CURRENT_GRP IS NULL
                THEN
                    INSERT INTO MGR_CAT_OUTPUT
                      VALUES   (MGR_CAT_LINE.NEXTVAL, REC.TEXT);

                    V_CHARACTERISTIC_ID   := SUBSTR (
                                                 REC.TEXT,
                                                 INSTR (REC.TEXT, 'id="') + 4,
                                                 INSTR (
                                                     SUBSTR (
                                                         REC.TEXT,
                                                         INSTR (REC.TEXT, 'id="') + 4),
                                                     '"')
                                                 - 1);

                    IF REC.TEXT LIKE '%systemRequired="true"%'
                    THEN
                        V_REQUIRED_FLAG   := TRUE;
                    END IF;

                    BEGIN
                        SELECT   ENTITY_NAME, FIELD_NAME
                          INTO   V_ENTITY_NAME, V_FIELD_NAME
                          FROM   CATALOGUE_MAPPING
                         WHERE   PRODUCT_TYPE = 'P' AND TAG_ID = V_CHARACTERISTIC_ID;
                    EXCEPTION
                        WHEN TOO_MANY_ROWS
                        THEN
                            /*


                            if v_characteristic_id in ('CAR_CURRENCY','CAR_DEF_LANGUAGE','CAR_GEN_PROCEDURE','CAR_NETWORK','CAR_PRODUCT_TYPE','CAR_EMB_PLASTIC_TYPE') then
                                 select entity_name,field_name into v_entity_name,v_field_name from catalogue_mapping where product_type='P' and tag_id=v_characteristic_id and entity_name='Card_product';
                            elsif v_characteristic_id in ('CAR_CARD_RNG_ISS_BIN','CAR_CARD_RNG_SERVICE_CODE','CAR_NBR_CRD_TYPE','CAR_CARD_RNG_MIN_RANGE','CAR_CARD_RNG_MAX_RANGE') then
                                  select entity_name,field_name into v_entity_name,v_field_name from catalogue_mapping where product_type='P' and tag_id=v_characteristic_id and entity_name='Card_range';
                            elsif v_characteristic_id ='CAR_EMV_APPLICATION_TYPE' then
                                select entity_name,field_name into v_entity_name,v_field_name from catalogue_mapping where product_type='P' and tag_id=v_characteristic_id and entity_name='Emv_icc_appl_definition';
                            elsif v_characteristic_id ='CAR_CARD_RNG_CARD_FILE_OPT' then
                                select entity_name,field_name into v_entity_name,v_field_name from catalogue_mapping where product_type='P' and tag_id=v_characteristic_id and field_name='card_file_option';
                            elsif v_characteristic_id ='CAR_EMV_APPLICATION_DESCRIPTION' then
                                  select entity_name,field_name into v_entity_name,v_field_name from catalogue_mapping where product_type='P' and tag_id=v_characteristic_id and field_name='wording';
                            elsif v_characteristic_id ='CAR_ISS_POST_ACC_CORP_LVL' then
                                  select entity_name,field_name into v_entity_name,v_field_name from catalogue_mapping where product_type='P' and tag_id=v_characteristic_id and field_name='corporate_level';
                            elsif v_characteristic_id ='CAR_CASH_BUYING_FIX' then
                                  select entity_name,field_name into v_entity_name,v_field_name from catalogue_mapping where product_type='P' and tag_id=v_characteristic_id and field_name='cash_buying_fix';
                             elsif v_characteristic_id ='CAR_CASH_BUYING_GRACE' then
                                  select entity_name,field_name into v_entity_name,v_field_name from catalogue_mapping where product_type='P' and tag_id=v_characteristic_id and field_name='cash_buying_grace';
                             elsif v_characteristic_id ='CAR_CASH_BUYING_MIN' then
                                  select entity_name,field_name into v_entity_name,v_field_name from catalogue_mapping where product_type='P' and tag_id=v_characteristic_id and field_name='cash_buying_min';
                             elsif v_characteristic_id ='CAR_CASH_BUYING_MAX' then
                                  select entity_name,field_name into v_entity_name,v_field_name from catalogue_mapping where product_type='P' and tag_id=v_characteristic_id and field_name='cash_buying_max';

                             */

                            BEGIN
                                SELECT   ENTITY_NAME, FIELD_NAME
                                  INTO   V_ENTITY_NAME, V_FIELD_NAME
                                  FROM   MGR_CATALOGUE_MAPPING
                                 WHERE   PRODUCT_TYPE = 'P'
                                         AND TAG_ID = V_CHARACTERISTIC_ID;
                            EXCEPTION
                                WHEN NO_DATA_FOUND
                                THEN
                                    INSERT INTO MGR_TRACE
                                      VALUES   ('TOO MANY ROWS : TAG_ID='
                                                || V_CHARACTERISTIC_ID);

                                    COMMIT;
                                    EXIT;
                            END;
                        WHEN NO_DATA_FOUND
                        THEN
                            IF V_CHARACTERISTIC_ID = 'CAR_FEATURE_TYPE'
                            THEN
                                V_ENTITY_NAME   := 'dual';
                                V_FIELD_NAME    := '''P''';
                            ELSIF V_CHARACTERISTIC_ID IN
                                          ('CAR_EMV_APPLICATION_USAGE',
                                           'CAR_EMV_SHARED_USAGE',
                                           'CAR_EMV_CONTACT_USAGE',
                                           'CAR_EMV_CONTACTLESS_USAGE')
                            THEN
                                V_ENTITY_NAME   := 'dual';
                                V_FIELD_NAME    := '''Y''';
                            ELSE
                                INSERT INTO MGR_TRACE
                                  VALUES   ('ERROR  TAG NOT FOUND TAG_ID='
                                            || V_CHARACTERISTIC_ID);

                                COMMIT;
                                V_ENTITY_NAME   := 'dual';
                                V_FIELD_NAME    := 'null';
                            END IF;
                        WHEN OTHERS
                        THEN
                            V_TRACE   := SQLERRM;

                            INSERT INTO MGR_TRACE
                              VALUES   (   'ERROR  TAG_ID='
                                        || V_CHARACTERISTIC_ID
                                        || ' '
                                        || V_TRACE);

                            COMMIT;
                            EXIT;
                    END;

                    IF LOWER (V_ENTITY_NAME) IN ('card_range')
                    THEN
                        TAB_WHERE   :=    '  product_code='''
                                       || V_PRODUCT_CODE
                                       || ''' and issuing_bank_code='''
                                       || V_BANK_CODE
                                       || ''' ';
                    ELSIF LOWER (V_ENTITY_NAME) IN ('card_gen_counters')
                    THEN
                        TAB_WHERE   :=    '  card_product_code='''
                                       || V_PRODUCT_CODE
                                       || ''' and bank_code='''
                                       || V_BANK_CODE
                                       || ''' ';
                    ELSIF LOWER (V_ENTITY_NAME) IN ('pcrd_card_prod_param')
                    THEN
                        TAB_WHERE   :=    '  nvl(card_product_code,'''
                                       || V_PRODUCT_CODE
                                       || ''')='''
                                       || V_PRODUCT_CODE
                                       || ''' and bank_code='''
                                       || V_BANK_CODE
                                       || ''' and plastic_code in (select plastic_type from card_product where product_code='''
                                       || V_PRODUCT_CODE
                                       || ''' and bank_code='''
                                       || V_BANK_CODE
                                       || ''') ';
                    ELSIF LOWER (V_ENTITY_NAME) = 'iss_posting_rules'
                    THEN
                        TAB_WHERE   :=    '  card_product_code='''
                                       || V_PRODUCT_CODE
                                       || ''' and bank_code='''
                                       || V_BANK_CODE
                                       || ''' and posting_account_sequence=1 ';
                    ELSIF LOWER (V_ENTITY_NAME) = 'card_fees'
                    THEN
                        TAB_WHERE   := ' card_fees_code=(select card_fees_ind_prim from card_product where bank_code='''
                                       || V_BANK_CODE
                                       || ''' and product_code='''
                                       || V_PRODUCT_CODE
                                       || ''') and bank_code='''
                                       || V_BANK_CODE
                                       || ''' ';
                    ELSIF LOWER (V_ENTITY_NAME) IN
                                  ('product_domain_setup',
                                   'control_verification_flags',
                                   'p7_ctrl_decision_matrix',
                                   'sca_rp_decision_matrix',
                                   'fleet_ctrl_verif_flags')
                    THEN
                        TAB_WHERE   := ' control_verification_index=(select control_verification_index from card_product where bank_code='''
                                       || V_BANK_CODE
                                       || ''' and product_code='''
                                       || V_PRODUCT_CODE
                                       || ''') and bank_code='''
                                       || V_BANK_CODE
                                       || ''' ';
                    ELSIF LOWER (V_ENTITY_NAME) IN ('p7_sa_limits_setup')
                    THEN
                        TAB_WHERE   :=    ' limit_index='''
                                       || V_PRODUCT_CODE
                                       || ''' and bank_code='''
                                       || V_BANK_CODE
                                       || ''' ';
                    ELSIF LOWER (V_ENTITY_NAME) IN ('p7_services_setup')
                    THEN
                        TAB_WHERE   := ' service_setup_index in (select services_setup_index from card_product where bank_code='''
                                       || V_BANK_CODE
                                       || ''' and product_code='''
                                       || V_PRODUCT_CODE
                                       || ''')  and bank_code='''
                                       || V_BANK_CODE
                                       || ''' ';
                    ELSIF LOWER (V_ENTITY_NAME) IN ('markup_calcul')
                    THEN
                        TAB_WHERE   := ' markup_fee_index=(select markup_code from card_product where bank_code='''
                                       || V_BANK_CODE
                                       || ''' and product_code='''
                                       || V_PRODUCT_CODE
                                       || ''')  and bank_code='''
                                       || V_BANK_CODE
                                       || ''' and rownum=1';
                    ELSIF LOWER (V_ENTITY_NAME) IN ('card_range_key')
                    THEN
                        TAB_WHERE   := ' issuing_bank_code=''' || V_BANK_CODE || ''' ';
                    ELSIF LOWER (V_ENTITY_NAME) IN ('autho_fees_param')
                    THEN
                        TAB_WHERE   := 'fee_index=(select product_code from card_product where product_code='''
                                       || V_PRODUCT_CODE
                                       || ''' and bank_code='''
                                       || V_BANK_CODE
                                       || ''') and bank_code='''
                                       || V_BANK_CODE
                                       || ''' ';
                    ELSIF LOWER (V_ENTITY_NAME) IN ('entity_event_grouping')
                    THEN
                        TAB_WHERE   := '  event_rules_index in ( select event_rules_index from card_product where bank_code='''
                                       || V_BANK_CODE
                                       || ''' and product_code='''
                                       || V_PRODUCT_CODE
                                       || ''' ) and bank_code='''
                                       || V_BANK_CODE
                                       || ''' ';
                    ELSIF LOWER (V_ENTITY_NAME) IN ('iss_transaction_fees_param')
                    THEN
                        TAB_WHERE   := '  transaction_fee_index in ( select transaction_fee_index from card_product where bank_code='''
                                       || V_BANK_CODE
                                       || ''' and product_code='''
                                       || V_PRODUCT_CODE
                                       || ''' ) and issuer_bank_code='''
                                       || V_BANK_CODE
                                       || ''' ';
                    ELSIF LOWER (V_ENTITY_NAME) IN ('p7_limits')
                    THEN
                        TAB_WHERE   := '  limit_index in ( select limits_indexes from card_product where bank_code='''
                                       || V_BANK_CODE
                                       || ''' and product_code='''
                                       || V_PRODUCT_CODE
                                       || ''' ) and bank_code='''
                                       || V_BANK_CODE
                                       || ''' ';
                    ELSIF LOWER (V_ENTITY_NAME) IN ('credit_auth_param')
                    THEN
                        TAB_WHERE   := '  service_setup_index in ( select services_setup_index from card_product where bank_code='''
                                       || V_BANK_CODE
                                       || ''' and product_code='''
                                       || V_PRODUCT_CODE
                                       || ''' ) and bank_code='''
                                       || V_BANK_CODE
                                       || ''' ';
                    ELSIF V_ENTITY_NAME = 'dual'
                    THEN
                        TAB_WHERE   := ' 1=1';
                    ELSE
                        TAB_WHERE   :=    '  product_code='''
                                       || V_PRODUCT_CODE
                                       || ''' and bank_code='''
                                       || V_BANK_CODE
                                       || ''' ';
                    END IF;


                    V_QUERY               :=    'select distinct '
                                             || V_FIELD_NAME
                                             || ' from '
                                             || V_ENTITY_NAME
                                             || ' where  '
                                             || TAB_WHERE;

                    BEGIN
                        EXECUTE IMMEDIATE V_QUERY INTO   V_VALUE;

                           IF v_characteristic_id = 'CTRL_CAR_RETRY_MAX'
                    THEN
                        SELECT exp_date_retry_max
                          INTO v_exp_date_retry_max
                          FROM control_verification_flags
                         WHERE     control_verification_index =
                                       (SELECT control_verification_index
                                          FROM card_product
                                         WHERE     bank_code = v_bank_code
                                               AND product_code =
                                                       v_product_code)
                               AND bank_code = v_bank_code;

                        IF v_exp_date_retry_max IS NOT NULL
                        THEN
                            v_value := 'Y';
                        ELSE
                            v_value := 'N';
                        END IF;
                    END IF;


                    EXCEPTION
                        WHEN NO_DATA_FOUND
                        THEN
                            --insert into mgr_trace values ('ERROR  no_data_found v_query='||v_query||' '||v_trace);
                            --insert into mgr_trace values ('ERROR  v_current_grp='||v_current_grp||' '||v_trace);
                            IF (V_REQUIRED_FLAG = TRUE)
                            THEN
                                INSERT INTO MGR_TRACE
                                  VALUES   ('WARNING  REQUIRED_FIELD EMPTY TAG_ID='
                                            || V_CHARACTERISTIC_ID);
                            END IF;

                            V_VALUE   := '';
                        WHEN TOO_MANY_ROWS
                        THEN
                            V_TRACE   := SQLERRM;

                            INSERT INTO MGR_TRACE
                              VALUES   ('ERROR  v_query=' || V_QUERY || ' ' || V_TRACE);

                            INSERT INTO MGR_TRACE
                              VALUES   (   'ERROR  v_current_grp='
                                        || V_CURRENT_GRP
                                        || ' '
                                        || V_TRACE);

                            INSERT INTO MGR_TRACE
                              VALUES   (   'ERROR  v_current_tag='
                                        || V_CHARACTERISTIC_ID
                                        || ' '
                                        || V_TRACE);

                            COMMIT;
                            EXIT;
                        WHEN OTHERS
                        THEN
                            V_TRACE   := SQLERRM;

                            IF V_TRACE LIKE '%ORA-00942%'
                            THEN
                                INSERT INTO MGR_TRACE
                                  VALUES   (   'ERROR Entity not found  v_query='
                                            || V_QUERY
                                            || ' '
                                            || V_TRACE);

                                V_VALUE   := '';
                            ELSE
                                INSERT INTO MGR_TRACE
                                  VALUES   (   'ERROR  v_query='
                                            || V_QUERY
                                            || ' '
                                            || V_TRACE);

                                INSERT INTO MGR_TRACE
                                  VALUES   (   'ERROR  v_current_grp='
                                            || V_CURRENT_GRP
                                            || ' '
                                            || V_TRACE);

                                COMMIT;
                                EXIT;
                            END IF;
                    END;
                ELSIF     REC.TEXT LIKE '%<CurrentStructure%'
                      AND GEN_NEXT_LINE.TEXT NOT LIKE '%<Value%'
                      AND GEN_NEXT_LINE.TEXT NOT LIKE '%<MinValue%'
                      AND V_CURRENT_GRP IS NULL
                THEN
                    INSERT INTO MGR_CAT_OUTPUT
                      VALUES   (MGR_CAT_LINE.NEXTVAL,
                                REPLACE (REC.TEXT, 'CurrentStructure', 'ParentStructure'))
;

                    INSERT INTO MGR_CAT_OUTPUT
                      VALUES   (MGR_CAT_LINE.NEXTVAL,
                                '                <CurrentStructure editable="true" mandatory="false" visible="true">');

                    INSERT INTO MGR_CAT_OUTPUT
                      VALUES   (MGR_CAT_LINE.NEXTVAL,
                                   '                                <Value>'
                                || TRIM (V_VALUE)
                                || '</Value>');

                    INSERT INTO MGR_CAT_OUTPUT
                      VALUES   (MGR_CAT_LINE.NEXTVAL,
                                '                </CurrentStructure>');
                ELSIF     REC.TEXT LIKE '%<CurrentStructure%'
                      AND GEN_NEXT_LINE.TEXT LIKE '%<Value%'
                      AND V_CURRENT_GRP IS NULL
                THEN
                    INSERT INTO MGR_CAT_OUTPUT
                      VALUES   (MGR_CAT_LINE.NEXTVAL,
                                REPLACE (REC.TEXT, 'CurrentStructure', 'ParentStructure'))
;

                    INSERT INTO MGR_CAT_OUTPUT
                      VALUES   (MGR_CAT_LINE.NEXTVAL, GEN_NEXT_LINE.TEXT);

                    INSERT INTO MGR_CAT_OUTPUT
                      VALUES   (MGR_CAT_LINE.NEXTVAL,
                                '                </ParentStructure>');

                    INSERT INTO MGR_CAT_OUTPUT
                      VALUES   (MGR_CAT_LINE.NEXTVAL,
                                '                <CurrentStructure editable="true" mandatory="false" visible="true">');

                    INSERT INTO MGR_CAT_OUTPUT
                      VALUES   (MGR_CAT_LINE.NEXTVAL,
                                   '                                <Value>'
                                || TRIM (V_VALUE)
                                || '</Value>');

                    INSERT INTO MGR_CAT_OUTPUT
                      VALUES   (MGR_CAT_LINE.NEXTVAL,
                                '                </CurrentStructure>');
                ELSIF     REC.TEXT LIKE '%<CurrentStructure%'
                      AND GEN_NEXT_LINE.TEXT LIKE '%<MinValue%'
                      AND V_CURRENT_GRP IS NULL
                THEN
                    INSERT INTO MGR_CAT_OUTPUT
                      VALUES   (MGR_CAT_LINE.NEXTVAL,
                                REPLACE (REC.TEXT, 'CurrentStructure', 'ParentStructure'))
;

                    INSERT INTO MGR_CAT_OUTPUT
                      VALUES   (MGR_CAT_LINE.NEXTVAL, GEN_NEXT_LINE.TEXT);

                    SELECT   *
                      INTO   GEN_NEXT_2ND_LINE
                      FROM   MGR_CAT_GENPAN
                     WHERE   LINE = REC.LINE + 2;

                    INSERT INTO MGR_CAT_OUTPUT
                      VALUES   (MGR_CAT_LINE.NEXTVAL, GEN_NEXT_2ND_LINE.TEXT);

                    INSERT INTO MGR_CAT_OUTPUT
                      VALUES   (MGR_CAT_LINE.NEXTVAL,
                                '                </ParentStructure>');

                    INSERT INTO MGR_CAT_OUTPUT
                      VALUES   (MGR_CAT_LINE.NEXTVAL,
                                '                <CurrentStructure editable="true" mandatory="false" visible="true">');

                    INSERT INTO MGR_CAT_OUTPUT
                      VALUES   (MGR_CAT_LINE.NEXTVAL,
                                   '                                <Value>'
                                || TRIM (V_VALUE)
                                || '</Value>');

                    INSERT INTO MGR_CAT_OUTPUT
                      VALUES   (MGR_CAT_LINE.NEXTVAL,
                                '                </CurrentStructure>');
                ELSIF    REC.TEXT LIKE '%<MinValue%'
                      OR REC.TEXT LIKE '%<MaxValue%'
                      OR REC.TEXT LIKE '%<Value%'
                      OR REC.TEXT LIKE '%</CurrentStructure%' AND V_CURRENT_GRP IS NULL
                THEN
                    CONTINUE;
                ELSIF V_END_IN_BLOCK = REC.LINE AND V_CURRENT_GRP IS NULL
                THEN
                    INSERT INTO MGR_CAT_OUTPUT
                      VALUES   (MGR_CAT_LINE.NEXTVAL, REC.TEXT);

                    V_END_IN_BLOCK   := GET_END_OF_BLOCK (GEN_NEXT_LINE.LINE, 'PAN');
                ELSIF REC.TEXT LIKE '%grouped="array"%'
                      AND REC.TEXT LIKE '%GRP_EMV_SHARED_INTERFACE%'
                THEN
                    INSERT INTO MGR_CAT_OUTPUT
                      VALUES   (MGR_CAT_LINE.NEXTVAL, REC.TEXT);

                    V_CURRENT_GRP      := 'GRP_EMV_SHARED_INTERFACE';
                    V_START_BLOCK      := REC.LINE;
                    V_END_BLOCK        := GET_END_OF_BLOCK (REC.LINE, 'PAN');
                    V_START_IN_BLOCK   := GEN_NEXT_LINE.LINE;
                    V_END_IN_BLOCK     := GET_END_OF_BLOCK (GEN_NEXT_LINE.LINE, 'PAN');
                ELSIF REC.TEXT LIKE '%grouped="array"%'
                      AND REC.TEXT LIKE '%GRP_EMV_CONTACT%'
                THEN
                    INSERT INTO MGR_CAT_OUTPUT
                      VALUES   (MGR_CAT_LINE.NEXTVAL, REC.TEXT);

                    V_CURRENT_GRP      := 'GRP_EMV_CONTACT';
                    V_START_BLOCK      := REC.LINE;
                    V_END_BLOCK        := GET_END_OF_BLOCK (REC.LINE, 'PAN');
                    V_START_IN_BLOCK   := GEN_NEXT_LINE.LINE;
                    V_END_IN_BLOCK     := GET_END_OF_BLOCK (GEN_NEXT_LINE.LINE, 'PAN');
                ELSIF REC.TEXT LIKE '%grouped="array"%'
                      AND REC.TEXT LIKE '%GRP_EMV_KEYS%'
                THEN
                    INSERT INTO MGR_CAT_OUTPUT
                      VALUES   (MGR_CAT_LINE.NEXTVAL, REC.TEXT);

                    V_CURRENT_GRP      := 'GRP_EMV_KEYS';
                    V_START_BLOCK      := REC.LINE;
                    V_END_BLOCK        := GET_END_OF_BLOCK (REC.LINE, 'PAN');
                    V_START_IN_BLOCK   := GEN_NEXT_LINE.LINE;
                    V_END_IN_BLOCK     := GET_END_OF_BLOCK (GEN_NEXT_LINE.LINE, 'PAN');

                     ELSIF     rec.text LIKE '%grouped="array"%'
                  AND rec.text LIKE '%GRP_CTRL_DECISION_MATRIX%'
            THEN
                INSERT INTO mgr_cat_output
                VALUES (mgr_cat_line.NEXTVAL, rec.text);

                v_current_grp := 'GRP_CTRL_DECISION_MATRIX';
                v_start_block := rec.line;
                v_end_block := get_end_of_block (rec.line, 'PAN');
                v_start_in_block := gen_next_line.line;
                v_end_in_block := get_end_of_block (gen_next_line.line, 'PAN');

                ELSIF REC.TEXT LIKE '%GRP_CARD_RANGE%'
                THEN
                    INSERT INTO MGR_CAT_OUTPUT
                      VALUES   (MGR_CAT_LINE.NEXTVAL, REC.TEXT);

                    V_CURRENT_GRP      := 'GRP_CARD_RANGE';
                    V_START_BLOCK      := REC.LINE;
                    V_END_BLOCK        := GET_END_OF_BLOCK (REC.LINE, 'PAN');
                    -- v_start_in_block:=110;
                    --  v_end_in_block:=231;
                    V_START_IN_BLOCK   := 107;
                    V_END_IN_BLOCK     := 228;
                --v_start_in_block:=gen_next_line.line;
                --v_end_in_block:=get_end_of_block(gen_next_line.line,'PAN');
                ELSIF REC.TEXT LIKE '%GRP_CONTEXTS%'
                THEN
                    INSERT INTO MGR_CAT_OUTPUT
                      VALUES   (MGR_CAT_LINE.NEXTVAL, REC.TEXT);

                    V_CURRENT_GRP      := 'GRP_CONTEXTS';
                    V_START_BLOCK      := REC.LINE;
                    V_END_BLOCK        := GET_END_OF_BLOCK (REC.LINE, 'PAN');
                    V_START_IN_BLOCK   := GEN_NEXT_LINE.LINE;
                    V_END_IN_BLOCK     := GET_END_OF_BLOCK (GEN_NEXT_LINE.LINE, 'PAN');
                ELSIF REC.TEXT LIKE '%id="GRP_LIMITS"%maxOccurence="99"%'
                THEN
                    INSERT INTO MGR_CAT_OUTPUT
                      VALUES   (MGR_CAT_LINE.NEXTVAL, REC.TEXT);

                    V_CURRENT_GRP      := 'GRP_LIMITS';
                    V_START_BLOCK      := REC.LINE;
                    V_END_BLOCK        := GET_END_OF_BLOCK (REC.LINE, 'PAN');
                    V_START_IN_BLOCK   := GEN_NEXT_LINE.LINE;
                    V_END_IN_BLOCK     := GET_END_OF_BLOCK (GEN_NEXT_LINE.LINE, 'PAN');
                ELSIF REC.TEXT LIKE '%grouped="array"%'
                      AND REC.TEXT LIKE '%GRP_EMV_CONTACTLESS%'
                THEN
                    INSERT INTO MGR_CAT_OUTPUT
                      VALUES   (MGR_CAT_LINE.NEXTVAL, REC.TEXT);

                    V_CURRENT_GRP      := 'GRP_EMV_CONTACTLESS';
                    V_START_BLOCK      := REC.LINE;
                    V_END_BLOCK        := GET_END_OF_BLOCK (REC.LINE, 'PAN');
                    V_START_IN_BLOCK   := GEN_NEXT_LINE.LINE;
                    V_END_IN_BLOCK     := GET_END_OF_BLOCK (GEN_NEXT_LINE.LINE, 'PAN');
                ELSIF REC.TEXT LIKE '%grouped="array"%'
                      AND REC.TEXT LIKE '%GRP_AUTHO_FEES_LIST%'
                THEN
                    INSERT INTO MGR_CAT_OUTPUT
                      VALUES   (MGR_CAT_LINE.NEXTVAL, REC.TEXT);

                    V_CURRENT_GRP      := 'GRP_AUTHO_FEES_LIST';
                    V_START_BLOCK      := REC.LINE;
                    V_END_BLOCK        := GET_END_OF_BLOCK (REC.LINE, 'PAN');
                    V_START_IN_BLOCK   := GEN_NEXT_LINE.LINE;
                    V_END_IN_BLOCK     := GET_END_OF_BLOCK (GEN_NEXT_LINE.LINE, 'PAN');
                ELSIF REC.TEXT LIKE '%grouped="tab"%' AND REC.TEXT LIKE '%"GRP_MARKUP"%'
                THEN
                    INSERT INTO MGR_CAT_OUTPUT
                      VALUES   (MGR_CAT_LINE.NEXTVAL, REC.TEXT);

                    V_CURRENT_GRP      := 'GRP_MARKUP';
                    V_START_BLOCK      := REC.LINE;
                    V_END_BLOCK        := GET_END_OF_BLOCK (REC.LINE, 'PAN');
                    V_START_IN_BLOCK   := GEN_NEXT_LINE.LINE;
                    V_END_IN_BLOCK     := GET_END_OF_BLOCK (GEN_NEXT_LINE.LINE, 'PAN');
                ELSIF REC.TEXT LIKE '%grouped="tab"%'
                      AND REC.TEXT LIKE '%GRP_ISS_POSTING_RULES%'
                THEN
                    INSERT INTO MGR_CAT_OUTPUT
                      VALUES   (MGR_CAT_LINE.NEXTVAL, REC.TEXT);

                    V_CURRENT_GRP      := 'GRP_ISS_POSTING_RULES';
                    V_START_BLOCK      := REC.LINE;
                    V_END_BLOCK        := GET_END_OF_BLOCK (REC.LINE, 'PAN');
                    V_START_IN_BLOCK   := GEN_NEXT_LINE.LINE;
                    V_END_IN_BLOCK     := GET_END_OF_BLOCK (GEN_NEXT_LINE.LINE, 'PAN');
                ELSIF REC.TEXT LIKE '%grouped="array"%' AND REC.TEXT LIKE '%GRP_SERVICE%'
                THEN
                    INSERT INTO MGR_CAT_OUTPUT
                      VALUES   (MGR_CAT_LINE.NEXTVAL, REC.TEXT);

                    V_CURRENT_GRP      := 'GRP_SERVICE';
                    V_START_BLOCK      := REC.LINE;
                    V_END_BLOCK        := GET_END_OF_BLOCK (REC.LINE, 'PAN');
                    V_START_IN_BLOCK   := GEN_NEXT_LINE.LINE;
                    V_END_IN_BLOCK     := GET_END_OF_BLOCK (GEN_NEXT_LINE.LINE, 'PAN');
                ELSIF REC.TEXT LIKE '%grouped="array"%'
                      AND REC.TEXT LIKE '%GRP_FEES_ON_TRANS_ARRAY%'
                THEN
                    INSERT INTO MGR_CAT_OUTPUT
                      VALUES   (MGR_CAT_LINE.NEXTVAL, REC.TEXT);

                    V_CURRENT_GRP      := 'GRP_FEES_ON_TRANS_ARRAY';
                    V_START_BLOCK      := REC.LINE;
                    V_END_BLOCK        := GET_END_OF_BLOCK (REC.LINE, 'PAN');
                    V_START_IN_BLOCK   := GEN_NEXT_LINE.LINE;
                    V_END_IN_BLOCK     := GET_END_OF_BLOCK (GEN_NEXT_LINE.LINE, 'PAN');
                ELSIF REC.TEXT LIKE '%grouped="array"%'
                      AND REC.TEXT LIKE '%GRP_EMV_ARC_CARD_BLOCKED%'
                THEN
                    INSERT INTO MGR_CAT_OUTPUT
                      VALUES   (MGR_CAT_LINE.NEXTVAL, REC.TEXT);

                    V_CURRENT_GRP      := 'GRP_EMV_ARC_CARD_BLOCKED';
                    V_START_BLOCK      := REC.LINE;
                    V_END_BLOCK        := GET_END_OF_BLOCK (REC.LINE, 'PAN');
                    V_START_IN_BLOCK   := GEN_NEXT_LINE.LINE;
                    V_END_IN_BLOCK     := GET_END_OF_BLOCK (GEN_NEXT_LINE.LINE, 'PAN');
                ELSIF REC.TEXT LIKE '%grouped="array"%'
                      AND REC.TEXT LIKE '%GRP_SCA_MATRIX%'
                THEN
                    INSERT INTO MGR_CAT_OUTPUT
                      VALUES   (MGR_CAT_LINE.NEXTVAL, REC.TEXT);

                    V_CURRENT_GRP      := 'GRP_SCA_MATRIX';
                    V_START_BLOCK      := REC.LINE;
                    V_END_BLOCK        := GET_END_OF_BLOCK (REC.LINE, 'PAN');
                    V_START_IN_BLOCK   := GEN_NEXT_LINE.LINE;
                    V_END_IN_BLOCK     := GET_END_OF_BLOCK (GEN_NEXT_LINE.LINE, 'PAN');
                ELSE
                    NULL;

                    INSERT INTO MGR_CAT_OUTPUT
                      VALUES   (MGR_CAT_LINE.NEXTVAL, REC.TEXT);
                END IF;
            END LOOP;

            COMMIT;

            BEGIN
                FOR REC IN (  SELECT   *
                                FROM   MGR_CAT_OUTPUT
                               WHERE   TEXT LIKE '%grouped="array"%'
                            ORDER BY   LINE)
                LOOP
                    SELECT   TEXT
                      INTO   V_TEXT
                      FROM   MGR_CAT_OUTPUT
                     WHERE   LINE = REC.LINE + 1;

                    IF V_TEXT LIKE '%</GroupData>%'
                    THEN
                        DELETE FROM   MGR_CAT_OUTPUT
                              WHERE   LINE IN (REC.LINE, REC.LINE + 1);

                        NULL;
                    END IF;
                END LOOP;

                COMMIT;
            END;

            BEGIN
                SELECT   SUBSTR (
                             TEXT,
                             INSTR (TEXT, 'uniqueIndex="') + 13,
                             INSTR (SUBSTR (TEXT, INSTR (TEXT, 'uniqueIndex="') + 13),
                                    '"')
                             - 1)
                  INTO   V_MCALCUL_INDEX
                  FROM   MGR_CAT_OUTPUT
                 WHERE   TEXT LIKE '%GRP_MARKUP_ITER%';

                SELECT   *
                  INTO   MARKUP_CALCUL_REC
                  FROM   MARKUP_CALCUL
                 WHERE   BANK_CODE = V_BANK_CODE AND MARKUP_FEE_INDEX = V_PRODUCT_CODE;

                INSERT INTO MGR_CATALOGUE_INJECTED_PARAM (BANK_CODE,
                                                          PRODUCT_CODE,
                                                          PROD_VERSION,
                                                          PROD_SEQUENCE,
                                                          GROUP_DATA_INDEX,
                                                          ENTITY_NAME,
                                                          PK_FIELD_NAME_1,
                                                          PK_FIELD_VALUE_1,
                                                          PK_FIELD_NAME_2,
                                                          PK_FIELD_VALUE_2,
                                                          PK_FIELD_NAME_3,
                                                          PK_FIELD_VALUE_3,
                                                          PK_FIELD_NAME_4,
                                                          PK_FIELD_VALUE_4,
                                                          PK_FIELD_NAME_5,
                                                          PK_FIELD_VALUE_5,
                                                          PK_FIELD_NAME_6,
                                                          PK_FIELD_VALUE_6,
                                                          PK_FIELD_NAME_7,
                                                          PK_FIELD_VALUE_7,
                                                          USER_CREATE,
                                                          DATE_CREATE,
                                                          USER_MODIF,
                                                          DATE_MODIF)
                  VALUES   (V_BANK_CODE,
                            'PAN' || V_PRODUCT_CODE,
                            '1',
                            V_PRODUCT_CODE,
                            V_MCALCUL_INDEX,
                            'Markup_calcul',
                            'bank_code',
                            V_BANK_CODE,
                            'markup_fee_index',
                            MARKUP_CALCUL_REC.MARKUP_FEE_INDEX,
                            'markup_id_seq',
                            MARKUP_CALCUL_REC.MARKUP_ID_SEQ,
                            NULL,
                            NULL,
                            NULL,
                            NULL,
                            NULL,
                            NULL,
                            NULL,
                            NULL,
                            'mgr',
                            NULL,
                            NULL,
                            NULL);
            EXCEPTION
                WHEN OTHERS
                THEN
                    NULL;
            END;


            BEGIN
                SELECT   SUBSTR (
                             TEXT,
                             INSTR (TEXT, 'uniqueIndex="') + 13,
                             INSTR (SUBSTR (TEXT, INSTR (TEXT, 'uniqueIndex="') + 13),
                                    '"')
                             - 1)
                  INTO   V_MCALCUL_INDEX
                  FROM   MGR_CAT_OUTPUT
                 WHERE   TEXT LIKE '%GRP_EMV_APPLICATION%';

                SELECT   *
                  INTO   ICC_APPLICATION_PAR_INDEX_REC
                  FROM   ICC_APPLICATION_PAR_INDEX
                 WHERE   BANK_CODE = V_BANK_CODE AND PRODUCT_CODE = V_PRODUCT_CODE;


                INSERT INTO MGR_CATALOGUE_INJECTED_PARAM (BANK_CODE,
                                                          PRODUCT_CODE,
                                                          PROD_VERSION,
                                                          PROD_SEQUENCE,
                                                          GROUP_DATA_INDEX,
                                                          ENTITY_NAME,
                                                          PK_FIELD_NAME_1,
                                                          PK_FIELD_VALUE_1,
                                                          PK_FIELD_NAME_2,
                                                          PK_FIELD_VALUE_2,
                                                          PK_FIELD_NAME_3,
                                                          PK_FIELD_VALUE_3,
                                                          PK_FIELD_NAME_4,
                                                          PK_FIELD_VALUE_4,
                                                          PK_FIELD_NAME_5,
                                                          PK_FIELD_VALUE_5,
                                                          PK_FIELD_NAME_6,
                                                          PK_FIELD_VALUE_6,
                                                          PK_FIELD_NAME_7,
                                                          PK_FIELD_VALUE_7,
                                                          USER_CREATE,
                                                          DATE_CREATE,
                                                          USER_MODIF,
                                                          DATE_MODIF)
                  VALUES   (V_BANK_CODE,
                            'PAN' || V_PRODUCT_CODE,
                            '1',
                            V_PRODUCT_CODE,
                            V_MCALCUL_INDEX,
                            'Icc_application_par_index',
                            'icc_application_index',
                            ICC_APPLICATION_PAR_INDEX_REC.ICC_APPLICATION_INDEX,
                            'bank_code',
                            ICC_APPLICATION_PAR_INDEX_REC.BANK_CODE,
                            'product_code',
                            ICC_APPLICATION_PAR_INDEX_REC.PRODUCT_CODE,
                            NULL,
                            NULL,
                            NULL,
                            NULL,
                            NULL,
                            NULL,
                            NULL,
                            NULL,
                            'mgr',
                            NULL,
                            NULL,
                            NULL);
            EXCEPTION
                WHEN OTHERS
                THEN
                    NULL;
            END;

            V_XML_FILE       := NULL;


            BEGIN
                FOR REC IN (  SELECT   *
                                FROM   MGR_CAT_OUTPUT
                            ORDER BY   LINE)
                LOOP
                    V_XML_FILE   := V_XML_FILE || REC.TEXT || CHR (10);
                END LOOP;

                UPDATE   CATALOGUE_PRODUCT
                   SET   XML_FILE   = V_XML_FILE
                 WHERE   PRODUCT_CODE = 'PAN' || V_PRODUCT_CODE
                         AND BANK_CODE = V_BANK_CODE;


                COMMIT;
            END;
        END LOOP;

     RETURN DECLARATION_CST.OK;
    END AUT_GENERATE_PAN_XML;

    FUNCTION AUT_POPULATE_CAT_INJ_PARAM (P_BANK_CODE VARCHAR2)
        RETURN PLS_INTEGER
    IS
        PK_COL_COUNT          NUMBER;
        V_BANK_CODE           VARCHAR2 (6);
        V_PRODUCT_CODE        VARCHAR2 (6);
        V_VAL_1               VARCHAR2 (100);
        V_VAL_2               VARCHAR2 (100);
        V_VAL_3               VARCHAR2 (100);
        V_VAL_4               VARCHAR2 (100);
        V_VAL_5               VARCHAR2 (100);
        V_VAL_6               VARCHAR2 (100);
        V_VAL_7               VARCHAR2 (100);
        V_CATALOGUE_PRODUCT   VARCHAR2 (6) := 'PAN';
        V_CATALOGUE_VERSION   VARCHAR2 (6) := 1;

        CURSOR ENTITY_CUR
        IS
            (SELECT   DISTINCT ENTITY_NAME
               FROM   CATALOGUE_DEFAULTING
              WHERE   PRODUCT_TYPE = 'P'            --and entity_name='P7_sa_limits_setup'
             UNION
             SELECT   DISTINCT ENTITY_NAME
               FROM   CATALOGUE_MAPPING
              WHERE   PRODUCT_TYPE = 'P'
                      AND TAG_ID IN
                                 (SELECT   DISTINCT
                                           SUBSTR (
                                               TEXT,
                                               INSTR (TEXT, 'id="') + 4,
                                               INSTR (
                                                   SUBSTR (TEXT,
                                                           INSTR (TEXT, 'id="') + 4),
                                                   '"')
                                               - 1)
                                    FROM   MGR_CAT_GENPAN
                                   WHERE   TEXT LIKE '%<Characteristic %') --and entity_name='P7_sa_limits_setup'
                                                                          );
    BEGIN
        FOR PRODUCT_REC
        IN (SELECT   C.*
              FROM   CARD_PRODUCT C, CATALOGUE_PRODUCT G
             WHERE       C.PRODUCT_CODE = SUBSTR (G.PRODUCT_CODE, 4, 3)
                     AND G.PRODUCT_TYPE = 'P'
                     AND C.BANK_CODE = P_BANK_CODE)
        LOOP
            V_BANK_CODE           := PRODUCT_REC.BANK_CODE;
            V_PRODUCT_CODE        := PRODUCT_REC.PRODUCT_CODE;

            V_CATALOGUE_PRODUCT   := 'PAN' || V_PRODUCT_CODE;
            V_CATALOGUE_VERSION   := 1;

            DELETE FROM   CATALOGUE_INJECTED_PARAM
                  WHERE   PRODUCT_CODE = V_CATALOGUE_PRODUCT AND BANK_CODE = V_BANK_CODE;

            FOR REC IN ENTITY_CUR
            LOOP
                IF REC.ENTITY_NAME = 'Card_fees'
                THEN
                    BEGIN
                        SELECT   BANK_CODE, CARD_FEES_CODE
                          INTO   V_VAL_1, V_VAL_2
                          FROM   CARD_FEES
                         WHERE   (BANK_CODE, CARD_FEES_CODE) IN
                                         (SELECT   BANK_CODE, CARD_FEES_IND_PRIM
                                            FROM   CARD_PRODUCT
                                           WHERE   PRODUCT_CODE = V_PRODUCT_CODE
                                                   AND BANK_CODE = V_BANK_CODE);

                        INSERT INTO CATALOGUE_INJECTED_PARAM (SEQUENCE_ID,
                                                              BANK_CODE,
                                                              PRODUCT_CODE,
                                                              PROD_VERSION,
                                                              PROD_SEQUENCE,
                                                              ENTITY_NAME,
                                                              PK_FIELD_NAME_1,
                                                              PK_FIELD_VALUE_1,
                                                              PK_FIELD_NAME_2,
                                                              PK_FIELD_VALUE_2)
                          VALUES   (CATALOGUE_INJECTED_PARAM_X.NEXTVAL,
                                    V_BANK_CODE,
                                    V_CATALOGUE_PRODUCT,
                                    V_CATALOGUE_VERSION,
                                    V_PRODUCT_CODE,
                                    REC.ENTITY_NAME,
                                    'bank_code',
                                    V_VAL_1,
                                    'card_fees_code',
                                    V_VAL_2);
                    EXCEPTION
                        WHEN NO_DATA_FOUND
                        THEN
                            INSERT INTO MGR_TRACE
                              VALUES   (   'NO DATA FOUND '
                                        || REC.ENTITY_NAME
                                        || ' BANK_CODE :'
                                        || V_BANK_CODE
                                        || ' PRODUCT_CODE :'
                                        || V_PRODUCT_CODE);
                    END;
                ELSIF REC.ENTITY_NAME = 'Control_verification_flags'
                THEN
                    BEGIN
                        SELECT   BANK_CODE, CONTROL_VERIFICATION_INDEX
                          INTO   V_VAL_1, V_VAL_2
                          FROM   CARD_PRODUCT
                         WHERE   PRODUCT_CODE = V_PRODUCT_CODE
                                 AND BANK_CODE = V_BANK_CODE;

                        INSERT INTO CATALOGUE_INJECTED_PARAM (SEQUENCE_ID,
                                                              BANK_CODE,
                                                              PRODUCT_CODE,
                                                              PROD_VERSION,
                                                              PROD_SEQUENCE,
                                                              ENTITY_NAME,
                                                              PK_FIELD_NAME_1,
                                                              PK_FIELD_VALUE_1,
                                                              PK_FIELD_NAME_2,
                                                              PK_FIELD_VALUE_2)
                          VALUES   (CATALOGUE_INJECTED_PARAM_X.NEXTVAL,
                                    V_BANK_CODE,
                                    V_CATALOGUE_PRODUCT,
                                    V_CATALOGUE_VERSION,
                                    V_PRODUCT_CODE,
                                    REC.ENTITY_NAME,
                                    'bank_code',
                                    V_VAL_1,
                                    'control_verification_index',
                                    V_VAL_2);
                    EXCEPTION
                        WHEN NO_DATA_FOUND
                        THEN
                            INSERT INTO MGR_TRACE
                              VALUES   (   'NO DATA FOUND '
                                        || REC.ENTITY_NAME
                                        || ' BANK_CODE :'
                                        || V_BANK_CODE
                                        || ' PRODUCT_CODE :'
                                        || V_PRODUCT_CODE);
                    END;
                ELSIF REC.ENTITY_NAME = 'P7_ctrl_decision_matrix'
                THEN
                    BEGIN
                        SELECT   BANK_CODE,
                                 CONTROL_VERIFICATION_INDEX,
                                 ON_OFF_FLAG,
                                 CTRL_ID,
                                 CTRL_RESULTS
                          INTO   V_VAL_1,
                                 V_VAL_2,
                                 V_VAL_3,
                                 V_VAL_4,
                                 V_VAL_5
                          FROM   P7_CTRL_DECISION_MATRIX
                         WHERE   CONTROL_VERIFICATION_INDEX IN
                                         (SELECT   CONTROL_VERIFICATION_INDEX
                                            FROM   CARD_PRODUCT
                                           WHERE   BANK_CODE = V_BANK_CODE
                                                   AND PRODUCT_CODE = V_PRODUCT_CODE)
                                 AND BANK_CODE = V_BANK_CODE;

                        INSERT INTO CATALOGUE_INJECTED_PARAM (SEQUENCE_ID,
                                                              BANK_CODE,
                                                              PRODUCT_CODE,
                                                              PROD_VERSION,
                                                              PROD_SEQUENCE,
                                                              ENTITY_NAME,
                                                              PK_FIELD_NAME_1,
                                                              PK_FIELD_VALUE_1,
                                                              PK_FIELD_NAME_2,
                                                              PK_FIELD_VALUE_2,
                                                              PK_FIELD_NAME_3,
                                                              PK_FIELD_VALUE_3,
                                                              PK_FIELD_NAME_4,
                                                              PK_FIELD_VALUE_4,
                                                              PK_FIELD_NAME_5,
                                                              PK_FIELD_VALUE_5)
                          VALUES   (CATALOGUE_INJECTED_PARAM_X.NEXTVAL,
                                    V_BANK_CODE,
                                    V_CATALOGUE_PRODUCT,
                                    V_CATALOGUE_VERSION,
                                    V_PRODUCT_CODE,
                                    REC.ENTITY_NAME,
                                    'bank_code',
                                    V_VAL_1,
                                    'control_verification_index',
                                    V_VAL_2,
                                    'on_off_flag',
                                    V_VAL_3,
                                    'ctrl_id',
                                    V_VAL_4,
                                    'ctrl_results',
                                    V_VAL_5);
                    EXCEPTION
                        WHEN NO_DATA_FOUND
                        THEN
                            INSERT INTO MGR_TRACE
                              VALUES   (   'NO DATA FOUND '
                                        || REC.ENTITY_NAME
                                        || ' BANK_CODE :'
                                        || V_BANK_CODE
                                        || ' PRODUCT_CODE :'
                                        || V_PRODUCT_CODE);
                    END;
                ELSIF REC.ENTITY_NAME = 'Sca_rp_decision_matrix'
                THEN
                    BEGIN
                        SELECT   SEQUENCE_ID
                          INTO   V_VAL_1
                          FROM   SCA_RP_DECISION_MATRIX
                         WHERE   CONTROL_VERIFICATION_INDEX IN
                                         (SELECT   CONTROL_VERIFICATION_INDEX
                                            FROM   CARD_PRODUCT
                                           WHERE   BANK_CODE = V_BANK_CODE
                                                   AND PRODUCT_CODE = V_PRODUCT_CODE)
                                 AND BANK_CODE = V_BANK_CODE;

                        INSERT INTO CATALOGUE_INJECTED_PARAM (SEQUENCE_ID,
                                                              BANK_CODE,
                                                              PRODUCT_CODE,
                                                              PROD_VERSION,
                                                              PROD_SEQUENCE,
                                                              ENTITY_NAME,
                                                              PK_FIELD_NAME_1,
                                                              PK_FIELD_VALUE_1)
                          VALUES   (CATALOGUE_INJECTED_PARAM_X.NEXTVAL,
                                    V_BANK_CODE,
                                    V_CATALOGUE_PRODUCT,
                                    V_CATALOGUE_VERSION,
                                    V_PRODUCT_CODE,
                                    REC.ENTITY_NAME,
                                    'sequence_id',
                                    V_VAL_1);
                    EXCEPTION
                        WHEN NO_DATA_FOUND
                        THEN
                            INSERT INTO MGR_TRACE
                              VALUES   (   'NO DATA FOUND '
                                        || REC.ENTITY_NAME
                                        || ' BANK_CODE :'
                                        || V_BANK_CODE
                                        || ' PRODUCT_CODE :'
                                        || V_PRODUCT_CODE);
                        WHEN TOO_MANY_ROWS
                        THEN
                            SELECT   SEQUENCE_ID
                              INTO   V_VAL_1
                              FROM   SCA_RP_DECISION_MATRIX
                             WHERE   CONTROL_VERIFICATION_INDEX IN
                                             (SELECT   CONTROL_VERIFICATION_INDEX
                                                FROM   CARD_PRODUCT
                                               WHERE   BANK_CODE = V_BANK_CODE
                                                       AND PRODUCT_CODE = V_PRODUCT_CODE)
                                     AND BANK_CODE = V_BANK_CODE
                                     AND ROWNUM = 1;

                            INSERT INTO CATALOGUE_INJECTED_PARAM (SEQUENCE_ID,
                                                                  BANK_CODE,
                                                                  PRODUCT_CODE,
                                                                  PROD_VERSION,
                                                                  PROD_SEQUENCE,
                                                                  ENTITY_NAME,
                                                                  PK_FIELD_NAME_1,
                                                                  PK_FIELD_VALUE_1)
                              VALUES   (CATALOGUE_INJECTED_PARAM_X.NEXTVAL,
                                        V_BANK_CODE,
                                        V_CATALOGUE_PRODUCT,
                                        V_CATALOGUE_VERSION,
                                        V_PRODUCT_CODE,
                                        REC.ENTITY_NAME,
                                        'sequence_id',
                                        V_VAL_1);
                    END;
                ELSIF REC.ENTITY_NAME = 'Entity_event_grouping'
                THEN
                    BEGIN
                        SELECT   EVENT_RULES_INDEX
                          INTO   V_VAL_1
                          FROM   ENTITY_EVENT_GROUPING
                         WHERE   EVENT_RULES_INDEX IN
                                         (SELECT   EVENT_RULES_INDEX
                                            FROM   CARD_PRODUCT
                                           WHERE   BANK_CODE = V_BANK_CODE
                                                   AND PRODUCT_CODE = V_PRODUCT_CODE)
                                 AND BANK_CODE = V_BANK_CODE;

                        INSERT INTO CATALOGUE_INJECTED_PARAM (SEQUENCE_ID,
                                                              BANK_CODE,
                                                              PRODUCT_CODE,
                                                              PROD_VERSION,
                                                              PROD_SEQUENCE,
                                                              ENTITY_NAME,
                                                              PK_FIELD_NAME_1,
                                                              PK_FIELD_VALUE_1)
                          VALUES   (CATALOGUE_INJECTED_PARAM_X.NEXTVAL,
                                    V_BANK_CODE,
                                    V_CATALOGUE_PRODUCT,
                                    V_CATALOGUE_VERSION,
                                    V_PRODUCT_CODE,
                                    REC.ENTITY_NAME,
                                    'event_rules_index',
                                    V_VAL_1);
                    EXCEPTION
                        WHEN NO_DATA_FOUND
                        THEN
                            INSERT INTO MGR_TRACE
                              VALUES   (   'NO DATA FOUND '
                                        || REC.ENTITY_NAME
                                        || ' BANK_CODE :'
                                        || V_BANK_CODE
                                        || ' PRODUCT_CODE :'
                                        || V_PRODUCT_CODE);
                    END;
                ELSIF REC.ENTITY_NAME = 'Iss_transaction_fees_param'
                THEN
                    BEGIN
                        SELECT   SEQUENCE_ID
                          INTO   V_VAL_1
                          FROM   ISS_TRANSACTION_FEES_PARAM
                         WHERE   CARD_PRODUCT_CODE = V_PRODUCT_CODE
                                 AND ISSUER_BANK_CODE = V_BANK_CODE;

                        INSERT INTO CATALOGUE_INJECTED_PARAM (SEQUENCE_ID,
                                                              BANK_CODE,
                                                              PRODUCT_CODE,
                                                              PROD_VERSION,
                                                              PROD_SEQUENCE,
                                                              ENTITY_NAME,
                                                              PK_FIELD_NAME_1,
                                                              PK_FIELD_VALUE_1)
                          VALUES   (CATALOGUE_INJECTED_PARAM_X.NEXTVAL,
                                    V_BANK_CODE,
                                    V_CATALOGUE_PRODUCT,
                                    V_CATALOGUE_VERSION,
                                    V_PRODUCT_CODE,
                                    REC.ENTITY_NAME,
                                    'sequence_id',
                                    V_VAL_1);
                    EXCEPTION
                        WHEN NO_DATA_FOUND
                        THEN
                            INSERT INTO MGR_TRACE
                              VALUES   (   'NO DATA FOUND '
                                        || REC.ENTITY_NAME
                                        || ' BANK_CODE :'
                                        || V_BANK_CODE
                                        || ' PRODUCT_CODE :'
                                        || V_PRODUCT_CODE);
                        WHEN TOO_MANY_ROWS
                        THEN
                            FOR ENR
                            IN (SELECT   SEQUENCE_ID
                                  FROM   ISS_TRANSACTION_FEES_PARAM
                                 WHERE   CARD_PRODUCT_CODE = V_PRODUCT_CODE
                                         AND ISSUER_BANK_CODE = V_BANK_CODE)
                            LOOP
                                INSERT INTO CATALOGUE_INJECTED_PARAM (SEQUENCE_ID,
                                                                      BANK_CODE,
                                                                      PRODUCT_CODE,
                                                                      PROD_VERSION,
                                                                      PROD_SEQUENCE,
                                                                      ENTITY_NAME,
                                                                      PK_FIELD_NAME_1,
                                                                      PK_FIELD_VALUE_1)
                                  VALUES   (CATALOGUE_INJECTED_PARAM_X.NEXTVAL,
                                            V_BANK_CODE,
                                            V_CATALOGUE_PRODUCT,
                                            V_CATALOGUE_VERSION,
                                            V_PRODUCT_CODE,
                                            REC.ENTITY_NAME,
                                            'sequence_id',
                                            ENR.SEQUENCE_ID);
                            END LOOP;
                    END;
                ELSIF REC.ENTITY_NAME = 'P7_limits'
                THEN
                    BEGIN
                        SELECT   BANK_CODE, LIMIT_INDEX
                          INTO   V_VAL_1, V_VAL_2
                          FROM   P7_LIMITS
                         WHERE   TRIM (LIMIT_INDEX) IN
                                         (SELECT   TRIM (LIMITS_INDEXES)
                                            FROM   CARD_PRODUCT
                                           WHERE   BANK_CODE = V_BANK_CODE
                                                   AND PRODUCT_CODE = V_PRODUCT_CODE)
                                 AND BANK_CODE = V_BANK_CODE;

                        INSERT INTO CATALOGUE_INJECTED_PARAM (SEQUENCE_ID,
                                                              BANK_CODE,
                                                              PRODUCT_CODE,
                                                              PROD_VERSION,
                                                              PROD_SEQUENCE,
                                                              ENTITY_NAME,
                                                              PK_FIELD_NAME_1,
                                                              PK_FIELD_VALUE_1,
                                                              PK_FIELD_NAME_2,
                                                              PK_FIELD_VALUE_2)
                          VALUES   (CATALOGUE_INJECTED_PARAM_X.NEXTVAL,
                                    V_BANK_CODE,
                                    V_CATALOGUE_PRODUCT,
                                    V_CATALOGUE_VERSION,
                                    V_PRODUCT_CODE,
                                    REC.ENTITY_NAME,
                                    'bank_code',
                                    V_VAL_1,
                                    'limit_index',
                                    V_VAL_2);
                    EXCEPTION
                        WHEN NO_DATA_FOUND
                        THEN
                            INSERT INTO MGR_TRACE
                              VALUES   (   ' NO DATA FOUND '
                                        || REC.ENTITY_NAME
                                        || ' BANK_CODE :'
                                        || V_BANK_CODE
                                        || ' PRODUCT_CODE :'
                                        || V_PRODUCT_CODE);
                    END;
                ELSIF REC.ENTITY_NAME = 'Credit_auth_param'
                THEN
                    BEGIN
                        SELECT   BANK_CODE, SERVICE_SETUP_INDEX
                          INTO   V_VAL_1, V_VAL_2
                          FROM   CREDIT_AUTH_PARAM
                         WHERE   SERVICE_SETUP_INDEX IN
                                         (SELECT   SERVICES_SETUP_INDEX
                                            FROM   CARD_PRODUCT
                                           WHERE   BANK_CODE = V_BANK_CODE
                                                   AND PRODUCT_CODE = V_PRODUCT_CODE)
                                 AND BANK_CODE = V_BANK_CODE;

                        INSERT INTO CATALOGUE_INJECTED_PARAM (SEQUENCE_ID,
                                                              BANK_CODE,
                                                              PRODUCT_CODE,
                                                              PROD_VERSION,
                                                              PROD_SEQUENCE,
                                                              ENTITY_NAME,
                                                              PK_FIELD_NAME_1,
                                                              PK_FIELD_VALUE_1,
                                                              PK_FIELD_NAME_2,
                                                              PK_FIELD_VALUE_2)
                          VALUES   (CATALOGUE_INJECTED_PARAM_X.NEXTVAL,
                                    V_BANK_CODE,
                                    V_CATALOGUE_PRODUCT,
                                    V_CATALOGUE_VERSION,
                                    V_PRODUCT_CODE,
                                    REC.ENTITY_NAME,
                                    'bank_code',
                                    V_VAL_1,
                                    'service_setup_index',
                                    V_VAL_2);
                    EXCEPTION
                        WHEN NO_DATA_FOUND
                        THEN
                            INSERT INTO MGR_TRACE
                              VALUES   (   'NO DATA FOUND '
                                        || REC.ENTITY_NAME
                                        || ' BANK_CODE :'
                                        || V_BANK_CODE
                                        || ' PRODUCT_CODE :'
                                        || V_PRODUCT_CODE);
                    END;
                ELSIF REC.ENTITY_NAME = 'Card_gen_counters'
                THEN
                    BEGIN
                        SELECT   SEQUENCE_ID
                          INTO   V_VAL_1
                          FROM   CARD_GEN_COUNTERS
                         WHERE   CARD_PRODUCT_CODE = V_PRODUCT_CODE
                                 AND BANK_CODE = V_BANK_CODE;

                        INSERT INTO CATALOGUE_INJECTED_PARAM (SEQUENCE_ID,
                                                              BANK_CODE,
                                                              PRODUCT_CODE,
                                                              PROD_VERSION,
                                                              PROD_SEQUENCE,
                                                              ENTITY_NAME,
                                                              PK_FIELD_NAME_1,
                                                              PK_FIELD_VALUE_1)
                          VALUES   (CATALOGUE_INJECTED_PARAM_X.NEXTVAL,
                                    V_BANK_CODE,
                                    V_CATALOGUE_PRODUCT,
                                    V_CATALOGUE_VERSION,
                                    V_PRODUCT_CODE,
                                    REC.ENTITY_NAME,
                                    'sequence_id',
                                    V_VAL_1);
                    EXCEPTION
                        WHEN NO_DATA_FOUND
                        THEN
                            INSERT INTO MGR_TRACE
                              VALUES   (   'NO DATA FOUND '
                                        || REC.ENTITY_NAME
                                        || ' BANK_CODE :'
                                        || V_BANK_CODE
                                        || ' PRODUCT_CODE :'
                                        || V_PRODUCT_CODE);
                    END;
                ELSIF REC.ENTITY_NAME = 'Product_domain_setup'
                THEN
                    BEGIN
                        SELECT   BANK_CODE, CONTROL_VERIFICATION_INDEX
                          INTO   V_VAL_1, V_VAL_2
                          FROM   PRODUCT_DOMAIN_SETUP
                         WHERE   CONTROL_VERIFICATION_INDEX =
                                     (SELECT   CONTROL_VERIFICATION_INDEX
                                        FROM   CARD_PRODUCT
                                       WHERE   PRODUCT_CODE = V_PRODUCT_CODE
                                               AND BANK_CODE = V_BANK_CODE)
                                 AND BANK_CODE = V_BANK_CODE;

                        INSERT INTO CATALOGUE_INJECTED_PARAM (SEQUENCE_ID,
                                                              BANK_CODE,
                                                              PRODUCT_CODE,
                                                              PROD_VERSION,
                                                              PROD_SEQUENCE,
                                                              ENTITY_NAME,
                                                              PK_FIELD_NAME_1,
                                                              PK_FIELD_VALUE_1,
                                                              PK_FIELD_NAME_2,
                                                              PK_FIELD_VALUE_2)
                          VALUES   (CATALOGUE_INJECTED_PARAM_X.NEXTVAL,
                                    V_BANK_CODE,
                                    V_CATALOGUE_PRODUCT,
                                    V_CATALOGUE_VERSION,
                                    V_PRODUCT_CODE,
                                    REC.ENTITY_NAME,
                                    'bank_code',
                                    V_VAL_1,
                                    'control_verification_index',
                                    V_VAL_2);
                    EXCEPTION
                        WHEN NO_DATA_FOUND
                        THEN
                            INSERT INTO MGR_TRACE
                              VALUES   (   'NO DATA FOUND '
                                        || REC.ENTITY_NAME
                                        || ' BANK_CODE :'
                                        || V_BANK_CODE
                                        || ' PRODUCT_CODE :'
                                        || V_PRODUCT_CODE);
                    END;
                ELSIF REC.ENTITY_NAME = 'Pcrd_card_prod_param'
                THEN
                    BEGIN
                        SELECT   PCRD_CARD_PROD_PARAM_ID
                          INTO   V_VAL_1
                          FROM   PCRD_CARD_PROD_PARAM
                         WHERE   CARD_PRODUCT_CODE = V_PRODUCT_CODE
                                 AND BANK_CODE = V_BANK_CODE
                                 AND PLASTIC_CODE IN
                                            (SELECT   PLASTIC_TYPE
                                               FROM   CARD_PRODUCT
                                              WHERE   PRODUCT_CODE = V_PRODUCT_CODE
                                                      AND BANK_CODE = V_BANK_CODE);

                        INSERT INTO CATALOGUE_INJECTED_PARAM (SEQUENCE_ID,
                                                              BANK_CODE,
                                                              PRODUCT_CODE,
                                                              PROD_VERSION,
                                                              PROD_SEQUENCE,
                                                              ENTITY_NAME,
                                                              PK_FIELD_NAME_1,
                                                              PK_FIELD_VALUE_1)
                          VALUES   (CATALOGUE_INJECTED_PARAM_X.NEXTVAL,
                                    V_BANK_CODE,
                                    V_CATALOGUE_PRODUCT,
