                                                                      PROD_VERSION,
                                                                      PROD_SEQUENCE,
                                                                      ENTITY_NAME,
                                                                      PK_FIELD_NAME_1,
                                                                      PK_FIELD_VALUE_1,
                                                                      PK_FIELD_NAME_2,
