                                          FROM   AUTHO_FEES_PARAM
                                         WHERE   FEE_INDEX = V_PRODUCT_CODE)
                            LOOP
                                INSERT INTO CATALOGUE_INJECTED_PARAM (SEQUENCE_ID,
                                                                      BANK_CODE,
                                                                      PRODUCT_CODE,
                                                                      PROD_VERSION,
                                                                      PROD_SEQUENCE,
