                        THEN
                            INSERT INTO MGR_TRACE
                              VALUES   (   'NO DATA FOUND '
                                        || REC.ENTITY_NAME
                                        || ' BANK_CODE :'
                                        || V_BANK_CODE
                                        || ' PRODUCT_CODE :'
                                        || V_PRODUCT_CODE);
                        WHEN TOO_MANY_ROWS
                        THEN
