                                                                      PK_FIELD_VALUE_1)
                                  VALUES   (CATALOGUE_INJECTED_PARAM_X.NEXTVAL,
                                            V_BANK_CODE,
                                            V_CATALOGUE_PRODUCT,
                                            V_CATALOGUE_VERSION,
                                            V_PRODUCT_CODE,
                                            REC.ENTITY_NAME,
                                            'sequence_id',
                                            ENR.SEQUENCE_ID);
                            END LOOP;
                    END;
                END IF;
            END LOOP;

            --commit;
        END LOOP;


        DECLARE
            V_IDX   NUMBER;
        BEGIN
            FOR PRODUCT_REC IN (SELECT   *
                                  FROM   CATALOGUE_PRODUCT
                                 WHERE   PRODUCT_TYPE = 'P' AND BANK_CODE = P_BANK_CODE)
            LOOP
                FOR REC IN (SELECT   *
                              FROM   CATALOGUE_INJECTORS
                             WHERE   PRODUCT_TYPE = 'P' AND IS_MULTI_OCCUR = 'Y')
                LOOP
                    V_IDX   := 1;

                    FOR ENR
                    IN (SELECT   *
                          FROM   CATALOGUE_INJECTED_PARAM
                         WHERE       ENTITY_NAME = REC.ENTITY_NAME
                                 AND PRODUCT_CODE = PRODUCT_REC.PRODUCT_CODE
                                 AND GROUP_DATA_INDEX IS NULL
                                 AND BANK_CODE = PRODUCT_REC.BANK_CODE)
                    LOOP
                        UPDATE   CATALOGUE_INJECTED_PARAM
                           SET   GROUP_DATA_INDEX   = V_IDX
                         WHERE   SEQUENCE_ID = ENR.SEQUENCE_ID;


                        V_IDX   := V_IDX + 1;
                    END LOOP;
                END LOOP;
            END LOOP;
        END;



        --commit;
        RETURN DECLARATION_CST.OK;
    END AUT_POPULATE_CAT_INJ_PARAM;
