    FUNCTION AUT_MULTI_RANGE_PRODUCTS (P_BANK_CODE IN VARCHAR2)
        RETURN PLS_INTEGER
    IS
        V_ENV_INFO_TRACE   GLOBAL_VARS.ENV_INFO_TRACE_TYPE;
        V_BANK_CODE        VARCHAR2 (6) := P_BANK_CODE;
    BEGIN
        --DEFINE TRACES RECORD
        V_ENV_INFO_TRACE.USER_NAME       := 'AUTOMATISATION';
        V_ENV_INFO_TRACE.MODULE_CODE     := 'AUT';
        V_ENV_INFO_TRACE.LANG            := 'E';
        V_ENV_INFO_TRACE.FUNCTION_NAME   := 'AUT_MULTI_RANGE_PRODUCTS';
        V_ENV_INFO_TRACE.PACKAGE_NAME    := 'PCRD_MGR_SCU_POST_MIG_PARAM';

        INSERT INTO MULTI_RANGE_PRODUCTS
            SELECT   ISSUING_BANK_CODE BANK_CODE,
                     P.PRODUCT_CODE CATALOGUE_PRODUCT,
                     P.PROD_VERSION CATALOGUE_PRODUCT_VERSION,
                     R.PRODUCT_CODE,
                     R.MIN_CARD_RANGE MIN_RANGE,
                     R.MAX_CARD_RANGE MAX_RANGE,
                     R.NETWORK_CODE,
                     'MGR',
                     SYSDATE,
                     NULL,
                     NULL
              FROM   CARD_RANGE R, CATALOGUE_PRODUCT P
             WHERE   R.ISSUING_BANK_CODE = P.BANK_CODE
                     AND P.PRODUCT_CODE = 'PAN' || R.PRODUCT_CODE
                     AND (MIN_CARD_RANGE, MAX_CARD_RANGE) NOT IN
                                (SELECT   MIN_RANGE, MAX_RANGE FROM MULTI_RANGE_PRODUCTS)
                     AND P.BANK_CODE = V_BANK_CODE;

        RETURN DECLARATION_CST.OK;
    END AUT_MULTI_RANGE_PRODUCTS;

---------------------------------------------------------------------------------------------------------------------------
    FUNCTION AUT_CATALOGE_ELIGIBILITY (P_BANK_CODE IN VARCHAR2)
        RETURN PLS_INTEGER
    IS
        V_ENV_INFO_TRACE                 GLOBAL_VARS.ENV_INFO_TRACE_TYPE;
        V_BANK_CODE                      VARCHAR2 (6) := P_BANK_CODE;
        CATALOGUE_PROD_ELIGIBILITY_REC   CATALOGUE_PROD_ELIGIBILITY%ROWTYPE;
        IDX                              NUMBER;
    BEGIN
        --DEFINE TRACES RECORD
        V_ENV_INFO_TRACE.USER_NAME       := 'AUTOMATISATION';
        V_ENV_INFO_TRACE.MODULE_CODE     := 'AUT';
        V_ENV_INFO_TRACE.LANG            := 'E';
        V_ENV_INFO_TRACE.FUNCTION_NAME   := 'AUT_CATALOGE_ELIGIBILITY';
        V_ENV_INFO_TRACE.PACKAGE_NAME    := 'PCRD_MGR_SCU_POST_MIG_PARAM';

        IDX                              := 30;

        FOR REC
        IN (SELECT   *
              FROM   CATALOGUE_PRODUCT
             WHERE   PRODUCT_LEVEL = 'M'
                     AND PRODUCT_CODE NOT IN
                                (SELECT   PRODUCT_CODE FROM CATALOGUE_PROD_ELIGIBILITY)
                     AND PRODUCT_TYPE IN ('A', 'P')
                     AND PRODUCT_CODE IN (SELECT   'PAN' || PRODUCT_CODE
                                            FROM   CARD_PRODUCT
                                           WHERE   BANK_CODE = P_BANK_CODE)
                     AND BANK_CODE = P_BANK_CODE)
        LOOP
            CATALOGUE_PROD_ELIGIBILITY_REC                     := NULL;
            CATALOGUE_PROD_ELIGIBILITY_REC.BANK_CODE           := REC.BANK_CODE;
            CATALOGUE_PROD_ELIGIBILITY_REC.PRODUCT_CODE        := REC.PRODUCT_CODE;
            CATALOGUE_PROD_ELIGIBILITY_REC.VERSION             := REC.PROD_VERSION;
            CATALOGUE_PROD_ELIGIBILITY_REC.ELIGIBILITY_INDEX   := '00';
            CATALOGUE_PROD_ELIGIBILITY_REC.DESCRIPTION         := SUBSTR (
                                                                      REC.DESCRIPTION,
                                                                      1,
                                                                      32);
            IDX                                                := IDX + 1;

            INSERT INTO CATALOGUE_PROD_ELIGIBILITY
              VALUES   CATALOGUE_PROD_ELIGIBILITY_REC;
        END LOOP;


        UPDATE   CATALOGUE_PRODUCT
           SET   VALIDITY_START_DATE   = TO_DATE ('01/02/2022', 'DD/MM/RRRR')
         WHERE   PRODUCT_CODE IN (SELECT   'PAN' || PRODUCT_CODE
                                    FROM   CARD_PRODUCT
                                   WHERE   BANK_CODE = P_BANK_CODE)
                 AND BANK_CODE = P_BANK_CODE;

        RETURN DECLARATION_CST.OK;
    END AUT_CATALOGE_ELIGIBILITY;
---------------------------------------------------------------------------------------------------------------------------

