    FUNCTION AUT_UPDATE_GRP_DATA_IDX (P_BANK_CODE VARCHAR2)
        RETURN PLS_INTEGER
    IS
    BEGIN
        FOR REC IN (SELECT   * FROM MGR_CATALOGUE_INJECTED_PARAM)
        LOOP
            UPDATE   CATALOGUE_INJECTED_PARAM
               SET   GROUP_DATA_INDEX   = REC.GROUP_DATA_INDEX
             WHERE       PRODUCT_CODE = REC.PRODUCT_CODE
                     AND PROD_VERSION = REC.PROD_VERSION
                     AND PROD_SEQUENCE = REC.PROD_SEQUENCE
                     AND ENTITY_NAME = REC.ENTITY_NAME
                     AND NVL (PK_FIELD_NAME_1, 'XX') = NVL (REC.PK_FIELD_NAME_1, 'XX')
                     AND NVL (PK_FIELD_VALUE_1, 'XX') = NVL (REC.PK_FIELD_VALUE_1, 'XX')
                     AND NVL (PK_FIELD_NAME_2, 'XX') = NVL (REC.PK_FIELD_NAME_2, 'XX')
                     AND NVL (PK_FIELD_VALUE_2, 'XX') = NVL (REC.PK_FIELD_VALUE_2, 'XX')
                     AND NVL (PK_FIELD_NAME_3, 'XX') = NVL (REC.PK_FIELD_NAME_3, 'XX')
                     AND NVL (PK_FIELD_VALUE_3, 'XX') = NVL (REC.PK_FIELD_VALUE_3, 'XX')
                     AND NVL (PK_FIELD_NAME_4, 'XX') = NVL (REC.PK_FIELD_NAME_4, 'XX')
                     AND NVL (PK_FIELD_VALUE_4, 'XX') = NVL (REC.PK_FIELD_VALUE_4, 'XX')
                     AND NVL (PK_FIELD_NAME_5, 'XX') = NVL (REC.PK_FIELD_NAME_5, 'XX')
                     AND NVL (PK_FIELD_VALUE_5, 'XX') = NVL (REC.PK_FIELD_VALUE_5, 'XX')
                     AND NVL (PK_FIELD_NAME_6, 'XX') = NVL (REC.PK_FIELD_NAME_6, 'XX')
                     AND NVL (PK_FIELD_VALUE_6, 'XX') = NVL (REC.PK_FIELD_VALUE_6, 'XX')
                     AND NVL (PK_FIELD_NAME_7, 'XX') = NVL (REC.PK_FIELD_NAME_7, 'XX')
                     AND NVL (PK_FIELD_VALUE_7, 'XX') = NVL (REC.PK_FIELD_VALUE_7, 'XX')
                     AND NVL (PK_FIELD_NAME_8, 'XX') = NVL (REC.PK_FIELD_NAME_8, 'XX')
                     AND NVL (PK_FIELD_VALUE_8, 'XX') = NVL (REC.PK_FIELD_VALUE_8, 'XX')
                     AND NVL (PK_FIELD_NAME_9, 'XX') = NVL (REC.PK_FIELD_NAME_9, 'XX')
                     AND NVL (PK_FIELD_VALUE_9, 'XX') = NVL (REC.PK_FIELD_VALUE_9, 'XX')
                     AND NVL (PK_FIELD_NAME_10, 'XX') = NVL (REC.PK_FIELD_NAME_10, 'XX')
                     AND NVL (PK_FIELD_VALUE_10, 'XX') =
                            NVL (REC.PK_FIELD_VALUE_10, 'XX');
        END LOOP;

        --commit;

        RETURN DECLARATION_CST.OK;
    END AUT_UPDATE_GRP_DATA_IDX;


